competitive-monitoring.source:
/**
 * Competitive Monitoring (Multi-Source Aggregation with Contradiction Detection)
 *
 * Demonstrates:
 * - Three parallel source agents extract feed data from local JSON fixtures
 * - Each agent processes claims with { claim, date, source_url, confidence }
 * - Aggregator cross-checks claims across sources, identifies duplicates, flags contradictions
 * - Structured markdown report output
 * - Timing validation: parallel execution must be <70% of serial sum
 *
 * Run:
 *   npx tsx packages/core/examples/cookbook/competitive-monitoring.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY env var must be set.
 *   Requires Node.js >= 18.
 *
 * Fixtures:
 *   - examples/fixtures/competitive-monitoring/twitter.json (10 claims)
 *   - examples/fixtures/competitive-monitoring/reddit.json (10 claims)
 *   - examples/fixtures/competitive-monitoring/news.json (10 claims)
 *
 * Intentional contradictions in fixtures (for aggregator to detect):
 *   - Competitor X product launch date: 04-15 (Twitter), 04-14 (Reddit), 04-16 (News)
 *   - Performance improvement claims: 60% (Twitter) vs 55% (News)
 */

import { readFileSync } from 'node:fs'
import { fileURLToPath } from 'node:url'
import path from 'node:path'
import { z } from 'zod'
import { Agent, ToolExecutor, ToolRegistry, registerBuiltInTools } from '../../src/index.js'
import type { AgentConfig, AgentRunResult } from '../../src/types.js'

// ---------------------------------------------------------------------------
// Fixture loading
// ---------------------------------------------------------------------------

const __dirname = path.dirname(fileURLToPath(import.meta.url))

interface Claim {
  claim: string
  date: string
  source_url: string
  confidence: number
}

function loadFixture(name: 'twitter' | 'reddit' | 'news'): Claim[] {
  const filePath = path.join(__dirname, '../fixtures/competitive-monitoring', `${name}.json`)
  const data = readFileSync(filePath, 'utf-8')
  return JSON.parse(data) as Claim[]
}

const twitterData = loadFixture('twitter')
const redditData = loadFixture('reddit')
const newsData = loadFixture('news')

// ---------------------------------------------------------------------------
// Zod schemas for structured extraction
// ---------------------------------------------------------------------------

const ClaimData = z.object({
  claims: z.array(
    z.object({
      claim: z.string().describe('The specific claim or news item'),
      date: z.string().describe('ISO date or date the claim was made'),
      source_url: z.string().describe('URL or source reference'),
      confidence: z.number().min(0).max(1).describe('Confidence 0.0-1.0'),
    }),
  ),
})
type ClaimData = z.infer<typeof ClaimData>

const AggregatedReport = z.object({
  verified_claims: z.array(
    z.object({
      claim: z.string(),
      sources: z.string().describe('Comma-separated list of source names'),
      consolidation: z.string().describe('How claims were merged/consolidated'),
      avg_confidence: z.number(),
      first_reported: z.string().describe('Earliest date across sources'),
    }),
  ),
  contradictions: z.array(
    z.object({
      claim_topic: z.string().describe('The general topic with conflicting claims'),
      variant_a: z.string().describe('One version of the claim'),
      variant_b: z.string().describe('Conflicting version'),
      source_a: z.string(),
      source_b: z.string(),
      severity: z.enum(['minor', 'moderate', 'critical']),
    }),
  ),
  summary: z.string().describe('High-level summary of monitoring findings'),
})
type AggregatedReport = z.infer<typeof AggregatedReport>

function confidenceLabel(value: number): 'high' | 'medium' | 'low' {
  if (value >= 0.8) return 'high'
  if (value >= 0.6) return 'medium'
  return 'low'
}

function severityLabel(value: AggregatedReport['contradictions'][number]['severity']): string {
  if (value === 'critical') return 'CRITICAL'
  if (value === 'moderate') return 'MODERATE'
  return 'MINOR'
}

// ---------------------------------------------------------------------------
// Agent configs
// ---------------------------------------------------------------------------

const twitterConfig: AgentConfig = {
  name: 'twitter-monitor',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a social media monitor analyzing Twitter/X feed data.
You receive raw JSON fixture data. Extract and validate each claim.
Focus on:
- Product announcements and updates
- Funding news and partnerships
- Market movements and competitive intelligence

Return JSON matching the schema, validating dates and confidence scores.`,
  maxTurns: 1,
  maxTokens: 800,
  temperature: 0.2,
  outputSchema: ClaimData,
}

const redditConfig: AgentConfig = {
  name: 'reddit-monitor',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a community sentiment analyzer monitoring Reddit discussions.
You receive raw JSON fixture data about tech industry claims.
Extract insights but note that:
- Community opinions may be speculative or unverified
- Confidence scores may be lower due to anecdotal nature
- Flag claims that contradict official sources

Return JSON matching the schema.`,
  maxTurns: 1,
  maxTokens: 800,
  temperature: 0.2,
  outputSchema: ClaimData,
}

const newsConfig: AgentConfig = {
  name: 'news-monitor',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a tech news analyst monitoring official press releases and news sources.
You receive raw JSON fixture data from reputable news outlets.
Extract and validate claims with focus on:
- Official product announcements
- Verified funding and acquisition data
- Industry analyst reports
- Conference announcements

Return JSON matching the schema.`,
  maxTurns: 1,
  maxTokens: 800,
  temperature: 0.2,
  outputSchema: ClaimData,
}

const aggregatorConfig: AgentConfig = {
  name: 'aggregator',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a competitive intelligence analyst synthesizing multi-source monitoring data.
You receive claim extractions from Twitter, Reddit, and News monitors.

Your tasks:
1. Deduplicate claims that are the same across sources, accounting for slight wording differences.
2. Flag contradictions when the same topic has different dates, numbers, or factual assertions.
3. Average confidence across sources for merged claims.
4. Return JSON matching the AggregatedReport schema.

Use only the provided claims. Be thorough about contradictions, even if the differences seem minor.`,
  maxTurns: 1,
  maxTokens: 1200,
  temperature: 0.3,
  outputSchema: AggregatedReport,
}

// ---------------------------------------------------------------------------
// Build agents
// ---------------------------------------------------------------------------

function buildAgent(config: AgentConfig): Agent {
  const registry = new ToolRegistry()
  registerBuiltInTools(registry)
  const executor = new ToolExecutor(registry)
  return new Agent(config, registry, executor)
}

const twitterMonitor = buildAgent(twitterConfig)
const redditMonitor = buildAgent(redditConfig)
const newsMonitor = buildAgent(newsConfig)
const aggregator = buildAgent(aggregatorConfig)

// ---------------------------------------------------------------------------
// Main execution
// ---------------------------------------------------------------------------

console.log('Competitive Monitoring - Multi-Source Aggregation with Contradiction Detection')
console.log('='.repeat(80))
console.log('Model backend: Anthropic')
console.log(`Local fixtures: Twitter (${twitterData.length}), Reddit (${redditData.length}), News (${newsData.length}) claims`)
console.log('Expected contradictions: Competitor X launch dates, performance improvement numbers\n')

const globalStartTime = performance.now()

const twitterPrompt = `Extract claims from this Twitter feed.
Rules:
- Use only claims from the input.
- Return a single JSON object matching the schema, no markdown and no extra text.
Input:
${JSON.stringify(twitterData)}`

const redditPrompt = `Extract claims from this Reddit feed.
Rules:
- Use only claims from the input.
- Return a single JSON object matching the schema, no markdown and no extra text.
Input:
${JSON.stringify(redditData)}`

const newsPrompt = `Extract claims from this News feed.
Rules:
- Use only claims from the input.
- Return a single JSON object matching the schema, no markdown and no extra text.
Input:
${JSON.stringify(newsData)}`

// ---------------------------------------------------------------------------
// Phase 1: Parallel fan-out - three monitors
// ---------------------------------------------------------------------------

console.log('[Phase 1] Parallel monitoring: Twitter, Reddit, News\n')

async function runTimed(
  name: string,
  agent: Agent,
  prompt: string,
): Promise<{ result: AgentRunResult, elapsedMs: number }> {
  const start = performance.now()
  console.log(`  [RUN] ${name} monitor started...`)
  const result = await agent.run(prompt)
  const elapsedMs = performance.now() - start
  console.log(`  [DONE] ${name} monitor finished in ${Math.round(elapsedMs)}ms`)
  return {
    result,
    elapsedMs,
  }
}

const monitorStartTime = performance.now()
const monitorRuns = await Promise.all([
  runTimed('Twitter', twitterMonitor, twitterPrompt),
  runTimed('Reddit', redditMonitor, redditPrompt),
  runTimed('News', newsMonitor, newsPrompt),
])
const monitorTime = performance.now() - monitorStartTime

const [twitterRun, redditRun, newsRun] = monitorRuns
const twitterResult = twitterRun.result
const redditResult = redditRun.result
const newsResult = newsRun.result

const monitorDurations = [
  { name: 'Twitter', time: twitterRun.elapsedMs, result: twitterResult },
  { name: 'Reddit', time: redditRun.elapsedMs, result: redditResult },
  { name: 'News', time: newsRun.elapsedMs, result: newsResult },
]

for (const monitor of monitorDurations) {
  const status = monitor.result.success ? 'OK' : 'FAILED'
  console.log(
    `  ${monitor.name.padEnd(10)} [${status}] - ${Math.round(monitor.time)}ms, ${monitor.result.tokenUsage.output_tokens} out tokens`,
  )
}
console.log()

for (const [name, result] of [
  ['twitter-monitor', twitterResult],
  ['reddit-monitor', redditResult],
  ['news-monitor', newsResult],
] as const) {
  if (!result.success) {
    console.error(`Monitor '${name}' failed: ${result.output}`)
    process.exit(1)
  }
}

const serialMonitorTime = monitorDurations.reduce((sum, monitor) => sum + monitor.time, 0)
console.log(`  Parallel wall time: ${Math.round(monitorTime)}ms`)
console.log(`  Sequential serial sum: ${Math.round(serialMonitorTime)}ms`)
console.log(`  Parallel speedup: ${(serialMonitorTime / monitorTime).toFixed(2)}x\n`)

const twitterClaims = twitterResult.structured as ClaimData | undefined
const redditClaims = redditResult.structured as ClaimData | undefined
const newsClaims = newsResult.structured as ClaimData | undefined

if (!twitterClaims || !redditClaims || !newsClaims) {
  console.error('Structured output missing from one or more monitors')
  process.exit(1)
}

// ---------------------------------------------------------------------------
// Phase 2: Aggregate
// ---------------------------------------------------------------------------

console.log('[Phase 2] Aggregation: Cross-check, merge, detect contradictions\n')

const aggregatorPrompt = `You have three monitoring reports. Merge and analyze:

TWITTER CLAIMS (${twitterClaims.claims.length} items):
${JSON.stringify(twitterClaims.claims, null, 2)}

REDDIT CLAIMS (${redditClaims.claims.length} items):
${JSON.stringify(redditClaims.claims, null, 2)}

NEWS CLAIMS (${newsClaims.claims.length} items):
${JSON.stringify(newsClaims.claims, null, 2)}

Now:
1. Find duplicate or similar claims across sources and merge them.
2. Identify contradictions for the same topic when dates, numbers, or facts differ.
3. Calculate average confidence for each merged claim.
4. Return one JSON object matching the AggregatedReport schema.
5. Use only facts present in the provided claims.
6. Do not output markdown, code fences, or explanations.`

const aggregatorStartTime = performance.now()
const aggregatorResult = await aggregator.run(aggregatorPrompt)
const aggregatorTime = performance.now() - aggregatorStartTime

if (!aggregatorResult.success) {
  console.error(`Aggregator failed: ${aggregatorResult.output}`)
  process.exit(1)
}

const report = aggregatorResult.structured as AggregatedReport | undefined
if (!report) {
  console.error('Structured output missing from aggregator')
  process.exit(1)
}

console.log(
  `  Aggregator [OK] - ${Math.round(aggregatorTime)}ms, ${aggregatorResult.tokenUsage.output_tokens} out tokens\n`,
)

// ---------------------------------------------------------------------------
// Output markdown report
// ---------------------------------------------------------------------------

const totalTime = performance.now() - globalStartTime

console.log('='.repeat(80))
console.log('COMPETITIVE INTELLIGENCE REPORT')
console.log('='.repeat(80))
console.log()

console.log('## Summary\n')
console.log(report.summary)
console.log()

console.log('## Verified Claims\n')
if (report.verified_claims.length === 0) {
  console.log('_No claims verified across multiple sources._\n')
} else {
  for (const vc of report.verified_claims) {
    console.log(`**${vc.claim}**`)
    console.log(`  - Sources: ${vc.sources}`)
    console.log(`  - Confidence: ${(vc.avg_confidence * 100).toFixed(0)}% [${confidenceLabel(vc.avg_confidence)}]`)
    console.log(`  - First reported: ${vc.first_reported}`)
    console.log(`  - Consolidation: ${vc.consolidation}`)
    console.log()
  }
}

console.log('## Contradictions\n')
if (report.contradictions.length === 0) {
  console.log('_No contradictions detected._\n')
} else {
  for (const contradiction of report.contradictions) {
    console.log(`- **${contradiction.claim_topic}** [${severityLabel(contradiction.severity)}]`)
    console.log(`  - Version A (${contradiction.source_a}): ${contradiction.variant_a}`)
    console.log(`  - Version B (${contradiction.source_b}): ${contradiction.variant_b}`)
    console.log()
  }
}

// ---------------------------------------------------------------------------
// Timing validation
// ---------------------------------------------------------------------------

console.log('## Timing Analysis\n')

const totalSourceTokens =
  twitterResult.tokenUsage.output_tokens +
  redditResult.tokenUsage.output_tokens +
  newsResult.tokenUsage.output_tokens

console.log(`Total execution time: ${Math.round(totalTime)}ms`)
console.log(`  - Parallel monitoring: ${Math.round(monitorTime)}ms`)
console.log(`  - Aggregation: ${Math.round(aggregatorTime)}ms`)
console.log()

console.log(`Serial sum of monitors: ${Math.round(serialMonitorTime)}ms`)
console.log(`Parallel actual: ${Math.round(monitorTime)}ms`)
console.log(`Speedup: ${(serialMonitorTime / monitorTime).toFixed(2)}x`)
console.log()

const threshold = serialMonitorTime * 0.7
const assertion = monitorTime < threshold

console.log('Parallel speedup assertion (must be <70% of serial):')
console.log(`  ${Math.round(monitorTime)}ms < ${Math.round(threshold)}ms? ${assertion ? 'PASS' : 'FAIL'}`)

if (!assertion) {
  console.warn('\nWarning: Parallel execution did not achieve 70% reduction vs serial sum.')
  console.warn('This may indicate insufficient parallelism or overhead.')
}

console.log()
console.log(`Total tokens: ${totalSourceTokens + aggregatorResult.tokenUsage.output_tokens}`)
console.log('='.repeat(80))

if (!assertion) {
  process.exit(1)
}

console.log('\nCompetitive monitoring complete.\n')

// ---------------------------------------------------------------------------
// Real API variant (commented out by default)
// ---------------------------------------------------------------------------

// To use live feeds instead of committed JSON fixtures, replace the fixture
// loaders above with your own source adapters, for example:
//
// const twitterData = await fetchTwitterFeed(...)
// const redditData = await fetchRedditPosts(...)
// const newsData = await fetchNewsArticles(...)
//
// The extraction and aggregation stages can stay unchanged so the example keeps
// demonstrating the same fan-out + contradiction-detection workflow.

contract-review-dag.source:
/**
 * Contract Review DAG with Step-Level Retry
 *
 * Demonstrates DAG task orchestration with step-level retry using runTasks().
 * Scenario: contract review pipeline with 4 tasks forming a DAG:
 *
 *   [Task 1: extract-clauses]
 *          ├──→ [Task 2: compliance-check] ────┐
 *          │                                    ├──→ [Task 4: notify] → Markdown
 *          └──→ [Task 3: summary] ──────────────┘
 *
 * Key features:
 * - DAG dependencies with parallel execution (Task 2 and 3 run concurrently)
 * - Step-level retry on Task 2/3/4 with exponential backoff
 * - FORCE_FAIL=task2 env var triggers Task 2 failure on first attempt
 *
 * Run:
 *   npx tsx packages/core/examples/cookbook/contract-review-dag.ts
 *   FORCE_FAIL=task2 npx tsx packages/core/examples/cookbook/contract-review-dag.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY env var must be set.
 */

import { OpenMultiAgent } from '../../src/index.js'
import type { AgentConfig, OrchestratorEvent } from '../../src/types.js'
import { readFileSync } from 'fs'
import { fileURLToPath } from 'url'
import { dirname, join } from 'path'

const __filename = fileURLToPath(import.meta.url)
const __dirname = dirname(__filename)

// ---------------------------------------------------------------------------
// Attempt counter for FORCE_FAIL mechanism (closure-based per agent)
// ---------------------------------------------------------------------------
const attemptCounter = new Map<string, number>()

function getAndIncrementAttempt(agentName: string): number {
  const count = (attemptCounter.get(agentName) ?? 0) + 1
  attemptCounter.set(agentName, count)
  return count
}

// ---------------------------------------------------------------------------
// Step 1: Agent configurations (4 agents)
// ---------------------------------------------------------------------------

const extractorConfig: AgentConfig = {
  name: 'extractor',
  model: 'claude-sonnet-4-6',
  provider: 'anthropic',
  systemPrompt: `You are a contract clause extraction specialist. Extract all clauses from the provided contract text and output as a JSON array.

Each object must have:
- id: clause number (string)
- title: clause title
- content: full clause text
- riskLevel: "low" | "medium" | "high"

Output ONLY valid JSON, no other text.`,
  maxTurns: 1,
  temperature: 0.1,
}

const complianceCheckerConfig: AgentConfig = {
  name: 'compliance-checker',
  model: 'claude-sonnet-4-6',
  provider: 'anthropic',
  systemPrompt: `You are a contract compliance auditor. Review each clause for regulatory and operational compliance.

For each clause, output:
- clauseId: clause number
- isCompliant: true/false
- issues: array of issues found (empty array if none)
- riskCategory: "none" | "regulatory" | "operational" | "legal"

Output ONLY valid JSON array, no other text.`,
  maxTurns: 1,
  temperature: 0.1,
  beforeRun: (context) => {
    const attempt = getAndIncrementAttempt('compliance-checker')

    // Only trigger FORCE_FAIL on first attempt (attempt=1)
    if (attempt === 1 && process.env.FORCE_FAIL === 'task2') {
      throw new Error('[FORCE_FAIL_TRIGGERED]')
    }
    return context
  },
}

const summarizerConfig: AgentConfig = {
  name: 'summarizer',
  model: 'claude-sonnet-4-6',
  provider: 'anthropic',
  systemPrompt: `You are a contract summary specialist. Generate an executive summary from the extracted clause list.

Include:
- Contract overview (main areas covered)
- Key clause summary (3-5 most important points)
- Risk callouts (highlight high-risk clauses)
- Recommended next steps

Output in Markdown format.`,
  maxTurns: 1,
  temperature: 0.2,
}

const notifierConfig: AgentConfig = {
  name: 'notifier',
  model: 'claude-sonnet-4-6',
  provider: 'anthropic',
  systemPrompt: `You are a report writer. Combine the compliance check results and summary into a final contract review report.

Include:
- Executive Summary
- Compliance Results
- Risk Details
- Recommended Actions

Output in Markdown format.`,
  maxTurns: 1,
  temperature: 0.2,
}

// ---------------------------------------------------------------------------
// Step 2: Task configurations (4 tasks)
// ---------------------------------------------------------------------------

interface TaskConfig {
  title: string
  description: string
  assignee?: string
  dependsOn?: readonly string[]
  maxRetries?: number
  retryDelayMs?: number
  retryBackoff?: number
}

// Task configs will be created after reading contract text

// ---------------------------------------------------------------------------
// Step 3: Progress tracking
// ---------------------------------------------------------------------------

interface TaskTiming {
  startTime: number
  endTime?: number
}

const taskTimings = new Map<string, TaskTiming>()
const taskStartTimes = new Map<string, number>()

function handleProgress(event: OrchestratorEvent): void {
  const ts = new Date().toISOString()

  switch (event.type) {
    case 'task_start': {
      const task = event.data as { id: string; title: string } | undefined
      if (task) {
        const now = Date.now()
        taskTimings.set(task.id, { startTime: now })
        taskStartTimes.set(task.title, now)  // Use title as key for easier verification
        console.log(`[${ts}] task_start: ${task.title}`)
      }
      break
    }

    case 'task_complete': {
      const task = event.data as { id: string; title: string } | undefined
      if (task) {
        const timing = taskTimings.get(task.id)
        if (timing) {
          timing.endTime = Date.now()
          const duration = timing.endTime - timing.startTime
          console.log(`[${ts}] task_complete: ${task.title} (${duration}ms)`)
        }
      }
      break
    }

    case 'task_retry':
      console.log(`[${ts}] task_retry:`, JSON.stringify(event.data))
      break

    case 'task_skipped':
      console.log(`[${ts}] task_skipped: ${event.task}`)
      break

    case 'agent_start':
      if (event.agent) {
        console.log(`[${ts}] agent_start: ${event.agent}`)
      }
      break

    case 'agent_complete':
      if (event.agent) {
        console.log(`[${ts}] agent_complete: ${event.agent}`)
      }
      break

    case 'message':
      if (typeof event.data === 'string') {
        console.log(`[${ts}] message: ${event.data}`)
      }
      break

    case 'error':
      console.log(`[${ts}] error:`, JSON.stringify(event.data))
      break

    default:
      break
  }
}

// ---------------------------------------------------------------------------
// Step 4: Parallelism verification
// ---------------------------------------------------------------------------

function verifyParallelism(): void {
  const t2Start = taskStartTimes.get('compliance-check')
  const t3Start = taskStartTimes.get('summary')

  if (t2Start !== undefined && t3Start !== undefined) {
    const diff = Math.abs(t2Start - t3Start)
    console.log('\n=== Parallelism Check ===')
    console.log(`Task 2 (compliance-check) start: ${t2Start}`)
    console.log(`Task 3 (summary) start: ${t3Start}`)
    console.log(`Time difference: ${diff}ms`)

    if (diff >= 500) {
      console.error(
        `ASSERTION FAILED: Task 2 and Task 3 start times differ by ${diff}ms (>= 500ms). ` +
          `Expected parallel execution after Task 1 completes.`,
      )
      process.exit(1)
    }
    console.log(`Parallel execution (< 500ms): YES`)
    console.log('========================\n')
  } else {
    console.log('\n=== Parallelism Check: Unable to verify (missing timing data) ===\n')
  }
}

// ---------------------------------------------------------------------------
// Step 5: Orchestrator and Team configuration
// ---------------------------------------------------------------------------

const orchestrator = new OpenMultiAgent({
  defaultModel: 'claude-sonnet-4-6',
  defaultProvider: 'anthropic',
  onProgress: handleProgress,
})

const team = orchestrator.createTeam('contract-review-team', {
  name: 'contract-review-team',
  agents: [extractorConfig, complianceCheckerConfig, summarizerConfig, notifierConfig],
  sharedMemory: true,
})

// ---------------------------------------------------------------------------
// Step 6: Read contract text
// ---------------------------------------------------------------------------

const contractText = readFileSync(
  join(__dirname, '..', 'fixtures', 'sample-contract.txt'),
  'utf-8',
)

// ---------------------------------------------------------------------------
// Step 6b: Create task configs with contract text
// ---------------------------------------------------------------------------

const taskConfigs: TaskConfig[] = [
  {
    title: 'extract-clauses',
    description: `Extract all clauses from the following contract text into structured JSON.\n\n=== CONTRACT TEXT ===\n${contractText}\n=== END CONTRACT ===\n\nOutput only valid JSON array.`,
    assignee: 'extractor',
  },
  {
    title: 'compliance-check',
    description: 'Check each clause for regulatory and operational compliance. Using the clause list from Task 1 above.',
    assignee: 'compliance-checker',
    dependsOn: ['extract-clauses'],
    maxRetries: 2,
    retryDelayMs: 500,
    retryBackoff: 2,
  },
  {
    title: 'summary',
    description: 'Generate executive summary of the contract. Using the clause list from Task 1 above.',
    assignee: 'summarizer',
    dependsOn: ['extract-clauses'],
    maxRetries: 2,
    retryDelayMs: 500,
    retryBackoff: 2,
  },
  {
    title: 'notify',
    description: 'Generate final markdown report with all analysis results',
    assignee: 'notifier',
    dependsOn: ['compliance-check', 'summary'],
    maxRetries: 2,
    retryDelayMs: 500,
    retryBackoff: 2,
  },
]

console.log('Contract Review DAG with Step-Level Retry')
console.log('='.repeat(60))
console.log(`\nContract: ${contractText.split('\n')[0]}`)
console.log(`Length: ${contractText.split(/\s+/).length} words\n`)
console.log(`FORCE_FAIL mode: ${process.env.FORCE_FAIL === 'task2' ? 'ENABLED (task2)' : 'disabled'}\n`)

// ---------------------------------------------------------------------------
// Step 7: Run the DAG
// ---------------------------------------------------------------------------

async function main(): Promise<void> {
  try {
    console.log('[Orchestration] Starting DAG execution...\n')

    const result = await orchestrator.runTasks(team, taskConfigs)

    // Verify parallelism
    verifyParallelism()

    console.log('\n' + '='.repeat(60))
    console.log('FINAL RESULT')
    console.log('='.repeat(60))
    console.log(`Success: ${result.success}`)
    console.log(`Total tasks: ${result.tasks?.length ?? taskConfigs.length}`)
    console.log(`Total token usage: ${result.totalTokenUsage.input_tokens} input, ${result.totalTokenUsage.output_tokens} output`)

    // Output each agent's result
    console.log('\n' + '='.repeat(60))
    console.log('AGENT RESULTS')
    console.log('='.repeat(60))
    for (const [agentName, agentResult] of result.agentResults) {
      console.log(`\n--- ${agentName} ---`)
      console.log(agentResult.success ? agentResult.output : `[FAILED] ${agentResult.output}`)
    }

    if (result.success) {
      console.log('\n--- Final Report ---')
      const notifierResult = result.agentResults.get('notifier')
      if (notifierResult?.output) {
        console.log(notifierResult.output)
      }
    } else {
      console.log('\nWorkflow failed.')
      for (const task of result.tasks ?? []) {
        if (task.status === 'failed') {
          console.log(`  - ${task.title}: failed`)
        }
      }
    }

    console.log('\n' + '='.repeat(60))
    console.log('Done.')
  } catch (error) {
    console.error('Fatal error:', error)
    process.exit(1)
  }
}

main()

consensus.source:
/**
 * Proposer / Judge Consensus Pattern
 *
 * Demonstrates `runConsensus()`: a proposer agent drafts an answer, then a
 * panel of judge agents tries to refute it. If enough judges accept (quorum),
 * the answer is returned as `accepted`. If dissent exceeds the budget, the
 * proposer revises and the loop repeats up to `maxRounds`.
 *
 * This example shows two variations:
 *   1. Basic — default judge prompt, mode `'refute'`, quorum 1 of 2.
 *   2. Custom judgePrompt — per-judge framing via a function so each judge
 *      evaluates from a different angle (security vs. maintainability).
 *
 * Run:
 *   npx tsx packages/core/examples/patterns/consensus.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY env var must be set.
 */

import { OpenMultiAgent } from '../../src/index.js'
import type { AgentConfig } from '../../src/types.js'

// ---------------------------------------------------------------------------
// Agent configs
// ---------------------------------------------------------------------------

const proposer: AgentConfig = {
  name: 'proposer',
  model: 'claude-haiku-4-5-20251001',
  provider: 'anthropic',
  systemPrompt: `You are a senior software architect. When asked to recommend an
approach, give a clear, concise recommendation (150-200 words) with the core
tradeoffs called out. Be direct — state what you recommend and why.`,
  maxTurns: 2,
  temperature: 0.3,
}

const judgeA: AgentConfig = {
  name: 'judge-correctness',
  model: 'claude-haiku-4-5-20251001',
  provider: 'anthropic',
  systemPrompt: `You are a rigorous code reviewer focused on correctness and
edge cases. When evaluating a technical recommendation, look for logical flaws,
incorrect assumptions, or missing failure modes. Be honest: if the proposal is
sound, say so. If not, be specific about what's wrong.`,
  maxTurns: 1,
  temperature: 0.2,
}

const judgeB: AgentConfig = {
  name: 'judge-pragmatism',
  model: 'claude-haiku-4-5-20251001',
  provider: 'anthropic',
  systemPrompt: `You are a pragmatic engineering lead focused on what actually
ships. When evaluating a technical recommendation, look for over-engineering,
unwarranted complexity, or impractical constraints. Be honest: if the proposal
is practical, say so. If not, be specific about what's impractical.`,
  maxTurns: 1,
  temperature: 0.2,
}

// ---------------------------------------------------------------------------
// Orchestrator + team
// ---------------------------------------------------------------------------

const orchestrator = new OpenMultiAgent({ defaultModel: 'claude-haiku-4-5-20251001' })

const team = orchestrator.createTeam('consensus-team', {
  name: 'consensus-team',
  agents: [proposer, judgeA, judgeB],
  sharedMemory: true,
})

const PROMPT = `Should a Node.js API service store user sessions in Redis or in
a signed JWT stored client-side? The service has ~5k DAU, a single-region
deployment, and no existing Redis infrastructure. Recommend one approach with
clear reasoning.`

console.log('Proposer / Judge Consensus Pattern')
console.log('='.repeat(60))
console.log(`\nQuestion: ${PROMPT.replace(/\n/g, ' ').trim()}\n`)

// ---------------------------------------------------------------------------
// Variation 1: default judge prompt, mode 'refute', quorum 1 of 2
// ---------------------------------------------------------------------------

console.log('--- Variation 1: basic (default judgePrompt, mode refute) ---\n')

const result1 = await orchestrator.runConsensus(team, PROMPT, {
  proposer,
  judges: [judgeA, judgeB],
  mode: 'refute',
  quorum: 1,
  maxRounds: 2,
  onDissent: 'revise',
})

console.log(`Verdict:  ${result1.verdict}`)
console.log(`Rounds:   ${result1.rounds}`)
console.log(`Dissent:  ${result1.dissent.length} critique(s)`)
if (result1.dissent.length > 0) {
  for (const d of result1.dissent) {
    console.log(`  • ${d.slice(0, 120).replace(/\n/g, ' ')}`)
  }
}
console.log(`\nAnswer:\n${result1.answer}\n`)

// ---------------------------------------------------------------------------
// Variation 2: per-judge framing via judgePrompt function
//
// Each judge receives a different lens. The function receives the judge's name
// and returns the full prompt to send. This is useful when you want one judge
// to focus on security and another on operational cost rather than both
// applying the same skeptic framing.
// ---------------------------------------------------------------------------

console.log('--- Variation 2: custom judgePrompt per judge ---\n')

const perJudgeLens: Record<string, string> = {
  'judge-correctness': `Evaluate the proposal strictly from a security standpoint.
Does it have authentication, session fixation, or token theft risks?
Reply with JSON: { "accept": true/false, "critique": "..." }`,
  'judge-pragmatism': `Evaluate the proposal strictly from an operational cost
standpoint. Is the infrastructure footprint reasonable for a 5k-DAU service?
Reply with JSON: { "accept": true/false, "critique": "..." }`,
}

const result2 = await orchestrator.runConsensus(team, PROMPT, {
  proposer,
  judges: [judgeA, judgeB],
  quorum: 1,
  maxRounds: 1,
  onDissent: 'keep',
  judgePrompt: (judgeName: string) =>
    perJudgeLens[judgeName] ??
    `Evaluate the proposal. Reply with JSON: { "accept": true/false, "critique": "..." }`,
})

console.log(`Verdict:  ${result2.verdict}`)
console.log(`Rounds:   ${result2.rounds}`)
console.log(`Dissent:  ${result2.dissent.length} critique(s)`)
if (result2.dissent.length > 0) {
  for (const d of result2.dissent) {
    console.log(`  • ${d.slice(0, 120).replace(/\n/g, ' ')}`)
  }
}
console.log(`\nAnswer:\n${result2.answer}\n`)

// ---------------------------------------------------------------------------
// Token summary
// ---------------------------------------------------------------------------

console.log('='.repeat(60))
console.log('Token Usage')
console.log('='.repeat(60))
console.log(
  `  Variation 1 — input: ${result1.tokenUsage.input_tokens}, output: ${result1.tokenUsage.output_tokens}`,
)
console.log(
  `  Variation 2 — input: ${result2.tokenUsage.input_tokens}, output: ${result2.tokenUsage.output_tokens}`,
)
const totalIn = result1.tokenUsage.input_tokens + result2.tokenUsage.input_tokens
const totalOut = result1.tokenUsage.output_tokens + result2.tokenUsage.output_tokens
console.log(`  TOTAL       — input: ${totalIn}, output: ${totalOut}`)
console.log('\nDone.')

single-agent.source:
/**
 * Single Agent
 *
 * The simplest possible usage: one agent with bash and file tools, running
 * a coding task. Then shows streaming output using the Agent class directly.
 *
 * Run:
 *   npx tsx packages/core/examples/basics/single-agent.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY env var must be set.
 */

import { join } from 'node:path'
import { OpenMultiAgent, Agent, ToolRegistry, ToolExecutor, registerBuiltInTools } from '../../src/index.js'
import type { OrchestratorEvent } from '../../src/types.js'

// Built-in filesystem tools are sandboxed to `<cwd>/.agent-workspace` by
// default; write example output there so the demo runs without disabling
// the sandbox.
const OUTPUT_DIR = join(process.cwd(), '.agent-workspace', 'single-agent')
const GREET_FILE = join(OUTPUT_DIR, 'greet.ts')

// ---------------------------------------------------------------------------
// Part 1: Single agent via OpenMultiAgent (simplest path)
// ---------------------------------------------------------------------------

const orchestrator = new OpenMultiAgent({
  defaultModel: 'claude-sonnet-4-6',
  onProgress: (event: OrchestratorEvent) => {
    if (event.type === 'agent_start') {
      console.log(`[start]    agent=${event.agent}`)
    } else if (event.type === 'agent_complete') {
      console.log(`[complete] agent=${event.agent}`)
    }
  },
})

console.log('Part 1: runAgent() — single one-shot task\n')

const result = await orchestrator.runAgent(
  {
    name: 'coder',
    model: 'claude-sonnet-4-6',
    systemPrompt: `You are a focused TypeScript developer.
When asked to implement something, write clean, minimal code with no extra commentary.
Use the bash tool to run commands and the file tools to read/write files.`,
    tools: ['bash', 'file_read', 'file_write'],
    maxTurns: 8,
  },
  `Create a small TypeScript utility function in ${GREET_FILE} that:
  1. Exports a function named greet(name: string): string
  2. Returns "Hello, <name>!"
  3. Adds a brief usage comment at the top of the file.
  Then add a default call greet("World") at the bottom and run the file with: npx tsx ${GREET_FILE}`,
)

if (result.success) {
  console.log('\nAgent output:')
  console.log('─'.repeat(60))
  console.log(result.output)
  console.log('─'.repeat(60))
} else {
  console.error('Agent failed:', result.output)
  process.exit(1)
}

console.log('\nToken usage:')
console.log(`  input:  ${result.tokenUsage.input_tokens}`)
console.log(`  output: ${result.tokenUsage.output_tokens}`)
console.log(`  tool calls made: ${result.toolCalls.length}`)

// ---------------------------------------------------------------------------
// Part 2: Streaming via Agent directly
//
// OpenMultiAgent.runAgent() is a convenient wrapper. When you need streaming, use
// the Agent class directly with an injected ToolRegistry + ToolExecutor.
// ---------------------------------------------------------------------------

console.log('\n\nPart 2: Agent.stream() — incremental text output\n')

// Build a registry with all built-in tools registered
const registry = new ToolRegistry()
registerBuiltInTools(registry)
const executor = new ToolExecutor(registry)

const streamingAgent = new Agent(
  {
    name: 'explainer',
    model: 'claude-sonnet-4-6',
    systemPrompt: 'You are a concise technical writer. Keep explanations brief.',
    maxTurns: 3,
  },
  registry,
  executor,
)

process.stdout.write('Streaming: ')

for await (const event of streamingAgent.stream(
  'In two sentences, explain what a TypeScript generic constraint is.',
)) {
  if (event.type === 'text' && typeof event.data === 'string') {
    process.stdout.write(event.data)
  } else if (event.type === 'done') {
    process.stdout.write('\n')
  } else if (event.type === 'error') {
    console.error('\nStream error:', event.data)
  }
}

// ---------------------------------------------------------------------------
// Part 3: Multi-turn conversation via Agent.prompt()
// ---------------------------------------------------------------------------

console.log('\nPart 3: Agent.prompt() — multi-turn conversation\n')

const conversationAgent = new Agent(
  {
    name: 'tutor',
    model: 'claude-sonnet-4-6',
    systemPrompt: 'You are a TypeScript tutor. Give short, direct answers.',
    maxTurns: 2,
    // Keep only the most recent turn in long prompt() conversations.
    contextStrategy: { type: 'sliding-window', maxTurns: 1 },
  },
  new ToolRegistry(), // no tools needed for this conversation
  new ToolExecutor(new ToolRegistry()),
)

const turn1 = await conversationAgent.prompt('What is a type guard in TypeScript?')
console.log('Turn 1:', turn1.output.slice(0, 200))

const turn2 = await conversationAgent.prompt('Give me one concrete code example of what you just described.')
console.log('\nTurn 2:', turn2.output.slice(0, 300))

// History is retained between prompt() calls
console.log(`\nConversation history length: ${conversationAgent.getHistory().length} messages`)

console.log('\nDone.')

incident-postmortem-dag.source:
/**
 * Incident Postmortem DAG with Parallel Fan-Out
 *
 * Demonstrates DAG task orchestration with three independent root tasks
 * fanning out from t=0, then synthesizing into a final postmortem document.
 *
 *   log-pattern-extractor   |
 *   correlate-deploys       |--> root-cause-hypothesizer --> postmortem-writer
 *   analyze-blast-radius    |
 * departures from that template:
 *   - No FORCE_FAIL / retry-demonstration machinery -- this example's
 *     theme is parallel fan-out + multi-source synthesis, not retry.
 *   - Three parallel root tasks (instead of two), so the parallelism
 *     check asserts that all three start within a 500ms window.
 *   - Final postmortem is also written to disk via os.tmpdir().
 *   - Token cost on claude-sonnet-4-6 is printed alongside token totals.
 *
 * Run:
 *   npx tsx packages/core/examples/cookbook/incident-postmortem-dag.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY env var must be set.
 *
 * Local validation hatch:
 *   EXAMPLE_PROVIDER=openrouter switches every agent + the orchestrator
 *   defaults to a free OpenRouter model (openrouter/free)
 *   via the OpenAI-compatible adapter. The framework reads OPENAI_API_KEY
 *   and OPENAI_BASE_URL from env.
 */

import { OpenMultiAgent } from '../../src/index.js'
import type { AgentConfig, OrchestratorEvent } from '../../src/types.js'
import { readFileSync, writeFileSync } from 'fs'
import { fileURLToPath } from 'url'
import { dirname, join } from 'path'
import { tmpdir } from 'os'

const __filename = fileURLToPath(import.meta.url)
const __dirname = dirname(__filename)

// ---------------------------------------------------------------------------
// Step 1: Agent configurations (5 agents)
// ---------------------------------------------------------------------------

const logPatternExtractorConfig: AgentConfig = {
  name: 'log-pattern-extractor',
  model: 'claude-sonnet-4-6',
  provider: 'anthropic',
  systemPrompt: `You are a log analysis specialist. Parse the provided raw backend logs and identify:
- Error clusters (group by error message / endpoint / service)
- The timestamp of the first regression (when error rate clearly departs from baseline)
- Noisy hosts/services/endpoints

Output a JSON object with this shape:
{
  "first_regression_at": "ISO 8601 timestamp",
  "error_clusters": [
    { "service": string, "endpoint": string, "error": string, "count": number, "first_seen": string, "last_seen": string }
  ],
  "noisy_endpoints": [ { "endpoint": string, "error_count": number } ],
  "notes": string
}

Output ONLY valid JSON, no other text.`,
  maxTurns: 1,
  temperature: 0.1,
}

const deployCorrelatorConfig: AgentConfig = {
  name: 'deploy-correlator',
  model: 'claude-sonnet-4-6',
  provider: 'anthropic',
  systemPrompt: `You are a deploy correlation analyst. Given a list of recent deploys and a window of incident symptoms, identify which deploy(s) most plausibly caused the symptoms based on timing and changed paths.

Output a JSON object:
{
  "ranked_candidates": [
    {
      "sha": string,
      "deployed_at": string,
      "summary": string,
      "confidence": "high" | "medium" | "low",
      "rationale": string
    }
  ],
  "ruled_out": [ { "sha": string, "reason": string } ]
}

Output ONLY valid JSON, no other text.`,
  maxTurns: 1,
  temperature: 0.1,
}

const blastRadiusAnalystConfig: AgentConfig = {
  name: 'blast-radius-analyst',
  model: 'claude-sonnet-4-6',
  provider: 'anthropic',
  systemPrompt: `You are a blast radius analyst. From the provided logs, estimate user-facing impact.

Output a JSON object:
{
  "affected_endpoints": [ { "endpoint": string, "method": string } ],
  "approximate_failed_requests": number,
  "approximate_total_requests_in_window": number,
  "error_rate_pct": number,
  "impact_window": { "start": string, "end": string },
  "user_facing_severity": "low" | "medium" | "high" | "critical",
  "notes": string
}

Output ONLY valid JSON, no other text.`,
  maxTurns: 1,
  temperature: 0.1,
}

const rootCauseHypothesizerConfig: AgentConfig = {
  name: 'root-cause-hypothesizer',
  model: 'claude-sonnet-4-6',
  provider: 'anthropic',
  systemPrompt: `You are a root cause analyst. Using the log patterns and deploy correlation from the previous tasks (available via shared memory), propose 2-3 ranked root cause hypotheses.

For each hypothesis, include:
- A short title
- Confidence (high / medium / low)
- Supporting evidence (cite specific log clusters and deploy SHAs)
- What you'd check next to confirm or refute it

Output in Markdown format, with hypotheses as numbered ## headings ranked from most to least likely.`,
  maxTurns: 1,
  temperature: 0.2,
}

const postmortemWriterConfig: AgentConfig = {
  name: 'postmortem-writer',
  model: 'claude-sonnet-4-6',
  provider: 'anthropic',
  systemPrompt: `You are a postmortem author. Synthesize a final incident postmortem in Markdown using the log patterns, deploy correlation, blast radius, and root cause hypotheses from the previous tasks (available via shared memory).

Use these top-level sections, in order:
- # Incident Postmortem
- ## Summary
- ## Timeline
- ## Impact
- ## Contributing Factors
- ## Action Items

Keep it tight and factual. Cite specific timestamps, endpoints, and deploy SHAs where they support a claim. Action items should be concrete and assignable.`,
  maxTurns: 1,
  temperature: 0.2,
}

// ---------------------------------------------------------------------------
// Step 2: Task configurations (5 tasks)
// ---------------------------------------------------------------------------

interface TaskConfig {
  title: string
  description: string
  assignee?: string
  dependsOn?: readonly string[]
  maxRetries?: number
  retryDelayMs?: number
  retryBackoff?: number
}

// Task configs will be created after reading fixture files (see Step 6b)

// ---------------------------------------------------------------------------
// Step 3: Progress tracking
// ---------------------------------------------------------------------------

interface TaskTiming {
  startTime: number
  endTime?: number
}

const taskTimings = new Map<string, TaskTiming>()
const taskStartTimes = new Map<string, number>()

function handleProgress(event: OrchestratorEvent): void {
  const ts = new Date().toISOString()

  switch (event.type) {
    case 'task_start': {
      const task = event.data as { id: string; title: string } | undefined
      if (task) {
        const now = Date.now()
        taskTimings.set(task.id, { startTime: now })
        taskStartTimes.set(task.title, now)  // Use title as key for easier verification
        console.log(`[${ts}] task_start: ${task.title}`)
      }
      break
    }

    case 'task_complete': {
      const task = event.data as { id: string; title: string } | undefined
      if (task) {
        const timing = taskTimings.get(task.id)
        if (timing) {
          timing.endTime = Date.now()
          const duration = timing.endTime - timing.startTime
          console.log(`[${ts}] task_complete: ${task.title} (${duration}ms)`)
        }
      }
      break
    }

    case 'task_retry':
      console.log(`[${ts}] task_retry:`, JSON.stringify(event.data))
      break

    case 'task_skipped':
      console.log(`[${ts}] task_skipped: ${event.task}`)
      break

    case 'agent_start':
      if (event.agent) {
        console.log(`[${ts}] agent_start: ${event.agent}`)
      }
      break

    case 'agent_complete':
      if (event.agent) {
        console.log(`[${ts}] agent_complete: ${event.agent}`)
      }
      break

    case 'message':
      if (typeof event.data === 'string') {
        console.log(`[${ts}] message: ${event.data}`)
      }
      break

    case 'error':
      console.log(`[${ts}] error:`, JSON.stringify(event.data))
      break

    default:
      break
  }
}

// ---------------------------------------------------------------------------
// Step 4: Parallelism verification
// ---------------------------------------------------------------------------

function verifyParallelism(): void {
  const t1 = taskStartTimes.get('extract-log-patterns')
  const t2 = taskStartTimes.get('correlate-deploys')
  const t3 = taskStartTimes.get('analyze-blast-radius')

  if (t1 !== undefined && t2 !== undefined && t3 !== undefined) {
    const spread = Math.max(t1, t2, t3) - Math.min(t1, t2, t3)
    console.log('\n=== Parallelism Check ===')
    console.log(`Task 1 (extract-log-patterns) start: ${t1}`)
    console.log(`Task 2 (correlate-deploys) start: ${t2}`)
    console.log(`Task 3 (analyze-blast-radius) start: ${t3}`)
    console.log(`Spread (max - min): ${spread}ms`)

    if (spread >= 500) {
      console.error(
        `ASSERTION FAILED: Tasks 1, 2, 3 start times spread by ${spread}ms (>= 500ms). ` +
          `Expected parallel execution from t=0.`,
      )
      process.exit(1)
    }
    console.log(`Parallel execution (< 500ms): YES`)
    console.log('========================\n')
  } else {
    console.log('\n=== Parallelism Check: Unable to verify (missing timing data) ===\n')
  }
}

// ---------------------------------------------------------------------------
// Step 5: Orchestrator and Team configuration
// ---------------------------------------------------------------------------

// Local validation hatch -- flip every agent's provider/model to a free
// OpenRouter model when EXAMPLE_PROVIDER=openrouter. The committed
// AgentConfig values above remain anthropic / claude-sonnet-4-6.
const useOpenRouter = process.env.EXAMPLE_PROVIDER === 'openrouter'
const OPENROUTER_MODEL = 'openrouter/free'

const agentConfigs: AgentConfig[] = [
  logPatternExtractorConfig,
  deployCorrelatorConfig,
  blastRadiusAnalystConfig,
  rootCauseHypothesizerConfig,
  postmortemWriterConfig,
]

const effectiveAgents: AgentConfig[] = useOpenRouter
  ? agentConfigs.map((c) => ({ ...c, provider: 'openai', model: OPENROUTER_MODEL }))
  : agentConfigs

const orchestrator = new OpenMultiAgent({
  defaultModel: useOpenRouter ? OPENROUTER_MODEL : 'claude-sonnet-4-6',
  defaultProvider: useOpenRouter ? 'openai' : 'anthropic',
  onProgress: handleProgress,
})

const team = orchestrator.createTeam('incident-postmortem-team', {
  name: 'incident-postmortem-team',
  agents: effectiveAgents,
  sharedMemory: true,
})

console.log(
  `[mode] provider=${useOpenRouter ? 'openai' : 'anthropic'} ` +
    `model=${useOpenRouter ? OPENROUTER_MODEL : 'claude-sonnet-4-6'}`,
)

// ---------------------------------------------------------------------------
// Step 6: Read fixture files
// ---------------------------------------------------------------------------

const logsText = readFileSync(
  join(__dirname, '..', 'fixtures', 'incident-logs.txt'),
  'utf-8',
)

const deploysText = readFileSync(
  join(__dirname, '..', 'fixtures', 'incident-deploys.json'),
  'utf-8',
)

// ---------------------------------------------------------------------------
// Step 6b: Create task configs with fixture content embedded
// ---------------------------------------------------------------------------

const taskConfigs: TaskConfig[] = [
  {
    title: 'extract-log-patterns',
    description: `Parse the following backend logs and extract structured error patterns.\n\n=== LOGS ===\n${logsText}\n=== END LOGS ===\n\nOutput only valid JSON.`,
    assignee: 'log-pattern-extractor',
  },
  {
    title: 'correlate-deploys',
    description: `Given the recent deploys below, identify which deploy(s) most likely caused the incident symptoms based on timing and changed paths. Symptoms: a sharp regression starting around 14:12 UTC on 2026-04-22, manifesting as 5xx errors. Use the timing alone for now; later tasks will cross-check against logs.\n\n=== DEPLOYS ===\n${deploysText}\n=== END DEPLOYS ===\n\nOutput only valid JSON.`,
    assignee: 'deploy-correlator',
  },
  {
    title: 'analyze-blast-radius',
    description: `Estimate user-facing impact (affected endpoints, approximate failed request count, error rate, severity) from the following logs.\n\n=== LOGS ===\n${logsText}\n=== END LOGS ===\n\nOutput only valid JSON.`,
    assignee: 'blast-radius-analyst',
  },
  {
    title: 'hypothesize-cause',
    description: 'Propose 2-3 ranked root cause hypotheses for the incident, using the log patterns and deploy correlation from the previous tasks. Cite specific log clusters and deploy SHAs.',
    assignee: 'root-cause-hypothesizer',
    dependsOn: ['extract-log-patterns', 'correlate-deploys'],
    maxRetries: 2,
    retryDelayMs: 500,
    retryBackoff: 2,
  },
  {
    title: 'write-postmortem',
    description: 'Write the final incident postmortem in Markdown, synthesizing the log patterns, deploy correlation, blast radius, and root cause hypotheses from the previous tasks. Use sections: Summary, Timeline, Impact, Contributing Factors, Action Items.',
    assignee: 'postmortem-writer',
    dependsOn: ['extract-log-patterns', 'correlate-deploys', 'analyze-blast-radius', 'hypothesize-cause'],
    maxRetries: 2,
    retryDelayMs: 500,
    retryBackoff: 2,
  },
]

console.log('Incident Postmortem DAG with Parallel Fan-Out')
console.log('='.repeat(60))
console.log(`\nLogs: ${logsText.split('\n').length} lines`)
console.log(`Deploys: ${(JSON.parse(deploysText) as unknown[]).length} entries\n`)

// ---------------------------------------------------------------------------
// Step 7: Run the DAG
// ---------------------------------------------------------------------------

async function main(): Promise<void> {
  try {
    console.log('[Orchestration] Starting DAG execution...\n')

    const result = await orchestrator.runTasks(team, taskConfigs)

    // Verify parallelism
    verifyParallelism()

    console.log('\n' + '='.repeat(60))
    console.log('FINAL RESULT')
    console.log('='.repeat(60))
    console.log(`Success: ${result.success}`)
    console.log(`Total tasks: ${result.tasks?.length ?? taskConfigs.length}`)
    console.log(`Total token usage: ${result.totalTokenUsage.input_tokens} input, ${result.totalTokenUsage.output_tokens} output`)

    // Cost estimate on claude-sonnet-4-6 -- even when running on OpenRouter,
    // this represents what the same token volume would cost on Anthropic.
    const inputCost = (result.totalTokenUsage.input_tokens / 1_000_000) * 3
    const outputCost = (result.totalTokenUsage.output_tokens / 1_000_000) * 15
    console.log(
      `Estimated cost on claude-sonnet-4-6: ~$${(inputCost + outputCost).toFixed(4)} USD ` +
        `(input @ $3/M, output @ $15/M)`,
    )

    // Output each agent's result
    console.log('\n' + '='.repeat(60))
    console.log('AGENT RESULTS')
    console.log('='.repeat(60))
    for (const [agentName, agentResult] of result.agentResults) {
      console.log(`\n--- ${agentName} ---`)
      console.log(agentResult.success ? agentResult.output : `[FAILED] ${agentResult.output}`)
    }

    if (result.success) {
      console.log('\n--- Final Postmortem ---')
      const writerResult = result.agentResults.get('postmortem-writer')
      const writerOutput = writerResult?.output ?? ''
      if (writerOutput) {
        console.log(writerOutput)
        const outPath = join(tmpdir(), 'incident-postmortem.md')
        writeFileSync(outPath, writerOutput, 'utf-8')
        console.log(`\nPostmortem written to: ${outPath}`)
      }
    } else {
      console.log('\nWorkflow failed.')
      for (const task of result.tasks ?? []) {
        if (task.status === 'failed') {
          console.log(`  - ${task.title}: failed`)
        }
      }
    }

    console.log('\n' + '='.repeat(60))
    console.log('Done.')
  } catch (error) {
    console.error('Fatal error:', error)
    process.exit(1)
  }
}

main()

rare-disease-information-triage.source:
/**
 * Rare Disease Information Triage (Source-Isolated Evidence Audit + Safety Arbitration)
 *
 * Demonstrates:
 * - Five source-isolated agents reading different MOCK fixtures
 * - Source-isolated evidence audits over patient-reported symptoms, nonprofit education,
 *   official guideline/expert-consensus style content, gene-phenotype evidence,
 *   and web/forum/commercial claims
 * - A downstream arbiter that receives only structured audit outputs
 * - Runtime conflict detection:
 *   - nonprofit content may make symptom overlap look specific
 *   - official guidance keeps the differential broad
 *   - gene-phenotype evidence is weak/uncertain for the claimed disease
 *   - web/commercial content overstates certainty and promotes a paid test
 *   - safety policy forbids diagnosis, treatment, dosing, or commercial recommendation
 * - Zod-validated structured output and simple runtime assertions
 *
 * Run:
 *   npx tsx packages/core/examples/cookbook/rare-disease-information-triage.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY env var must be set.
 *   Requires Node.js >= 18.
 *
 * Fixtures:
 *   All fixtures under examples/fixtures/rare-disease-information-triage/ are MOCK.
 *   They are shaped like realistic source types but do not contain real patient data
 *   and do not provide medical diagnosis or treatment advice.
 */

import { readFileSync } from 'node:fs'
import { fileURLToPath } from 'node:url'
import path from 'node:path'
import { z } from 'zod'
import { Agent, ToolExecutor, ToolRegistry } from '../../src/index.js'
import type { AgentConfig, AgentRunResult } from '../../src/types.js'

// ---------------------------------------------------------------------------
// Fixture loading
// ---------------------------------------------------------------------------

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const fixtureRoot = path.join(__dirname, '../fixtures/rare-disease-information-triage')

function readFixture(name: string): string {
  return readFileSync(path.join(fixtureRoot, name), 'utf-8')
}

const patientSymptomSummary = readFixture('patient-symptom-summary.json')
const nonprofitPatientEducation = readFixture('nonprofit-patient-education.md')
const officialGuidelineExcerpt = readFixture('official-guideline-excerpt.md')
const genePhenotypeEvidence = readFixture('gene-phenotype-evidence.json')
const webClaimsSnippets = readFixture('web-claims-snippets.json')
const medicalSafetyPolicy = readFixture('medical-safety-policy.json')
const MODEL = process.env['MODEL'] ?? 'claude-sonnet-4-6'
const ANTHROPIC_API_KEY = process.env['ANTHROPIC_API_KEY']
const ANTHROPIC_BASE_URL = process.env['ANTHROPIC_BASE_URL']

const providerConfig = {
  provider: 'anthropic' as const,
  model: MODEL,
  apiKey: ANTHROPIC_API_KEY,
  baseURL: ANTHROPIC_BASE_URL,
  tools: [] as const,
}

// ---------------------------------------------------------------------------
// Zod schemas
// ---------------------------------------------------------------------------

const SymptomAudit = z.object({
  source_is_mock: z.boolean(),
  symptom_clusters: z.array(z.string()),
  red_flags: z.array(z.string()),
  claimed_condition_from_patient_context: z.string(),
  missing_clinical_information: z.array(z.string()),
  diagnosis_attempted: z.boolean(),
})
type SymptomAudit = z.infer<typeof SymptomAudit>

const NonprofitEducationAudit = z.object({
  source_is_mock: z.boolean(),
  educational_claims: z.array(z.string()),
  simplification_risks: z.array(z.string()),
  patient_friendly_but_incomplete_points: z.array(z.string()),
  claims_that_may_overfocus_on_one_condition: z.array(z.string()),
})
type NonprofitEducationAudit = z.infer<typeof NonprofitEducationAudit>

const GuidelineAudit = z.object({
  source_is_mock: z.boolean(),
  candidate_disease_families: z.array(z.string()),
  specialist_evaluation_required: z.boolean(),
  reasons_symptoms_are_not_specific: z.array(z.string()),
  recommended_non_diagnostic_next_steps: z.array(z.string()),
})
type GuidelineAudit = z.infer<typeof GuidelineAudit>

const GeneticsAudit = z.object({
  source_is_mock: z.boolean(),
  claimed_gene_or_marker: z.string(),
  evidence_strength_for_claimed_disease: z.enum(['strong', 'moderate', 'weak', 'uncertain']),
  phenotype_consistency: z.enum(['consistent', 'partially_consistent', 'inconsistent', 'uncertain']),
  uncertainty_flags: z.array(z.string()),
})
type GeneticsAudit = z.infer<typeof GeneticsAudit>

const WebClaimsAudit = z.object({
  source_is_mock: z.boolean(),
  claims: z.array(z.object({
    source_label: z.string(),
    claim: z.string(),
    claim_type: z.enum(['forum_experience', 'general_web_content', 'commercial_promotion']),
    overstatement_risk: z.enum(['low', 'moderate', 'high']),
    commercial_intent: z.boolean(),
    unsupported_elements: z.array(z.string()),
  })),
})
type WebClaimsAudit = z.infer<typeof WebClaimsAudit>

const SafetyAudit = z.object({
  source_is_mock: z.boolean(),
  prohibited_outputs: z.array(z.string()),
  allowed_outputs: z.array(z.string()),
  required_disclaimers: z.array(z.string()),
  patient_facing_answer_allowed_without_clinician: z.boolean(),
})
type SafetyAudit = z.infer<typeof SafetyAudit>

const TriageDecision = z.object({
  decision: z.enum(['credible_lead', 'conflicting_evidence', 'misleading_or_commercial', 'needs_specialist_review']),
  confidence: z.enum(['low', 'medium', 'high']),
  conflicts: z.array(z.string()),
  missing_evidence: z.array(z.string()),
  unsafe_elements: z.array(z.string()),
  safe_next_steps: z.array(z.string()),
  patient_facing_answer_allowed: z.boolean(),
  diagnosis_provided: z.boolean(),
  rationale: z.string(),
})
type TriageDecision = z.infer<typeof TriageDecision>

// ---------------------------------------------------------------------------
// Agent configs
// ---------------------------------------------------------------------------

const symptomNormalizerConfig: AgentConfig = {
  name: 'symptom-normalizer',
  ...providerConfig,
  systemPrompt: `You are a medical information triage assistant.

You audit only a MOCK patient-reported symptom summary. You must not diagnose.
Extract symptom clusters, red flags, the patient's suspected condition from context,
and missing clinical information.

Return JSON matching the provided schema. Output ONLY valid JSON, no markdown, no code fences, and no explanatory prose. Output ONLY valid JSON, no markdown, no code fences, and no explanatory prose. Do not provide diagnosis or treatment advice.`,
  maxTurns: 1,
  maxTokens: 1800,
  temperature: 0.1,
  outputSchema: SymptomAudit,
}

const nonprofitEducationConfig: AgentConfig = {
  name: 'nonprofit-education-auditor',
  ...providerConfig,
  systemPrompt: `You audit only MOCK nonprofit / patient-advocacy educational content.

Your job is to identify what the patient-friendly content says, what it simplifies,
and whether the simplification may make symptom overlap look more disease-specific
than it is. Do not use outside medical knowledge.

Return JSON matching the provided schema. Output ONLY valid JSON, no markdown, no code fences, and no explanatory prose.`,
  maxTurns: 1,
  maxTokens: 1800,
  temperature: 0.1,
  outputSchema: NonprofitEducationAudit,
}

const guidelineAuditorConfig: AgentConfig = {
  name: 'guideline-auditor',
  ...providerConfig,
  systemPrompt: `You audit only a MOCK official disease guideline or expert-consensus style excerpt.

Identify the broad differential, why symptoms are not specific, whether specialist
evaluation is required, and safe non-diagnostic next steps. Do not diagnose.

Return JSON matching the provided schema. Output ONLY valid JSON, no markdown, no code fences, and no explanatory prose.`,
  maxTurns: 1,
  maxTokens: 1800,
  temperature: 0.1,
  outputSchema: GuidelineAudit,
}

const geneticsAuditorConfig: AgentConfig = {
  name: 'genetics-auditor',
  ...providerConfig,
  systemPrompt: `You audit only MOCK gene-phenotype evidence.

Assess whether the claimed gene or marker strongly supports the claimed rare disease,
whether the phenotype is consistent, and what uncertainty flags exist. Do not diagnose
or interpret real patient genetics.

Return JSON matching the provided schema. Output ONLY valid JSON, no markdown, no code fences, and no explanatory prose.`,
  maxTurns: 1,
  maxTokens: 1800,
  temperature: 0.1,
  outputSchema: GeneticsAudit,
}

const webClaimsAuditorConfig: AgentConfig = {
  name: 'web-claims-auditor',
  ...providerConfig,
  systemPrompt: `You audit only MOCK web, forum, and commercial claim snippets.

Classify each claim as forum experience, general web content, or commercial promotion.
Flag overstatement risk, commercial intent, and unsupported elements. Do not validate
claims using outside knowledge.

Return JSON matching the provided schema. Output ONLY valid JSON, no markdown, no code fences, and no explanatory prose.`,
  maxTurns: 1,
  maxTokens: 2000,
  temperature: 0.1,
  outputSchema: WebClaimsAudit,
}

const safetyBoundaryConfig: AgentConfig = {
  name: 'safety-boundary-agent',
  ...providerConfig,
  systemPrompt: `You audit only a MOCK medical safety policy.

Extract prohibited outputs, allowed outputs, required disclaimers, and whether a
patient-facing answer is allowed without a clinician. Do not generate medical advice.

Return JSON matching the provided schema. Output ONLY valid JSON, no markdown, no code fences, and no explanatory prose.`,
  maxTurns: 1,
  maxTokens: 1800,
  temperature: 0.1,
  outputSchema: SafetyAudit,
}

const arbiterConfig: AgentConfig = {
  name: 'rare-disease-triage-arbiter',
  ...providerConfig,
  systemPrompt: `You are the downstream arbiter for a rare disease information triage workflow.

You receive only structured outputs from source-isolated audits. You cannot access
the original fixtures. Your tasks:
1. Detect conflicts among the audits.
2. Identify misleading or commercial overclaims.
3. Enforce the safety boundary.
4. Decide whether the information is a credible lead, conflicting evidence,
   misleading/commercial content, or needs specialist review.
5. Never provide diagnosis, treatment advice, dosing, or commercial recommendation.

Return JSON matching the TriageDecision schema. The seeded conflict should be explicit:
web/commercial content maps symptom similarity to one rare disease, while the guideline
keeps the differential broad and genetics evidence is weak or uncertain.`,
  maxTurns: 1,
  maxTokens: 3000,
  temperature: 0.1,
  outputSchema: TriageDecision,
}

// ---------------------------------------------------------------------------
// Build agents
// ---------------------------------------------------------------------------

function buildAgent(config: AgentConfig): Agent {
  // Source isolation is enforced at runtime: fixtures are injected into prompts,
  // and audit agents receive an empty tool registry with tools: [].
  const registry = new ToolRegistry()
  const executor = new ToolExecutor(registry)
  return new Agent(config, registry, executor)
}

const symptomNormalizer = buildAgent(symptomNormalizerConfig)
const nonprofitEducationAuditor = buildAgent(nonprofitEducationConfig)
const guidelineAuditor = buildAgent(guidelineAuditorConfig)
const geneticsAuditor = buildAgent(geneticsAuditorConfig)
const webClaimsAuditor = buildAgent(webClaimsAuditorConfig)
const safetyBoundaryAgent = buildAgent(safetyBoundaryConfig)
const triageArbiter = buildAgent(arbiterConfig)

// ---------------------------------------------------------------------------
// Main execution
// ---------------------------------------------------------------------------

console.log('Rare Disease Information Triage - Source-Isolated Audit + Safety Arbitration')
console.log('='.repeat(88))
console.log(`Model backend: anthropic-compatible (${MODEL})`)
console.log('All fixtures are MOCK and contain no real patient data.')
console.log('Expected runtime conflict: simplified patient-facing content + commercial claim vs broad guideline differential + weak genetics evidence.\n')

async function runTimed(
  name: string,
  agent: Agent,
  prompt: string,
): Promise<{ name: string, result: AgentRunResult, elapsedMs: number }> {
  const start = performance.now()
  const maxAttempts = 3

  for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
    console.log(`  [RUN] ${name} started... attempt ${attempt}/${maxAttempts}`)
    const result = await agent.run(prompt)
    const elapsedMs = performance.now() - start

    if (result.success && result.structured) {
      console.log(`  [DONE] ${name} finished in ${Math.round(elapsedMs)}ms`)
      return { name, result, elapsedMs }
    }

    const outputPreview = result.output ? result.output.slice(0, 240).replace(/\s+/g, ' ') : '<empty output>'
    console.warn(`  [RETRY] ${name} failed structured output on attempt ${attempt}/${maxAttempts}: ${outputPreview}`)
  }

  const result = await agent.run(prompt)
  const elapsedMs = performance.now() - start
  console.log(`  [DONE] ${name} finished in ${Math.round(elapsedMs)}ms`)
  return { name, result, elapsedMs }
}

function requireStructured<T>(name: string, result: AgentRunResult): T {
  if (!result.success) {
    console.error(`${name} failed: ${result.output}`)
    process.exit(1)
  }

  if (!result.structured) {
    console.error(`${name} did not return structured output`)
    process.exit(1)
  }

  return result.structured as T
}

console.log('[Phase 1] Source-isolated audits\n')

const auditStart = performance.now()
const auditRuns: Array<{ name: string, result: AgentRunResult, elapsedMs: number }> = []

auditRuns.push(await runTimed(
  'symptom-normalizer',
  symptomNormalizer,
  `Audit this MOCK patient-reported symptom summary. Use only this input.\n\n${patientSymptomSummary}`,
))

auditRuns.push(await runTimed(
  'nonprofit-education-auditor',
  nonprofitEducationAuditor,
  `Audit this MOCK nonprofit / patient-advocacy educational content. Use only this input.\n\n${nonprofitPatientEducation}`,
))

auditRuns.push(await runTimed(
  'guideline-auditor',
  guidelineAuditor,
  `Audit this MOCK official guideline / expert-consensus style excerpt. Use only this input.\n\n${officialGuidelineExcerpt}`,
))

auditRuns.push(await runTimed(
  'genetics-auditor',
  geneticsAuditor,
  `Audit this MOCK gene-phenotype evidence. Use only this input.\n\n${genePhenotypeEvidence}`,
))

auditRuns.push(await runTimed(
  'web-claims-auditor',
  webClaimsAuditor,
  `Audit these MOCK web/forum/commercial claim snippets. Use only this input.\n\n${webClaimsSnippets}`,
))

auditRuns.push(await runTimed(
  'safety-boundary-agent',
  safetyBoundaryAgent,
  `Audit this MOCK medical safety policy. Use only this input.\n\n${medicalSafetyPolicy}`,
))
const auditElapsed = performance.now() - auditStart

const auditMap = new Map(auditRuns.map((run) => [run.name, run.result]))

const symptomAudit = requireStructured<SymptomAudit>('symptom-normalizer', auditMap.get('symptom-normalizer')!)
const nonprofitAudit = requireStructured<NonprofitEducationAudit>('nonprofit-education-auditor', auditMap.get('nonprofit-education-auditor')!)
const guidelineAudit = requireStructured<GuidelineAudit>('guideline-auditor', auditMap.get('guideline-auditor')!)
const geneticsAudit = requireStructured<GeneticsAudit>('genetics-auditor', auditMap.get('genetics-auditor')!)
const webClaimsAudit = requireStructured<WebClaimsAudit>('web-claims-auditor', auditMap.get('web-claims-auditor')!)
const safetyAudit = requireStructured<SafetyAudit>('safety-boundary-agent', auditMap.get('safety-boundary-agent')!)

console.log('\n[Phase 1 Summary]')
for (const run of auditRuns) {
  const status = run.result.success ? 'OK' : 'FAILED'
  console.log(`  ${run.name.padEnd(30)} [${status}] ${Math.round(run.elapsedMs)}ms, ${run.result.tokenUsage.output_tokens} out tokens`)
}
console.log(`  Audit wall time: ${Math.round(auditElapsed)}ms\n`)

console.log('[Phase 2] Downstream arbitration over structured audit outputs only\n')

const arbiterPrompt = `You are given structured outputs from six source-isolated audits.
You cannot access the original fixtures. Decide whether this case is a credible lead,
conflicting evidence, misleading/commercial, or needs specialist review.

SYMPTOM AUDIT:
${JSON.stringify(symptomAudit, null, 2)}

NONPROFIT EDUCATION AUDIT:
${JSON.stringify(nonprofitAudit, null, 2)}

OFFICIAL GUIDELINE / EXPERT-CONSENSUS AUDIT:
${JSON.stringify(guidelineAudit, null, 2)}

GENE-PHENOTYPE AUDIT:
${JSON.stringify(geneticsAudit, null, 2)}

WEB / FORUM / COMMERCIAL CLAIMS AUDIT:
${JSON.stringify(webClaimsAudit, null, 2)}

SAFETY BOUNDARY AUDIT:
${JSON.stringify(safetyAudit, null, 2)}

Rules:
- Do not produce a diagnosis.
- Do not recommend a treatment, dose, paid test, or commercial product.
- Surface the conflict between over-specific web/commercial claims and broader official/gene evidence.
- Return one JSON object matching the schema, no markdown.`

const arbiterStart = performance.now()
const arbiterResult = await triageArbiter.run(arbiterPrompt)
const arbiterElapsed = performance.now() - arbiterStart

const decision = requireStructured<TriageDecision>('rare-disease-triage-arbiter', arbiterResult)

console.log(`  Arbiter [OK] ${Math.round(arbiterElapsed)}ms, ${arbiterResult.tokenUsage.output_tokens} out tokens\n`)

// ---------------------------------------------------------------------------
// Runtime assertions
// ---------------------------------------------------------------------------

const allowedConflictDecisions: TriageDecision['decision'][] = [
  'conflicting_evidence',
  'misleading_or_commercial',
  'needs_specialist_review',
]

const asserts = [
  {
    name: 'decision should reflect conflict/safety concern',
    pass: allowedConflictDecisions.includes(decision.decision),
  },
  {
    name: 'patient-facing diagnosis should not be allowed',
    pass: decision.patient_facing_answer_allowed === false,
  },
  {
    name: 'diagnosis should not be provided',
    pass: decision.diagnosis_provided === false,
  },
  {
    name: 'conflicts should be surfaced',
    pass: decision.conflicts.length > 0,
  },
  {
    name: 'unsafe elements should be surfaced',
    pass: decision.unsafe_elements.length > 0,
  },
]

console.log('='.repeat(88))
console.log('RARE DISEASE INFORMATION TRIAGE DECISION')
console.log('='.repeat(88))
console.log(JSON.stringify(decision, null, 2))
console.log()

console.log('## Runtime Assertions\n')
let hasFailure = false
for (const assertion of asserts) {
  console.log(`- ${assertion.pass ? 'PASS' : 'FAIL'}: ${assertion.name}`)
  if (!assertion.pass) hasFailure = true
}

const totalOutputTokens =
  auditRuns.reduce((sum, run) => sum + run.result.tokenUsage.output_tokens, 0) +
  arbiterResult.tokenUsage.output_tokens

const totalInputTokens =
  auditRuns.reduce((sum, run) => sum + run.result.tokenUsage.input_tokens, 0) +
  arbiterResult.tokenUsage.input_tokens

console.log('\n## Token Usage\n')
console.log(`Input tokens: ${totalInputTokens}`)
console.log(`Output tokens: ${totalOutputTokens}`)
console.log('Estimated cost depends on the selected provider/model; this example prints token usage for transparency.')

console.log('\n' + '='.repeat(88))

if (hasFailure) {
  console.error('Runtime assertion failed.')
  process.exit(1)
}

console.log('Rare disease information triage example complete.\n')

// ---------------------------------------------------------------------------
// Production source adapter sketch
// ---------------------------------------------------------------------------
//
// This example intentionally uses committed MOCK fixtures so the demo is
// deterministic, safe, and runnable. A production version could replace fixtures
// with source adapters for patient intake forms, patient-advocacy education,
// official guideline repositories, gene-phenotype databases, web-claim crawlers,
// and an internally approved medical safety policy service. The source-isolated
// audit + downstream arbitration shape would remain the same.

team-collaboration.source:
/**
 * Multi-Agent Team Collaboration
 *
 * Three specialised agents (architect, developer, reviewer) collaborate on a
 * shared goal. The OpenMultiAgent orchestrator breaks the goal into tasks, assigns
 * them to the right agents, and collects the results.
 *
 * Run:
 *   npx tsx packages/core/examples/basics/team-collaboration.ts
 *
 * Prerequisites:
 *   OPENAI_API_KEY env var must be set. Works with any OpenAI-compatible
 *   provider: set OPENAI_BASE_URL + OMA_MODEL for Groq, DeepSeek, Ollama, etc.
 */

import { join } from 'node:path'
import { OpenMultiAgent } from '../../src/index.js'
import type { AgentConfig, OrchestratorEvent } from '../../src/types.js'

// Works with any OpenAI-compatible provider. Set OPENAI_API_KEY for OpenAI, or
// OPENAI_BASE_URL + OMA_MODEL for Groq, DeepSeek, Ollama, etc.
const model = process.env.OMA_MODEL ?? 'gpt-5.4'

// Built-in filesystem tools are sandboxed to `<cwd>/.agent-workspace` by
// default; the generated API lives under that root so the demo runs
// without disabling the sandbox.
const OUTPUT_DIR = join(process.cwd(), '.agent-workspace', 'express-api')

// ---------------------------------------------------------------------------
// Agent definitions
// ---------------------------------------------------------------------------

const architect: AgentConfig = {
  name: 'architect',
  model,
  systemPrompt: `You are a software architect with deep experience in Node.js and REST API design.
Your job is to design clear, production-quality API contracts and file/directory structures.
Output concise plans in markdown — no unnecessary prose.`,
  tools: ['bash', 'file_write'],
  maxTurns: 5,
  temperature: 0.2,
}

const developer: AgentConfig = {
  name: 'developer',
  model,
  systemPrompt: `You are a TypeScript/Node.js developer. You implement what the architect specifies.
Write clean, runnable code with proper error handling. Use the tools to write files and run tests.`,
  tools: ['bash', 'file_read', 'file_write', 'file_edit'],
  maxTurns: 12,
  temperature: 0.1,
}

const reviewer: AgentConfig = {
  name: 'reviewer',
  model,
  systemPrompt: `You are a senior code reviewer. Review code for correctness, security, and clarity.
Provide a structured review with: LGTM items, suggestions, and any blocking issues.
Read files using the tools before reviewing.`,
  tools: ['bash', 'file_read', 'grep'],
  maxTurns: 5,
  temperature: 0.3,
}

// ---------------------------------------------------------------------------
// Progress tracking
// ---------------------------------------------------------------------------

const startTimes = new Map<string, number>()

function handleProgress(event: OrchestratorEvent): void {
  const ts = new Date().toISOString().slice(11, 23) // HH:MM:SS.mmm

  switch (event.type) {
    case 'agent_start':
      startTimes.set(event.agent ?? '', Date.now())
      console.log(`[${ts}] AGENT START  → ${event.agent}`)
      break

    case 'agent_complete': {
      const elapsed = Date.now() - (startTimes.get(event.agent ?? '') ?? Date.now())
      console.log(`[${ts}] AGENT DONE   ← ${event.agent} (${elapsed}ms)`)
      break
    }

    case 'task_start':
      console.log(`[${ts}] TASK START   ↓ ${event.task}`)
      break

    case 'task_complete':
      console.log(`[${ts}] TASK DONE    ↑ ${event.task}`)
      break

    case 'message':
      console.log(`[${ts}] MESSAGE      • ${event.agent} → (team)`)
      break

    case 'error':
      console.error(`[${ts}] ERROR        ✗ agent=${event.agent} task=${event.task}`)
      if (event.data instanceof Error) {
        console.error(`               ${event.data.message}`)
      }
      break
  }
}

// ---------------------------------------------------------------------------
// Orchestrate
// ---------------------------------------------------------------------------

const orchestrator = new OpenMultiAgent({
  defaultProvider: 'openai',
  defaultModel: model,
  defaultBaseURL: process.env.OPENAI_BASE_URL, // unset = OpenAI
  maxConcurrency: 1, // run agents sequentially so output is readable
  onProgress: handleProgress,
})

const team = orchestrator.createTeam('api-team', {
  name: 'api-team',
  agents: [architect, developer, reviewer],
  sharedMemory: true,
  maxConcurrency: 1,
})

console.log(`Team "${team.name}" created with agents: ${team.getAgents().map(a => a.name).join(', ')}`)
console.log('\nStarting team run...\n')
console.log('='.repeat(60))

const goal = `Create a minimal Express.js REST API in ${OUTPUT_DIR}/ with:
- GET  /health       → { status: "ok" }
- GET  /users        → returns a hardcoded array of 2 user objects
- POST /users        → accepts { name, email } body, logs it, returns 201
- Proper error handling middleware
- The server should listen on port 3001
- Include a package.json with the required dependencies`

const result = await orchestrator.runTeam(team, goal)

console.log('\n' + '='.repeat(60))

// ---------------------------------------------------------------------------
// Results
// ---------------------------------------------------------------------------

console.log('\nTeam run complete.')
console.log(`Success: ${result.success}`)
console.log(`Total tokens — input: ${result.totalTokenUsage.input_tokens}, output: ${result.totalTokenUsage.output_tokens}`)

console.log('\nPer-agent results:')
for (const [agentName, agentResult] of result.agentResults) {
  const status = agentResult.success ? 'OK' : 'FAILED'
  const tools = agentResult.toolCalls.length
  console.log(`  ${agentName.padEnd(12)} [${status}]  tool_calls=${tools}`)
  if (!agentResult.success) {
    console.log(`    Error: ${agentResult.output.slice(0, 120)}`)
  }
}

// Print the developer's final output (the actual code) as a sample
const developerResult = result.agentResults.get('developer')
if (developerResult?.success) {
  console.log('\nDeveloper output (last 600 chars):')
  console.log('─'.repeat(60))
  const out = developerResult.output
  console.log(out.length > 600 ? '...' + out.slice(-600) : out)
  console.log('─'.repeat(60))
}

// Print the reviewer's findings
const reviewerResult = result.agentResults.get('reviewer')
if (reviewerResult?.success) {
  console.log('\nReviewer output:')
  console.log('─'.repeat(60))
  console.log(reviewerResult.output)
  console.log('─'.repeat(60))
}

multi-model-team.source:
/**
 * Multi-Model Team with Custom Tools
 *
 * Demonstrates:
 * - Mixing Anthropic and OpenAI models in the same team
 * - Defining custom tools with defineTool() and Zod schemas
 * - Building agents with a custom ToolRegistry so they can use custom tools
 * - Running a team goal that uses the custom tools
 *
 * Run:
 *   npx tsx packages/core/examples/basics/multi-model-team.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY and OPENAI_API_KEY env vars must be set.
 *   (If you only have one key, set useOpenAI = false below.)
 */

import { z } from 'zod'
import { OpenMultiAgent, defineTool } from '../../src/index.js'
import type { AgentConfig, OrchestratorEvent } from '../../src/types.js'

// ---------------------------------------------------------------------------
// Custom tools — defined with defineTool() + Zod schemas
// ---------------------------------------------------------------------------

/**
 * A custom tool that fetches live exchange rates from a public API.
 */
const exchangeRateTool = defineTool({
  name: 'get_exchange_rate',
  description:
    'Get the current exchange rate between two currencies. ' +
    'Returns the rate as a decimal: 1 unit of `from` = N units of `to`.',
  inputSchema: z.object({
    from: z.string().describe('ISO 4217 currency code, e.g. "USD"'),
    to: z.string().describe('ISO 4217 currency code, e.g. "EUR"'),
  }),
  execute: async ({ from, to }) => {
    try {
      const url = `https://api.exchangerate.host/convert?from=${from}&to=${to}&amount=1`
      const resp = await fetch(url, { signal: AbortSignal.timeout(5000) })

      if (!resp.ok) throw new Error(`HTTP ${resp.status}`)

      interface ExchangeRateResponse {
        result?: number
        info?: { rate?: number }
      }
      const json = (await resp.json()) as ExchangeRateResponse
      const rate: number | undefined = json?.result ?? json?.info?.rate

      if (typeof rate !== 'number') throw new Error('Unexpected API response shape')

      return {
        data: JSON.stringify({ from, to, rate, timestamp: new Date().toISOString() }),
        isError: false,
      }
    } catch (err) {
      // Graceful degradation — return a stubbed rate so the team can still proceed
      const stub = parseFloat((Math.random() * 0.5 + 0.8).toFixed(4))
      return {
        data: JSON.stringify({
          from,
          to,
          rate: stub,
          note: `Live fetch failed (${err instanceof Error ? err.message : String(err)}). Using stub rate.`,
        }),
        isError: false,
      }
    }
  },
})

/**
 * A custom tool that formats a number as a localised currency string.
 */
const formatCurrencyTool = defineTool({
  name: 'format_currency',
  description: 'Format a number as a localised currency string.',
  inputSchema: z.object({
    amount: z.number().describe('The numeric amount to format.'),
    currency: z.string().describe('ISO 4217 currency code, e.g. "USD".'),
    locale: z
      .string()
      .optional()
      .describe('BCP 47 locale string, e.g. "en-US". Defaults to "en-US".'),
  }),
  execute: async ({ amount, currency, locale = 'en-US' }) => {
    try {
      const formatted = new Intl.NumberFormat(locale, {
        style: 'currency',
        currency,
      }).format(amount)
      return { data: formatted, isError: false }
    } catch {
      return { data: `${amount} ${currency}`, isError: true }
    }
  },
})

// ---------------------------------------------------------------------------
// Helper: build an AgentConfig whose tools list includes custom tool names.
//
// Agents reference tools by name in their AgentConfig.tools array.
// The ToolRegistry is injected via the Agent constructor. When using OpenMultiAgent
// convenience methods (runTeam, runTasks, runAgent), the orchestrator builds
// agents internally using buildAgent(), which registers only the five built-in
// tools. For custom tools, use AgentPool + Agent directly (see the note in the
// README) or provide the custom tool names in the tools array and rely on a
// registry you inject yourself.
//
// In this example we demonstrate the custom-tool pattern by running the agents
// directly through AgentPool rather than through the OpenMultiAgent high-level API.
// ---------------------------------------------------------------------------

import { Agent, AgentPool, ToolRegistry, ToolExecutor, registerBuiltInTools } from '../../src/index.js'

/**
 * Build an Agent with both built-in and custom tools registered.
 */
function buildCustomAgent(
  config: AgentConfig,
  extraTools: ReturnType<typeof defineTool>[],
): Agent {
  const registry = new ToolRegistry()
  registerBuiltInTools(registry)
  for (const tool of extraTools) {
    registry.register(tool)
  }
  const executor = new ToolExecutor(registry)
  return new Agent(config, registry, executor)
}

// ---------------------------------------------------------------------------
// Agent definitions — mixed providers
// ---------------------------------------------------------------------------

const useOpenAI = Boolean(process.env.OPENAI_API_KEY)

const researcherConfig: AgentConfig = {
  name: 'researcher',
  model: 'claude-sonnet-4-6',
  provider: 'anthropic',
  systemPrompt: `You are a financial data researcher.
Use the get_exchange_rate tool to fetch current rates between the currency pairs you are given.
Return the raw rates as a JSON object keyed by pair, e.g. { "USD/EUR": 0.91, "USD/GBP": 0.79 }.`,
  tools: ['get_exchange_rate'],
  maxTurns: 6,
  temperature: 0,
}

const analystConfig: AgentConfig = {
  name: 'analyst',
  model: useOpenAI ? 'gpt-5.4' : 'claude-sonnet-4-6',
  provider: useOpenAI ? 'openai' : 'anthropic',
  systemPrompt: `You are a foreign exchange analyst.
You receive exchange rate data and produce a short briefing.
Use format_currency to show example conversions.
Keep the briefing under 200 words.`,
  tools: ['format_currency'],
  maxTurns: 4,
  temperature: 0.3,
}

// ---------------------------------------------------------------------------
// Build agents with custom tools
// ---------------------------------------------------------------------------

const researcher = buildCustomAgent(researcherConfig, [exchangeRateTool])
const analyst = buildCustomAgent(analystConfig, [formatCurrencyTool])

// ---------------------------------------------------------------------------
// Run with AgentPool for concurrency control
// ---------------------------------------------------------------------------

console.log('Multi-model team with custom tools')
console.log(`Providers: researcher=anthropic, analyst=${useOpenAI ? 'openai (gpt-5.4)' : 'anthropic (fallback)'}`)
console.log('Custom tools:', [exchangeRateTool.name, formatCurrencyTool.name].join(', '))
console.log()

const pool = new AgentPool(1) // sequential for readability
pool.add(researcher)
pool.add(analyst)

// Step 1: researcher fetches the rates
console.log('[1/2] Researcher fetching FX rates...')
const researchResult = await pool.run(
  'researcher',
  `Fetch exchange rates for these pairs using the get_exchange_rate tool:
- USD to EUR
- USD to GBP
- USD to JPY
- EUR to GBP

Return the results as a JSON object: { "USD/EUR": <rate>, "USD/GBP": <rate>, ... }`,
)

if (!researchResult.success) {
  console.error('Researcher failed:', researchResult.output)
  process.exit(1)
}

console.log('Researcher done. Tool calls made:', researchResult.toolCalls.map(c => c.toolName).join(', '))

// Step 2: analyst writes the briefing, receiving the researcher output as context
console.log('\n[2/2] Analyst writing FX briefing...')
const analystResult = await pool.run(
  'analyst',
  `Here are the current FX rates gathered by the research team:

${researchResult.output}

Using format_currency, show what $1,000 USD and €1,000 EUR convert to in each of the other currencies.
Then write a short FX market briefing (under 200 words) covering:
- Each rate with a brief observation
- The strongest and weakest currency in the set
- One-sentence market comment`,
)

if (!analystResult.success) {
  console.error('Analyst failed:', analystResult.output)
  process.exit(1)
}

console.log('Analyst done. Tool calls made:', analystResult.toolCalls.map(c => c.toolName).join(', '))

// ---------------------------------------------------------------------------
// Results
// ---------------------------------------------------------------------------

console.log('\n' + '='.repeat(60))

console.log('\nResearcher output:')
console.log(researchResult.output.slice(0, 400))

console.log('\nAnalyst briefing:')
console.log('─'.repeat(60))
console.log(analystResult.output)
console.log('─'.repeat(60))

const totalInput = researchResult.tokenUsage.input_tokens + analystResult.tokenUsage.input_tokens
const totalOutput = researchResult.tokenUsage.output_tokens + analystResult.tokenUsage.output_tokens
console.log(`\nTotal tokens — input: ${totalInput}, output: ${totalOutput}`)

// ---------------------------------------------------------------------------
// Bonus: show how defineTool() works in isolation (no LLM needed)
// ---------------------------------------------------------------------------

console.log('\n--- Bonus: testing custom tools in isolation ---\n')

const fmtResult = await formatCurrencyTool.execute(
  { amount: 1234.56, currency: 'EUR', locale: 'de-DE' },
  { agent: { name: 'test', role: 'test', model: 'test' } },
)
console.log(`format_currency(1234.56, EUR, de-DE) = ${fmtResult.data}`)

const rateResult = await exchangeRateTool.execute(
  { from: 'USD', to: 'EUR' },
  { agent: { name: 'test', role: 'test', model: 'test' } },
)
console.log(`get_exchange_rate(USD→EUR) = ${rateResult.data}`)

personalized-interview-simulator.source:
/**
 * Personalized Interview Simulator (Interviewer + Observer)
 *
 * Demonstrates:
 * - A stateful `interviewer` agent using `Agent.prompt()` across turns
 * - A stateless `observer` agent that reads full transcript context between turns
 * - Manual `SharedMemory` seeding and prompt injection outside `runTeam()` / `runTasks()`
 * - Human input handled at app level with `readline`
 * - Structured debrief via Zod at the end of the interview loop
 *
 * Run:
 *   npx tsx packages/core/examples/cookbook/personalized-interview-simulator.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY env var must be set.
 *
 * Optional:
 *   Set INTERVIEW_CANDIDATE_DIR to point at your own materials directory.
 *   Expected files:
 *   - resume.md
 *   - project-notes.md
 *   - code.ts
 *   - job-description.md
 */

import { readFileSync } from 'node:fs'
import path from 'node:path'
import { createInterface } from 'node:readline/promises'
import { stdin as input, stdout as output } from 'node:process'
import { fileURLToPath } from 'node:url'
import { z } from 'zod'
import { Agent, SharedMemory, ToolExecutor, ToolRegistry } from '../../src/index.js'
import type { AgentConfig } from '../../src/types.js'

// ---------------------------------------------------------------------------
// Candidate materials
// ---------------------------------------------------------------------------

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const DEFAULT_CANDIDATE_DIR = path.join(__dirname, '../fixtures/interview-candidate')
const CANDIDATE_DIR = process.env.INTERVIEW_CANDIDATE_DIR ?? DEFAULT_CANDIDATE_DIR
const MAX_TURNS = 10

function loadText(fileName: string): string {
  return readFileSync(path.join(CANDIDATE_DIR, fileName), 'utf-8').trim()
}

const resumeText = loadText('resume.md')
const projectNotes = loadText('project-notes.md')
const codeSnippet = loadText('code.ts')
const jobDescription = loadText('job-description.md')

// ---------------------------------------------------------------------------
// Structured debrief
// ---------------------------------------------------------------------------

const DebriefSchema = z.object({
  questions_asked: z.array(
    z.object({
      question: z.string(),
      why_it_mattered: z.string(),
    }),
  ),
  weak_spots: z.array(z.string()),
  strong_spots: z.array(z.string()),
  overall_assessment: z.object({
    recommendation: z.enum(['strong-hire', 'hire', 'lean-hire', 'lean-no-hire', 'no-hire']),
    summary: z.string(),
  }),
})
type Debrief = z.infer<typeof DebriefSchema>

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function buildAgent(config: AgentConfig): Agent {
  const registry = new ToolRegistry()
  const executor = new ToolExecutor(registry)
  return new Agent(config, registry, executor)
}

async function readlineFromCandidate(prompt: string, rl: ReturnType<typeof createInterface>): Promise<string> {
  console.log('\n' + '='.repeat(60))
  console.log('INTERVIEWER')
  console.log('='.repeat(60))
  console.log(prompt)
  console.log()

  const answer = await rl.question('Candidate > ')
  return answer.trim()
}

function isExitAnswer(answer: string): boolean {
  const normalized = answer.trim().toLowerCase()
  return normalized === 'exit' || normalized === 'quit'
}

// ---------------------------------------------------------------------------
// Agent configs
// ---------------------------------------------------------------------------

if (!process.env.ANTHROPIC_API_KEY) {
  console.log('[skip] This example needs ANTHROPIC_API_KEY.')
  process.exit(0)
}

const interviewerConfig: AgentConfig = {
  name: 'interviewer',
  provider: 'anthropic',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a senior technical interviewer.

You are running a personalized interview grounded in:
- the candidate's resume
- project notes
- a code sample
- the target job description
- observer flags written after each turn

Rules:
- Ask exactly one question per turn.
- Prefer probing follow-ups over switching topics too early.
- Use the role expectations and candidate materials together.
- If the observer flags a contradiction, vague answer, or missing dimension, use that.
- Keep each question concise but sharp.
- Do not answer your own question.
- Do not output analysis, just the next interview question.`,
  maxTurns: 2,
  temperature: 0.3,
}

const observerConfig: AgentConfig = {
  name: 'observer',
  provider: 'anthropic',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are an interview observer.

You will receive shared memory containing:
- candidate resume
- project notes
- code sample
- target job spec
- the full interview transcript so far

Write compact flags for the next interviewer turn.
Focus on:
- contradictions with candidate claims
- vague or incomplete answers
- important dimensions not yet tested
- specific follow-up hooks hidden in the answer

Output 3-6 short bullets. Be concrete. No prose introduction.`,
  maxTurns: 1,
  temperature: 0.2,
}

const reporterConfig: AgentConfig = {
  name: 'reporter',
  provider: 'anthropic',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are writing a compact interview debrief.

Use the complete interview record to produce:
- questions_asked: the most important questions and why each mattered
- weak_spots: concise bullets for weak areas
- strong_spots: concise bullets for strengths
- overall_assessment: recommendation plus a short summary

Return JSON only, matching the schema exactly.`,
  maxTurns: 2,
  temperature: 0.1,
  outputSchema: DebriefSchema,
}

// ---------------------------------------------------------------------------
// Seed memory
// ---------------------------------------------------------------------------

const mem = new SharedMemory()

await mem.write('candidate', 'resume', resumeText)
await mem.write('candidate', 'project-notes', projectNotes)
await mem.write('candidate', 'code', codeSnippet)
await mem.write('role', 'target-job-spec', jobDescription)

const interviewer = buildAgent(interviewerConfig)
const observer = buildAgent(observerConfig)
const reporter = buildAgent(reporterConfig)

const rl = createInterface({ input, output })

console.log('Personalized Interview Simulator')
console.log('='.repeat(60))
console.log(`Candidate materials: ${CANDIDATE_DIR}`)
console.log('Type "exit" or "quit" to stop early.')
console.log()

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------

let answer = ''
let turnsCompleted = 0

try {
  for (let turn = 0; turn < MAX_TURNS; turn++) {
    const ctx = await mem.getSummary()
    const result = await interviewer.prompt(
      turn === 0
        ? [
            `Context:\n${ctx}`,
            'Ask the most probing opening question you can justify from the materials and role.',
          ].join('\n\n')
        : [
            `Context:\n${ctx}`,
            `Candidate answer:\n${answer}`,
            'Ask the next question.',
          ].join('\n\n'),
    )

    if (!result.success) {
      console.error('Interviewer failed:', result.output)
      process.exit(1)
    }

    answer = await readlineFromCandidate(result.output, rl)
    if (isExitAnswer(answer)) {
      console.log('\nInterview stopped by candidate.')
      break
    }

    turnsCompleted++
    await mem.write('interviewer', `turn-${turn}`, `Q: ${result.output}\nA: ${answer}`)

    const observerResult = await observer.run(
      [
        'Review transcript and candidate materials. Write flags for the next turn.',
        await mem.getSummary(),
      ].join('\n\n'),
    )

    if (!observerResult.success) {
      console.error('Observer failed:', observerResult.output)
      process.exit(1)
    }

    await mem.write('observer', 'flags', observerResult.output)
  }
} finally {
  rl.close()
}

// ---------------------------------------------------------------------------
// Structured debrief
// ---------------------------------------------------------------------------

console.log('\n' + '='.repeat(60))
console.log('DEBRIEF')
console.log('='.repeat(60))

const debriefResult = await reporter.run(`Summarize the full interview:\n\n${await mem.getSummary()}`)

if (!debriefResult.success || !debriefResult.structured) {
  console.error('Debrief generation failed:', debriefResult.output)
  process.exit(1)
}

const debrief = debriefResult.structured as Debrief

console.log(JSON.stringify(debrief, null, 2))
console.log()
console.log(`Turns completed: ${turnsCompleted}`)
console.log('Done.')

task-retry.source:
/**
 * Task Retry with Exponential Backoff
 *
 * Demonstrates `maxRetries`, `retryDelayMs`, and `retryBackoff` on task config.
 * When a task fails, the framework automatically retries with exponential
 * backoff. The `onProgress` callback receives `task_retry` events so you can
 * log retry attempts in real time.
 *
 * Scenario: a two-step pipeline where the first task (data fetch) is configured
 * to retry on failure, and the second task (analysis) depends on it.
 *
 * Run:
 *   npx tsx packages/core/examples/patterns/task-retry.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY env var must be set.
 */

import { OpenMultiAgent } from '../../src/index.js'
import type { AgentConfig, OrchestratorEvent } from '../../src/types.js'

// ---------------------------------------------------------------------------
// Agents
// ---------------------------------------------------------------------------

const fetcher: AgentConfig = {
  name: 'fetcher',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a data-fetching agent. When given a topic, produce a short
JSON summary with 3-5 key facts. Output ONLY valid JSON, no markdown fences.
Example: {"topic":"...", "facts":["fact1","fact2","fact3"]}`,
  maxTurns: 2,
}

const analyst: AgentConfig = {
  name: 'analyst',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a data analyst. Read the fetched data from shared memory
and produce a brief analysis (3-4 sentences) highlighting trends or insights.`,
  maxTurns: 2,
}

// ---------------------------------------------------------------------------
// Progress handler — watch for task_retry events
// ---------------------------------------------------------------------------

function handleProgress(event: OrchestratorEvent): void {
  const ts = new Date().toISOString().slice(11, 23)

  switch (event.type) {
    case 'task_start':
      console.log(`[${ts}] TASK START    "${event.task}" (agent: ${event.agent})`)
      break
    case 'task_complete':
      console.log(`[${ts}] TASK DONE     "${event.task}"`)
      break
    case 'task_retry': {
      const d = event.data as { attempt: number; maxAttempts: number; error: string; nextDelayMs: number }
      console.log(`[${ts}] TASK RETRY    "${event.task}" — attempt ${d.attempt}/${d.maxAttempts}, next in ${d.nextDelayMs}ms`)
      console.log(`               error: ${d.error.slice(0, 120)}`)
      break
    }
    case 'error':
      console.log(`[${ts}] ERROR         "${event.task}" agent=${event.agent}`)
      break
  }
}

// ---------------------------------------------------------------------------
// Orchestrator + team
// ---------------------------------------------------------------------------

const orchestrator = new OpenMultiAgent({
  defaultModel: 'claude-sonnet-4-6',
  onProgress: handleProgress,
})

const team = orchestrator.createTeam('retry-demo', {
  name: 'retry-demo',
  agents: [fetcher, analyst],
  sharedMemory: true,
})

// ---------------------------------------------------------------------------
// Tasks — fetcher has retry config, analyst depends on it
// ---------------------------------------------------------------------------

const tasks = [
  {
    title: 'Fetch data',
    description: 'Fetch key facts about the adoption of TypeScript in open-source projects as of 2024. Output a JSON object with a "topic" and "facts" array.',
    assignee: 'fetcher',
    // Retry config: up to 2 retries, 500ms base delay, 2x backoff (500ms, 1000ms)
    maxRetries: 2,
    retryDelayMs: 500,
    retryBackoff: 2,
  },
  {
    title: 'Analyze data',
    description: 'Read the fetched data from shared memory and produce a 3-4 sentence analysis of TypeScript adoption trends.',
    assignee: 'analyst',
    dependsOn: ['Fetch data'],
    // No retry — if analysis fails, just report the error
  },
]

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------

console.log('Task Retry Example')
console.log('='.repeat(60))
console.log('Pipeline: fetch (with retry) → analyze')
console.log(`Retry config: maxRetries=2, delay=500ms, backoff=2x`)
console.log('='.repeat(60))
console.log()

const result = await orchestrator.runTasks(team, tasks)

// ---------------------------------------------------------------------------
// Summary
// ---------------------------------------------------------------------------

console.log('\n' + '='.repeat(60))
console.log(`Overall success: ${result.success}`)
console.log(`Tokens — input: ${result.totalTokenUsage.input_tokens}, output: ${result.totalTokenUsage.output_tokens}`)

for (const [name, r] of result.agentResults) {
  const icon = r.success ? 'OK  ' : 'FAIL'
  console.log(`  [${icon}] ${name}`)
  console.log(`         ${r.output.slice(0, 200)}`)
}

research-aggregation.source:
/**
 * Multi-Source Research Aggregation
 *
 * Demonstrates runTasks() with explicit dependency chains:
 * - Parallel execution: three analyst agents research the same topic independently
 * - Dependency chain via dependsOn: synthesizer waits for all analysts to finish
 * - Automatic shared memory: agent output flows to downstream agents via the framework
 *
 * Compare with example 07 (fan-out-aggregate) which uses AgentPool.runParallel()
 * for the same 3-analysts + synthesizer pattern. This example shows the runTasks()
 * API with explicit dependsOn declarations instead.
 *
 * Flow:
 *   [technical-analyst, market-analyst, community-analyst] (parallel) → synthesizer
 *
 * Run:
 *   npx tsx packages/core/examples/patterns/research-aggregation.ts "<topic>"
 *
 * Provider selection (env):
 *   - LLM_PROVIDER=anthropic   (default)  → requires ANTHROPIC_API_KEY
 *   - LLM_PROVIDER=gemini                 → requires GEMINI_API_KEY (+ optional peer dep @google/genai)
 *   - LLM_PROVIDER=groq                   → requires GROQ_API_KEY
 *   - LLM_PROVIDER=openrouter             → requires OPENROUTER_API_KEY
 *
 * Optional:
 *   - LLM_MODEL=... overrides the default model for the selected provider.
 */

import { z } from 'zod'
import { OpenMultiAgent } from '../../src/index.js'
import type { AgentConfig, OrchestratorEvent } from '../../src/types.js'

// ---------------------------------------------------------------------------
// Topic + provider selection
// ---------------------------------------------------------------------------

const TOPIC = process.argv[2] ?? 'WebAssembly adoption in 2026'

type ProviderChoice = 'anthropic' | 'gemini' | 'groq' | 'openrouter'

function resolveProvider(): {
  label: ProviderChoice
  model: string
  provider: NonNullable<AgentConfig['provider']>
  baseURL?: string
  apiKey?: string
} {
  const raw = (process.env.LLM_PROVIDER ?? 'anthropic').toLowerCase() as ProviderChoice
  const modelOverride = process.env.LLM_MODEL

  switch (raw) {
    case 'gemini':
      return { label: 'gemini', provider: 'gemini', model: modelOverride ?? 'gemini-2.5-flash' }
    case 'groq':
      return {
        label: 'groq',
        provider: 'openai',
        baseURL: 'https://api.groq.com/openai/v1',
        apiKey: process.env.GROQ_API_KEY,
        model: modelOverride ?? 'llama-3.3-70b-versatile',
      }
    case 'openrouter':
      return {
        label: 'openrouter',
        provider: 'openai',
        baseURL: 'https://openrouter.ai/api/v1',
        apiKey: process.env.OPENROUTER_API_KEY,
        model: modelOverride ?? 'openai/gpt-4o-mini',
      }
    case 'anthropic':
    default:
      return { label: 'anthropic', provider: 'anthropic', model: modelOverride ?? 'claude-sonnet-4-6' }
  }
}

const PROVIDER = resolveProvider()
if (PROVIDER.label === 'groq' && !PROVIDER.apiKey) {
  throw new Error('LLM_PROVIDER=groq requires GROQ_API_KEY')
}
if (PROVIDER.label === 'openrouter' && !PROVIDER.apiKey) {
  throw new Error('LLM_PROVIDER=openrouter requires OPENROUTER_API_KEY')
}

// ---------------------------------------------------------------------------
// Output schema (synthesizer)
// ---------------------------------------------------------------------------

const FindingSchema = z.object({
  title: z.string().describe('One-sentence finding'),
  detail: z.string().describe('2-4 sentence explanation'),
  analysts: z.array(z.enum(['technical-analyst', 'market-analyst', 'community-analyst']))
    .min(1)
    .describe('Analyst agent names that support this finding'),
  confidence: z.number().min(0).max(1).describe('0..1 confidence score'),
})

const ContradictionSchema = z.object({
  claim_a: z.string().describe('Claim from analyst A (quote or tight paraphrase)'),
  claim_b: z.string().describe('Contradicting claim from analyst B (quote or tight paraphrase)'),
  analysts: z.tuple([
    z.enum(['technical-analyst', 'market-analyst', 'community-analyst']),
    z.enum(['technical-analyst', 'market-analyst', 'community-analyst']),
  ])
    .describe('Exactly two analyst agent names (must be different)'),
}).refine((x) => x.analysts[0] !== x.analysts[1], {
  message: 'contradictions.analysts must reference two different analysts',
  path: ['analysts'],
})

const ResearchAggregationSchema = z.object({
  summary: z.string().describe('High-level executive summary'),
  findings: z.array(FindingSchema).describe('Key findings extracted from the analyst reports'),
  contradictions: z.array(ContradictionSchema).describe('Explicit contradictions (may be empty)'),
})

// ---------------------------------------------------------------------------
// Agents — three analysts + one synthesizer
// ---------------------------------------------------------------------------

const technicalAnalyst: AgentConfig = {
  name: 'technical-analyst',
  model: PROVIDER.model,
  systemPrompt: `You are a technical analyst.

Task: Given a topic, produce a compact report that is easy to cross-reference.
Output markdown with EXACT sections:

## Claims (max 6 bullets)
Each bullet is one falsifiable technical claim.

## Evidence (max 4 bullets)
Concrete examples, benchmarks, or implementation details.

Constraints: <= 160 words total. No filler.`,
  maxTurns: 1,
}

const marketAnalyst: AgentConfig = {
  name: 'market-analyst',
  model: PROVIDER.model,
  systemPrompt: `You are a market analyst.

Output markdown with EXACT sections:

## Claims (max 6 bullets)
Adoption, players, market dynamics.

## Evidence (max 4 bullets)
Metrics, segments, named companies, or directional estimates.

Constraints: <= 160 words total. No filler.`,
  maxTurns: 1,
}

const communityAnalyst: AgentConfig = {
  name: 'community-analyst',
  model: PROVIDER.model,
  systemPrompt: `You are a developer community analyst.

Output markdown with EXACT sections:

## Claims (max 6 bullets)
Sentiment, ecosystem maturity, learning curve, community signals.

## Evidence (max 4 bullets)
Tooling, docs, conferences, repos, surveys.

Constraints: <= 160 words total. No filler.`,
  maxTurns: 1,
}

const synthesizer: AgentConfig = {
  name: 'synthesizer',
  model: PROVIDER.model,
  outputSchema: ResearchAggregationSchema,
  systemPrompt: `You are a research director. You will receive three analyst reports.

Your job: produce ONLY a JSON object matching the required schema.

Rules:
1. Extract 3-6 findings. Each finding MUST list the analyst names that support it.
2. Extract contradictions as explicit pairs of claims. Each contradiction MUST:
   - include claim_a and claim_b copied VERBATIM from the analysts' "## Claims" bullets
   - include analysts as a 2-item array with the two analyst names
3. contradictions MUST be an array (may be empty).
4. No markdown, no code fences, no extra text. JSON only.`,
  maxTurns: 2,
}

// ---------------------------------------------------------------------------
// Orchestrator + team
// ---------------------------------------------------------------------------

function handleProgress(event: OrchestratorEvent): void {
  if (event.type === 'task_start') {
    console.log(`  [START] ${event.task ?? ''} → ${event.agent ?? ''}`)
  }
  if (event.type === 'task_complete') {
    console.log(`  [DONE]  ${event.task ?? ''}`)
  }
}

const orchestrator = new OpenMultiAgent({
  defaultModel: PROVIDER.model,
  defaultProvider: PROVIDER.provider,
  ...(PROVIDER.baseURL ? { defaultBaseURL: PROVIDER.baseURL } : {}),
  ...(PROVIDER.apiKey ? { defaultApiKey: PROVIDER.apiKey } : {}),
  onProgress: handleProgress,
})

const team = orchestrator.createTeam('research-team', {
  name: 'research-team',
  agents: [technicalAnalyst, marketAnalyst, communityAnalyst, synthesizer],
  sharedMemory: true,
})

// ---------------------------------------------------------------------------
// Tasks — three analysts run in parallel, synthesizer depends on all three
// ---------------------------------------------------------------------------

const tasks = [
  {
    title: 'Technical analysis',
    description: `Research the technical aspects of ${TOPIC}. Focus on capabilities, limitations, performance, and architecture.`,
    assignee: 'technical-analyst',
  },
  {
    title: 'Market analysis',
    description: `Research the market landscape for ${TOPIC}. Focus on adoption rates, key players, market size, and competition.`,
    assignee: 'market-analyst',
  },
  {
    title: 'Community analysis',
    description: `Research the developer community around ${TOPIC}. Focus on sentiment, ecosystem maturity, learning resources, and community activity.`,
    assignee: 'community-analyst',
  },
  {
    title: 'Synthesize report',
    description: `Cross-reference all analyst findings, identify key insights, flag contradictions, and produce a unified research report.`,
    assignee: 'synthesizer',
    dependsOn: ['Technical analysis', 'Market analysis', 'Community analysis'],
  },
]

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------

console.log('Multi-Source Research Aggregation')
console.log('='.repeat(60))
console.log(`Topic: ${TOPIC}`)
console.log(`Provider: ${PROVIDER.label} (model=${PROVIDER.model})`)
console.log('Pipeline: 3 analysts (parallel) → synthesizer')
console.log('='.repeat(60))
console.log()

const result = await orchestrator.runTasks(team, tasks)

// ---------------------------------------------------------------------------
// Parallelism assertion (analysts should benefit from concurrency)
// ---------------------------------------------------------------------------

const analystTitles = new Set(['Technical analysis', 'Market analysis', 'Community analysis'])
const analystTasks = (result.tasks ?? []).filter((t) => analystTitles.has(t.title))

if (
  analystTasks.length === 3
  && analystTasks.every((t) => t.metrics?.startMs !== undefined && t.metrics?.endMs !== undefined)
) {
  const durations = analystTasks.map((t) => Math.max(0, (t.metrics!.endMs - t.metrics!.startMs)))
  const serialSum = durations.reduce((a, b) => a + b, 0)
  const minStart = Math.min(...analystTasks.map((t) => t.metrics!.startMs))
  const maxEnd = Math.max(...analystTasks.map((t) => t.metrics!.endMs))
  const parallelWall = Math.max(0, maxEnd - minStart)

  // Require parallel wall time < 70% of the serial sum.
  if (serialSum > 0 && parallelWall >= 0.7 * serialSum) {
    throw new Error(
      `Parallelism assertion failed: parallelWall=${parallelWall}ms, serialSum=${serialSum}ms (need < 0.7x). ` +
      `Tighten analyst prompts or increase concurrency.`,
    )
  }
}

// ---------------------------------------------------------------------------
// Output
// ---------------------------------------------------------------------------

console.log('\n' + '='.repeat(60))
console.log(`Overall success: ${result.success}`)
console.log(`Tokens — input: ${result.totalTokenUsage.input_tokens}, output: ${result.totalTokenUsage.output_tokens}`)
console.log()

for (const [name, r] of result.agentResults) {
  const icon = r.success ? 'OK  ' : 'FAIL'
  const tokens = `in:${r.tokenUsage.input_tokens} out:${r.tokenUsage.output_tokens}`
  console.log(`  [${icon}] ${name.padEnd(20)} ${tokens}`)
}

const synthResult = result.agentResults.get('synthesizer')
if (synthResult?.success) {
  console.log('\n' + '='.repeat(60))
  console.log('SYNTHESIZED OUTPUT (JSON)')
  console.log('='.repeat(60))
  console.log()

  if (synthResult.structured) {
    console.log(JSON.stringify(synthResult.structured, null, 2))
  } else {
    // Should not happen when outputSchema succeeds, but keep a fallback.
    console.log(synthResult.output)
  }
}

console.log('\nDone.')

fan-out-aggregate.source:
/**
 * Fan-Out / Aggregate (MapReduce) Pattern
 *
 * Demonstrates:
 * - Fan-out: send the same question to N "analyst" agents in parallel
 * - Aggregate: a "synthesizer" agent reads all analyst outputs and produces
 *   a balanced final report
 * - AgentPool with runParallel() for concurrent fan-out
 * - No tools needed — pure LLM reasoning to keep the focus on the pattern
 *
 * Run:
 *   npx tsx packages/core/examples/patterns/fan-out-aggregate.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY env var must be set.
 */

import { Agent, AgentPool, ToolRegistry, ToolExecutor, registerBuiltInTools } from '../../src/index.js'
import type { AgentConfig, AgentRunResult } from '../../src/types.js'

// ---------------------------------------------------------------------------
// Analysis topic
// ---------------------------------------------------------------------------

const TOPIC = `Should a solo developer build a SaaS product that uses AI agents
for automated customer support? Consider the current state of AI technology,
market demand, competition, costs, and the unique constraints of being a solo
founder with limited time (~6 hours/day of productive work).`

// ---------------------------------------------------------------------------
// Analyst agent configs — three perspectives on the same question
// ---------------------------------------------------------------------------

const optimistConfig: AgentConfig = {
  name: 'optimist',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are an optimistic technology analyst who focuses on
opportunities, upside potential, and emerging trends. You see possibilities
where others see obstacles. Back your optimism with concrete reasoning —
cite market trends, cost curves, and real capabilities. Keep your analysis
to 200-300 words.`,
  maxTurns: 1,
  temperature: 0.4,
}

const skepticConfig: AgentConfig = {
  name: 'skeptic',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a skeptical technology analyst who focuses on risks,
challenges, failure modes, and hidden costs. You stress-test assumptions and
ask "what could go wrong?" Back your skepticism with concrete reasoning —
cite failure rates, technical limitations, and market realities. Keep your
analysis to 200-300 words.`,
  maxTurns: 1,
  temperature: 0.4,
}

const pragmatistConfig: AgentConfig = {
  name: 'pragmatist',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a pragmatic technology analyst who focuses on practical
feasibility, execution complexity, and resource requirements. You care about
what works today, not what might work someday. You think in terms of MVPs,
timelines, and concrete tradeoffs. Keep your analysis to 200-300 words.`,
  maxTurns: 1,
  temperature: 0.4,
}

const synthesizerConfig: AgentConfig = {
  name: 'synthesizer',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a senior strategy advisor who synthesizes multiple
perspectives into a balanced, actionable recommendation. You do not simply
summarise — you weigh the arguments, identify where they agree and disagree,
and produce a clear verdict with next steps. Structure your output as:

1. Key agreements across perspectives
2. Key disagreements and how you weigh them
3. Verdict (go / no-go / conditional go)
4. Recommended next steps (3-5 bullet points)

Keep the final report to 300-400 words.`,
  maxTurns: 1,
  temperature: 0.3,
}

// ---------------------------------------------------------------------------
// Build agents — no tools needed for pure reasoning
// ---------------------------------------------------------------------------

function buildAgent(config: AgentConfig): Agent {
  const registry = new ToolRegistry()
  registerBuiltInTools(registry) // available to grant, but these agents grant none (tools are opt-in) — pure reasoning
  const executor = new ToolExecutor(registry)
  return new Agent(config, registry, executor)
}

const optimist = buildAgent(optimistConfig)
const skeptic = buildAgent(skepticConfig)
const pragmatist = buildAgent(pragmatistConfig)
const synthesizer = buildAgent(synthesizerConfig)

// ---------------------------------------------------------------------------
// Set up the pool
// ---------------------------------------------------------------------------

const pool = new AgentPool(3) // 3 analysts can run simultaneously
pool.add(optimist)
pool.add(skeptic)
pool.add(pragmatist)
pool.add(synthesizer)

console.log('Fan-Out / Aggregate (MapReduce) Pattern')
console.log('='.repeat(60))
console.log(`\nTopic: ${TOPIC.replace(/\n/g, ' ').trim()}\n`)

// ---------------------------------------------------------------------------
// Step 1: Fan-out — run all 3 analysts in parallel
// ---------------------------------------------------------------------------

console.log('[Step 1] Fan-out: 3 analysts running in parallel...\n')

const analystResults: Map<string, AgentRunResult> = await pool.runParallel([
  { agent: 'optimist',   prompt: TOPIC },
  { agent: 'skeptic',    prompt: TOPIC },
  { agent: 'pragmatist', prompt: TOPIC },
])

// Print each analyst's output (truncated)
const analysts = ['optimist', 'skeptic', 'pragmatist'] as const
for (const name of analysts) {
  const result = analystResults.get(name)!
  const status = result.success ? 'OK' : 'FAILED'
  console.log(`  ${name} [${status}] — ${result.tokenUsage.output_tokens} output tokens`)
  console.log(`  ${result.output.slice(0, 150).replace(/\n/g, ' ')}...`)
  console.log()
}

// Check all analysts succeeded
for (const name of analysts) {
  if (!analystResults.get(name)!.success) {
    console.error(`Analyst '${name}' failed: ${analystResults.get(name)!.output}`)
    process.exit(1)
  }
}

// ---------------------------------------------------------------------------
// Step 2: Aggregate — synthesizer reads all 3 analyses
// ---------------------------------------------------------------------------

console.log('[Step 2] Aggregate: synthesizer producing final report...\n')

const synthesizerPrompt = `Three analysts have independently evaluated the same question.
Read their analyses below and produce your synthesis report.

--- OPTIMIST ---
${analystResults.get('optimist')!.output}

--- SKEPTIC ---
${analystResults.get('skeptic')!.output}

--- PRAGMATIST ---
${analystResults.get('pragmatist')!.output}

Now synthesize these three perspectives into a balanced recommendation.`

const synthResult = await pool.run('synthesizer', synthesizerPrompt)

if (!synthResult.success) {
  console.error('Synthesizer failed:', synthResult.output)
  process.exit(1)
}

// ---------------------------------------------------------------------------
// Final output
// ---------------------------------------------------------------------------

console.log('='.repeat(60))
console.log('SYNTHESIZED REPORT')
console.log('='.repeat(60))
console.log()
console.log(synthResult.output)
console.log()
console.log('-'.repeat(60))

// ---------------------------------------------------------------------------
// Token usage comparison
// ---------------------------------------------------------------------------

console.log('\nToken Usage Summary:')
console.log('-'.repeat(60))

let totalInput = 0
let totalOutput = 0

for (const name of analysts) {
  const r = analystResults.get(name)!
  totalInput += r.tokenUsage.input_tokens
  totalOutput += r.tokenUsage.output_tokens
  console.log(`  ${name.padEnd(12)} — input: ${r.tokenUsage.input_tokens}, output: ${r.tokenUsage.output_tokens}`)
}

totalInput += synthResult.tokenUsage.input_tokens
totalOutput += synthResult.tokenUsage.output_tokens
console.log(`  ${'synthesizer'.padEnd(12)} — input: ${synthResult.tokenUsage.input_tokens}, output: ${synthResult.tokenUsage.output_tokens}`)
console.log('-'.repeat(60))
console.log(`  ${'TOTAL'.padEnd(12)} — input: ${totalInput}, output: ${totalOutput}`)

console.log('\nDone.')

translation-backtranslation.source:
/**
 * Translation + Backtranslation Quality Check (Cross-Model)
 *
 * Demonstrates:
 * - Agent A: translate EN -> target language with Claude
 * - Agent B: back-translate -> EN with a different provider family
 * - Agent C: compare original vs. backtranslation and flag semantic drift
 * - Structured output with Zod schemas
 *
 * Run:
 *   npx tsx packages/core/examples/cookbook/translation-backtranslation.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY must be set
 *   and at least one of OPENAI_API_KEY / GEMINI_API_KEY must be set
 */

import { z } from 'zod'
import {
  Agent,
  AgentPool,
  ToolRegistry,
  ToolExecutor,
  registerBuiltInTools,
} from '../../src/index.js'
import type { AgentConfig } from '../../src/types.js'

// ---------------------------------------------------------------------------
// Inline sample text (3-5 technical paragraphs, per issue requirement)
// ---------------------------------------------------------------------------

const SAMPLE_TEXT = `
Modern CI/CD pipelines rely on deterministic builds and reproducible environments.
A deployment may fail even when the application code is correct if the runtime,
dependency graph, or container image differs from what engineers tested locally.

Observability should combine logs, metrics, and traces rather than treating them
as separate debugging tools. Metrics show that something is wrong, logs provide
local detail, and traces explain how a request moved across services.

Schema validation is especially important in LLM systems. A response may sound
reasonable to a human reader but still break automation if the JSON structure,
field names, or enum values do not match the downstream contract.

Cross-model verification can reduce self-confirmation bias. When one model
produces a translation and a different provider family performs the
backtranslation, semantic drift becomes easier to detect.
`.trim()

// ---------------------------------------------------------------------------
// Zod schemas
// ---------------------------------------------------------------------------

const ParagraphInput = z.object({
  index: z.number().int().positive(),
  original: z.string(),
})
type ParagraphInput = z.infer<typeof ParagraphInput>

const TranslationBatch = z.object({
  target_language: z.string(),
  items: z.array(
    z.object({
      index: z.number().int().positive(),
      translation: z.string(),
    }),
  ),
})
type TranslationBatch = z.infer<typeof TranslationBatch>

const BacktranslationBatch = z.object({
  items: z.array(
    z.object({
      index: z.number().int().positive(),
      backtranslation: z.string(),
    }),
  ),
})
type BacktranslationBatch = z.infer<typeof BacktranslationBatch>

const DriftRow = z.object({
  original: z.string(),
  translation: z.string(),
  backtranslation: z.string(),
  drift_severity: z.enum(['none', 'minor', 'major']),
  notes: z.string(),
})
type DriftRow = z.infer<typeof DriftRow>

const DriftTable = z.array(DriftRow)
type DriftTable = z.infer<typeof DriftTable>

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function buildAgent(config: AgentConfig): Agent {
  const registry = new ToolRegistry()
  registerBuiltInTools(registry)
  const executor = new ToolExecutor(registry)
  return new Agent(config, registry, executor)
}

function splitParagraphs(text: string): ParagraphInput[] {
  return text
    .split(/\n\s*\n/)
    .map((p, i) => ({
      index: i + 1,
      original: p.trim(),
    }))
    .filter((p) => p.original.length > 0)
}

// ---------------------------------------------------------------------------
// Provider selection
// ---------------------------------------------------------------------------

const hasAnthropic = Boolean(process.env.ANTHROPIC_API_KEY)
const hasOpenAI = Boolean(process.env.OPENAI_API_KEY)
const hasGemini = Boolean(process.env.GEMINI_API_KEY)

if (!hasAnthropic || (!hasGemini && !hasOpenAI)) {
  console.log(
    '[skip] This example needs ANTHROPIC_API_KEY plus GEMINI_API_KEY or OPENAI_API_KEY.',
  )
  process.exit(0)
}

// Prefer native Gemini when GEMINI_API_KEY is available.
// Fall back to OpenAI otherwise.
const backProvider: 'gemini' | 'openai' = hasGemini ? 'gemini' : 'openai'

const backModel =
  backProvider === 'gemini'
    ? 'gemini-2.5-pro'
    : (process.env.OPENAI_MODEL || 'gpt-5.4')

// ---------------------------------------------------------------------------
// Agent configs
// ---------------------------------------------------------------------------

// Agent A ---------------------------------------------------------------
// 用 Claude 做 “英文 -> 目标语言” 翻译
const translatorConfig: AgentConfig = {
  name: 'translator',
  provider: 'anthropic',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are Agent A, a technical translator.

Translate English paragraphs into Simplified Chinese.
Preserve meaning, terminology, paragraph boundaries, and index numbers.
Do not merge paragraphs.
Return JSON only, matching the schema exactly.`,
  maxTurns: 1,
  temperature: 0,
  outputSchema: TranslationBatch,
}

// Agent B ---------------------------------------------------------------
// 用不同 provider 家族做 “目标语言 -> 英文” 回译
const backtranslatorConfig: AgentConfig = {
  name: 'backtranslator',
  provider: backProvider,
  model: backModel,
  baseURL: backProvider === 'openai' ? process.env.OPENAI_BASE_URL : undefined,
  systemPrompt: `You are Agent B, a back-translation specialist.

Back-translate the provided Simplified Chinese paragraphs into English.
Preserve meaning as literally as possible.
Do not merge paragraphs.
Keep the same index numbers.
Return JSON only, matching the schema exactly.`,
  maxTurns: 1,
  temperature: 0,
  outputSchema: BacktranslationBatch,
}
// Agent C ---------------------------------------------------------------
// 比较原文和回译文，判断语义漂移
const reviewerConfig: AgentConfig = {
  name: 'reviewer',
  provider: 'anthropic',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are Agent C, a semantic drift reviewer.

You will receive:
- the original English paragraph
- the translated paragraph
- the backtranslated English paragraph

For each paragraph, judge drift_severity using only:
- none: meaning preserved
- minor: slight wording drift, but no important meaning change
- major: material semantic change, omission, contradiction, or mistranslation

Return JSON only.
The final output must be an array where each item contains:
original, translation, backtranslation, drift_severity, notes.`,
  maxTurns: 1,
  temperature: 0,
  outputSchema: DriftTable,
}

// ---------------------------------------------------------------------------
// Build agents
// ---------------------------------------------------------------------------

const translator = buildAgent(translatorConfig)
const backtranslator = buildAgent(backtranslatorConfig)
const reviewer = buildAgent(reviewerConfig)

const pool = new AgentPool(1)
pool.add(translator)
pool.add(backtranslator)
pool.add(reviewer)

// ---------------------------------------------------------------------------
// Run pipeline
// ---------------------------------------------------------------------------

const paragraphs = splitParagraphs(SAMPLE_TEXT)

console.log('Translation + Backtranslation Quality Check')
console.log('='.repeat(60))
console.log(`Paragraphs: ${paragraphs.length}`)
console.log(`Translator provider: anthropic (claude-sonnet-4-6)`)
console.log(`Backtranslator provider: ${backProvider} (${backModel})`)
console.log()

// Step 1: Agent A translates
console.log('[1/3] Agent A translating EN -> zh-CN...\n')

const translationPrompt = `Target language: Simplified Chinese

Translate the following paragraphs.
Return exactly one translated item per paragraph.

Input:
${JSON.stringify(paragraphs, null, 2)}`
const translationResult = await pool.run('translator', translationPrompt)

if (!translationResult.success || !translationResult.structured) {
  console.error('Agent A failed:', translationResult.output)
  process.exit(1)
}

const translated = translationResult.structured as TranslationBatch

// Step 2: Agent B back-translates
console.log('[2/3] Agent B back-translating zh-CN -> EN...\n')

const backtranslationPrompt = `Back-translate the following paragraphs into English.
Keep the same indexes.

Input:
${JSON.stringify(translated.items, null, 2)}`
const backtranslationResult = await pool.run('backtranslator', backtranslationPrompt)

if (!backtranslationResult.success || !backtranslationResult.structured) {
  console.error('Agent B failed:', backtranslationResult.output)
  process.exit(1)
}

const backtranslated = backtranslationResult.structured as BacktranslationBatch

// Step 3: Agent C reviews semantic drift
console.log('[3/3] Agent C reviewing semantic drift...\n')

const mergedInput = paragraphs.map((p) => ({
  index: p.index,
  original: p.original,
  translation: translated.items.find((x) => x.index === p.index)?.translation ?? '',
  backtranslation:
    backtranslated.items.find((x) => x.index === p.index)?.backtranslation ?? '',
}))

const reviewPrompt = `Compare the original English against the backtranslated English.

Important:
- Evaluate semantic drift paragraph by paragraph
- Do not judge style differences as major unless meaning changed
- Return only the final JSON array

Input:
${JSON.stringify(mergedInput, null, 2)}`
const reviewResult = await pool.run('reviewer', reviewPrompt)

if (!reviewResult.success || !reviewResult.structured) {
  console.error('Agent C failed:', reviewResult.output)
  process.exit(1)
}

const driftTable = reviewResult.structured as DriftTable

// ---------------------------------------------------------------------------
// Final output
// ---------------------------------------------------------------------------

console.log('='.repeat(60))
console.log('FINAL DRIFT TABLE')
console.log('='.repeat(60))
console.log(JSON.stringify(driftTable, null, 2))
console.log()

console.log('Token Usage Summary')
console.log('-'.repeat(60))
console.log(
  `Agent A (translator)    — input: ${translationResult.tokenUsage.input_tokens}, output: ${translationResult.tokenUsage.output_tokens}`,
)
console.log(
  `Agent B (backtranslator) — input: ${backtranslationResult.tokenUsage.input_tokens}, output: ${backtranslationResult.tokenUsage.output_tokens}`,
)
console.log(
  `Agent C (reviewer)      — input: ${reviewResult.tokenUsage.input_tokens}, output: ${reviewResult.tokenUsage.output_tokens}`,
)

const totalInput =
  translationResult.tokenUsage.input_tokens +
  backtranslationResult.tokenUsage.input_tokens +
  reviewResult.tokenUsage.input_tokens

const totalOutput =
  translationResult.tokenUsage.output_tokens +
  backtranslationResult.tokenUsage.output_tokens +
  reviewResult.tokenUsage.output_tokens

console.log('-'.repeat(60))
console.log(`TOTAL                   — input: ${totalInput}, output: ${totalOutput}`)
console.log('\nDone.')

structured-output.source:
/**
 * Structured Output
 *
 * Demonstrates `outputSchema` on AgentConfig. The agent's response is
 * automatically parsed as JSON and validated against a Zod schema.
 * On validation failure, the framework retries once with error feedback.
 *
 * The validated result is available via `result.structured`.
 *
 * Run:
 *   npx tsx packages/core/examples/patterns/structured-output.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY env var must be set.
 */

import { z } from 'zod'
import { OpenMultiAgent } from '../../src/index.js'
import type { AgentConfig } from '../../src/types.js'

// ---------------------------------------------------------------------------
// Define a Zod schema for the expected output
// ---------------------------------------------------------------------------

const ReviewAnalysis = z.object({
  summary: z.string().describe('One-sentence summary of the review'),
  sentiment: z.enum(['positive', 'negative', 'neutral']),
  confidence: z.number().min(0).max(1).describe('How confident the analysis is'),
  keyTopics: z.array(z.string()).describe('Main topics mentioned in the review'),
})

type ReviewAnalysis = z.infer<typeof ReviewAnalysis>

// ---------------------------------------------------------------------------
// Agent with outputSchema
// ---------------------------------------------------------------------------

const analyst: AgentConfig = {
  name: 'analyst',
  model: 'claude-sonnet-4-6',
  systemPrompt: 'You are a product review analyst. Analyze the given review and extract structured insights.',
  outputSchema: ReviewAnalysis,
}

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------

const orchestrator = new OpenMultiAgent({ defaultModel: 'claude-sonnet-4-6' })

const reviews = [
  'This keyboard is amazing! The mechanical switches feel incredible and the RGB lighting is stunning. Build quality is top-notch. Only downside is the price.',
  'Terrible experience. The product arrived broken, customer support was unhelpful, and the return process took 3 weeks.',
  'It works fine. Nothing special, nothing bad. Does what it says on the box.',
]

console.log('Analyzing product reviews with structured output...\n')

for (const review of reviews) {
  const result = await orchestrator.runAgent(analyst, `Analyze this review: "${review}"`)

  if (result.structured) {
    const data = result.structured as ReviewAnalysis
    console.log(`Sentiment: ${data.sentiment} (confidence: ${data.confidence})`)
    console.log(`Summary:   ${data.summary}`)
    console.log(`Topics:    ${data.keyTopics.join(', ')}`)
  } else {
    console.log(`Validation failed. Raw output: ${result.output.slice(0, 100)}`)
  }

  console.log(`Tokens:    ${result.tokenUsage.input_tokens} in / ${result.tokenUsage.output_tokens} out`)
  console.log('---')
}

multi-perspective-code-review.source:
/**
 * Multi-Perspective Code Review
 *
 * Demonstrates:
 * - Dependency chain: generator produces code, three reviewers depend on it
 * - Parallel execution: security, performance, and style reviewers run concurrently
 * - Structured output: synthesizer returns a Zod-validated list of findings
 * - Shared memory: each agent's output is automatically stored and injected
 *   into downstream agents' prompts by the framework
 *
 * Flow:
 *   generator → [security-reviewer, performance-reviewer, style-reviewer] (parallel) → synthesizer
 *
 * Run:
 *   npx tsx packages/core/examples/patterns/multi-perspective-code-review.ts
 *
 * Prerequisites:
 *   If LLM_PROVIDER is unset, this example auto-selects the first available key
 *   in this fixed order: Gemini → Groq → OpenRouter → Anthropic.
 *   This precedence is this example's implementation choice for satisfying
 *   "default to whichever key is present".
 *   Override with LLM_PROVIDER=gemini|groq|openrouter|anthropic.
 *
 *   Supported env vars:
 *   - Gemini: GEMINI_API_KEY, GOOGLE_API_KEY, or GOOGLE_AI_STUDIO_API_KEY
 *   - Groq: GROQ_API_KEY
 *   - OpenRouter: OPENROUTER_API_KEY
 *   - Anthropic: ANTHROPIC_API_KEY
 *
 *   Anthropic support is kept for backward compatibility with the original
 *   example. It is not part of the free-provider path.
 */

import { z } from 'zod'
import { OpenMultiAgent } from '../../src/index.js'
import type { AgentConfig, OrchestratorEvent } from '../../src/types.js'

// ---------------------------------------------------------------------------
// API spec to implement
// ---------------------------------------------------------------------------

const API_SPEC = `POST /users endpoint that:
- Accepts JSON body with name (string, required), email (string, required), age (number, optional)
- Validates all fields
- Inserts into a PostgreSQL database
- Returns 201 with the created user or 400/500 on error`

// ---------------------------------------------------------------------------
// Structured output schema
// ---------------------------------------------------------------------------

const ReviewFinding = z.object({
  priority: z.enum(['critical', 'high', 'medium', 'low']),
  category: z.enum(['security', 'performance', 'style']),
  issue: z.string().describe('A concise description of the code review finding'),
  fix_hint: z.string().describe('A short, actionable suggestion for fixing the issue'),
})

const ReviewFindings = z.array(ReviewFinding)

type ProviderId = 'anthropic' | 'gemini' | 'groq' | 'openrouter'
type ProviderConfig = Pick<AgentConfig, 'provider' | 'model' | 'apiKey' | 'baseURL'>

// ---------------------------------------------------------------------------
// Provider resolution
// ---------------------------------------------------------------------------

function getGeminiApiKey(): string | undefined {
  return (
    process.env.GEMINI_API_KEY ??
    process.env.GOOGLE_API_KEY ??
    process.env.GOOGLE_AI_STUDIO_API_KEY
  )
}

function inferProvider(): ProviderId {
  if (getGeminiApiKey()) return 'gemini'
  if (process.env.GROQ_API_KEY) return 'groq'
  if (process.env.OPENROUTER_API_KEY) return 'openrouter'
  if (process.env.ANTHROPIC_API_KEY) return 'anthropic'

  throw new Error(
    'No supported API key found. Set GEMINI_API_KEY / GOOGLE_API_KEY / GOOGLE_AI_STUDIO_API_KEY, ' +
      'GROQ_API_KEY, OPENROUTER_API_KEY, or ANTHROPIC_API_KEY.',
  )
}

function getSelectedProvider(): ProviderId {
  const requested = process.env.LLM_PROVIDER?.trim().toLowerCase()
  if (!requested) return inferProvider()

  if (
    requested === 'anthropic' ||
    requested === 'gemini' ||
    requested === 'groq' ||
    requested === 'openrouter'
  ) {
    return requested
  }

  throw new Error(
    `Unsupported LLM_PROVIDER="${process.env.LLM_PROVIDER}". ` +
      'Use one of: gemini, groq, openrouter, anthropic.',
  )
}

function getProviderConfigs(provider: ProviderId): {
  defaultModel: string
  defaultProvider: 'anthropic' | 'gemini' | 'openai'
  fast: ProviderConfig
  strong: ProviderConfig
} {
  switch (provider) {
    case 'gemini': {
      const apiKey = getGeminiApiKey()
      if (!apiKey) {
        throw new Error(
          'LLM_PROVIDER=gemini requires GEMINI_API_KEY, GOOGLE_API_KEY, or GOOGLE_AI_STUDIO_API_KEY.',
        )
      }

      return {
        defaultModel: 'gemini-2.5-flash',
        defaultProvider: 'gemini',
        fast: {
          provider: 'gemini',
          model: 'gemini-2.5-flash',
          apiKey,
        },
        strong: {
          provider: 'gemini',
          model: 'gemini-2.5-flash',
          apiKey,
        },
      }
    }

    case 'groq': {
      const apiKey = process.env.GROQ_API_KEY
      if (!apiKey) {
        throw new Error('LLM_PROVIDER=groq requires GROQ_API_KEY.')
      }

      return {
        defaultModel: 'llama-3.3-70b-versatile',
        defaultProvider: 'openai',
        fast: {
          provider: 'openai',
          model: 'llama-3.3-70b-versatile',
          apiKey,
          baseURL: 'https://api.groq.com/openai/v1',
        },
        strong: {
          provider: 'openai',
          model: 'llama-3.3-70b-versatile',
          apiKey,
          baseURL: 'https://api.groq.com/openai/v1',
        },
      }
    }

    case 'openrouter': {
      const apiKey = process.env.OPENROUTER_API_KEY
      if (!apiKey) {
        throw new Error('LLM_PROVIDER=openrouter requires OPENROUTER_API_KEY.')
      }

      return {
        defaultModel: 'google/gemini-2.5-flash',
        defaultProvider: 'openai',
        fast: {
          provider: 'openai',
          model: 'google/gemini-2.5-flash',
          apiKey,
          baseURL: 'https://openrouter.ai/api/v1',
        },
        strong: {
          provider: 'openai',
          model: 'google/gemini-2.5-flash',
          apiKey,
          baseURL: 'https://openrouter.ai/api/v1',
        },
      }
    }

    case 'anthropic':
    default:
      if (!process.env.ANTHROPIC_API_KEY) {
        throw new Error('LLM_PROVIDER=anthropic requires ANTHROPIC_API_KEY.')
      }

      return {
        defaultModel: 'claude-sonnet-4-6',
        defaultProvider: 'anthropic',
        fast: {
          provider: 'anthropic',
          model: 'claude-sonnet-4-6',
        },
        strong: {
          provider: 'anthropic',
          model: 'claude-sonnet-4-6',
        },
      }
  }
}

const selectedProvider = getSelectedProvider()
const providerConfigs = getProviderConfigs(selectedProvider)

// ---------------------------------------------------------------------------
// Agents
// ---------------------------------------------------------------------------

const generator: AgentConfig = {
  name: 'generator',
  ...providerConfigs.fast,
  systemPrompt: `You are a Node.js backend developer. Given an API spec, write a complete
Express route handler. Include imports, validation, database query, and error handling.
Output only the code, no explanation. Keep it under 80 lines.`,
  maxTurns: 2,
}

const securityReviewer: AgentConfig = {
  name: 'security-reviewer',
  ...providerConfigs.fast,
  systemPrompt: `You are a security reviewer. Review the code provided in context and check
for OWASP top 10 vulnerabilities: SQL injection, XSS, broken authentication,
sensitive data exposure, etc. Write your findings as a markdown checklist.
Keep it to 150-200 words.`,
  maxTurns: 2,
}

const performanceReviewer: AgentConfig = {
  name: 'performance-reviewer',
  ...providerConfigs.fast,
  systemPrompt: `You are a performance reviewer. Review the code provided in context and check
for N+1 queries, memory leaks, blocking calls, missing connection pooling, and
inefficient patterns. Write your findings as a markdown checklist.
Keep it to 150-200 words.`,
  maxTurns: 2,
}

const styleReviewer: AgentConfig = {
  name: 'style-reviewer',
  ...providerConfigs.fast,
  systemPrompt: `You are a code style reviewer. Review the code provided in context and check
naming conventions, function structure, readability, error message clarity, and
consistency. Write your findings as a markdown checklist.
Keep it to 150-200 words.`,
  maxTurns: 2,
}

const synthesizer: AgentConfig = {
  name: 'synthesizer',
  ...providerConfigs.strong,
  systemPrompt: `You are a lead engineer synthesizing code review feedback. Review all
the feedback and original code provided in context. Produce a deduplicated list of
code review findings as JSON.

Rules:
- Output ONLY a JSON array matching the provided schema.
- Merge overlapping reviewer comments into a single finding when they describe the same issue.
- Use category "security", "performance", or "style" only.
- Use priority "critical", "high", "medium", or "low" only.
- issue should describe the problem, not the fix.
- fix_hint should be specific and actionable.
- If the code looks clean, return an empty JSON array.`,
  maxTurns: 2,
  outputSchema: ReviewFindings,
}

// ---------------------------------------------------------------------------
// Orchestrator + team
// ---------------------------------------------------------------------------

function handleProgress(event: OrchestratorEvent): void {
  if (event.type === 'task_start') {
    console.log(`  [START] ${event.task ?? '?'} → ${event.agent ?? '?'}`)
  }
  if (event.type === 'task_complete') {
    const success = (event.data as { success?: boolean })?.success ?? true
    console.log(`  [DONE]  ${event.task ?? '?'} (${success ? 'OK' : 'FAIL'})`)
  }
}

const orchestrator = new OpenMultiAgent({
  defaultModel: providerConfigs.defaultModel,
  defaultProvider: providerConfigs.defaultProvider,
  onProgress: handleProgress,
})

const team = orchestrator.createTeam('code-review-team', {
  name: 'code-review-team',
  agents: [generator, securityReviewer, performanceReviewer, styleReviewer, synthesizer],
  sharedMemory: true,
})

// ---------------------------------------------------------------------------
// Tasks
// ---------------------------------------------------------------------------

const tasks = [
  {
    title: 'Generate code',
    description: `Write a Node.js Express route handler for this API spec:\n\n${API_SPEC}`,
    assignee: 'generator',
  },
  {
    title: 'Security review',
    description: 'Review the generated code for security vulnerabilities.',
    assignee: 'security-reviewer',
    dependsOn: ['Generate code'],
  },
  {
    title: 'Performance review',
    description: 'Review the generated code for performance issues.',
    assignee: 'performance-reviewer',
    dependsOn: ['Generate code'],
  },
  {
    title: 'Style review',
    description: 'Review the generated code for style and readability.',
    assignee: 'style-reviewer',
    dependsOn: ['Generate code'],
  },
  {
    title: 'Synthesize feedback',
    description: 'Synthesize all review feedback and the original code into a unified, prioritized structured findings array.',
    assignee: 'synthesizer',
    dependsOn: ['Security review', 'Performance review', 'Style review'],
  },
]

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------

console.log('Multi-Perspective Code Review')
console.log('='.repeat(60))
console.log(`Provider: ${selectedProvider}`)
console.log(`Spec: ${API_SPEC.split('\n')[0]}`)
console.log('Pipeline: generator → 3 reviewers (parallel) → synthesizer')
console.log('='.repeat(60))
console.log()

const result = await orchestrator.runTasks(team, tasks)

// ---------------------------------------------------------------------------
// Output
// ---------------------------------------------------------------------------

console.log('\n' + '='.repeat(60))
console.log(`Overall success: ${result.success}`)
console.log(`Tokens — input: ${result.totalTokenUsage.input_tokens}, output: ${result.totalTokenUsage.output_tokens}`)
console.log()

for (const [name, r] of result.agentResults) {
  const icon = r.success ? 'OK  ' : 'FAIL'
  const tokens = `in:${r.tokenUsage.input_tokens} out:${r.tokenUsage.output_tokens}`
  console.log(`  [${icon}] ${name.padEnd(22)} ${tokens}`)
}

const synthResult = result.agentResults.get('synthesizer')
if (synthResult?.structured) {
  console.log('\n' + '='.repeat(60))
  console.log('STRUCTURED REVIEW FINDINGS')
  console.log('='.repeat(60))
  console.log()
  console.log(JSON.stringify(synthResult.structured, null, 2))
} else if (synthResult) {
  console.log('\n' + '='.repeat(60))
  console.log('SYNTHESIZER OUTPUT FAILED SCHEMA VALIDATION OR DID NOT PRODUCE VALID JSON')
  console.log('='.repeat(60))
  console.log()
  console.log(synthResult.output.slice(0, 1200))
}

console.log('\nDone.')

narrative-puzzle-hint-arbitration.source:
/**
 * Narrative Puzzle Hint Arbitration (Multi-Source Conflict Resolution + Safety Veto)
 *
 * Demonstrates:
 * - Five agents in a three-tier architecture: upstream parallel → dependent synthesis → external veto
 * - Three source-isolated upstream agents reading different MOCK fixtures:
 *   - Mechanic Agent: game state analysis (structured puzzle progress, no player-facing text)
 *   - Lore Agent: diegetic hint framing in the game world's narrative voice
 *   - Community Agent: empirically effective hint proposal based on player behavior analytics
 * - A downstream Arbiter that receives only structured upstream outputs, detects cross-source
 *   conflicts, and generates a compromise hint following priority chain safety > immersion > progress
 * - An external Safety Agent that performs independent semantic review on the Arbiter's draft
 *   and issues a binary veto when the hint reveals or materially narrows toward a protected
 *   puzzle linkage — the veto sits outside the generation loop so hard constraints cannot be
 *   overridden downstream
 * - Runtime conflict scenario (Piano-Mirror): Lore demands metaphorical framing, Community
 *   demands directness, and the Arbiter's compromise is vetoed because it compresses the
 *   search space enough to defeat the designed discovery moment
 * - Zod-validated structured output and simple runtime assertions
 *
 * Run:
 *   npx tsx packages/core/examples/cookbook/narrative-puzzle-hint-arbitration.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY env var must be set.
 *   Requires Node.js >= 18.
 *
 * Fixtures:
 *   All fixtures under examples/fixtures/narrative-puzzle-hint-arbitration/ are MOCK.
 *   They are shaped like realistic source types (game save, lore wiki, platform analytics,
 *   designer policy) but do not contain real game artifacts. The scenario is fictional and
 *   constructed solely for demonstration of the multi-agent conflict resolution pattern.
 */

import { readFileSync } from 'node:fs'
import { fileURLToPath } from 'node:url'
import path from 'node:path'
import { z } from 'zod'
import { Agent, ToolExecutor, ToolRegistry } from '../../src/index.js'
import type { AgentConfig, AgentRunResult } from '../../src/types.js'

// ---------------------------------------------------------------------------
// Fixture loading
// ---------------------------------------------------------------------------

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const fixtureRoot = path.join(__dirname, '../fixtures/narrative-puzzle-hint-arbitration')

function readFixture(name: string): string {
  return readFileSync(path.join(fixtureRoot, name), 'utf-8')
}

const extractedGameState = readFixture('extracted-game-state.json')
const loreCorpus = readFixture('lore-corpus.md')
const communityAggregates = readFixture('community-aggregates.json')
const designerConstraints = readFixture('designer-constraints.json')

const MODEL = process.env['MODEL'] ?? 'claude-sonnet-4-6'
const ANTHROPIC_API_KEY = process.env['ANTHROPIC_API_KEY']
const ANTHROPIC_BASE_URL = process.env['ANTHROPIC_BASE_URL']

const providerConfig = {
  provider: 'anthropic' as const,
  model: MODEL,
  apiKey: ANTHROPIC_API_KEY,
  baseURL: ANTHROPIC_BASE_URL,
  tools: [] as const,
}

// ---------------------------------------------------------------------------
// Zod schemas
// ---------------------------------------------------------------------------

const MechanicAudit = z.object({
  source_is_mock: z.boolean(),
  room: z.string(),
  inventory: z.array(z.string()),
  scene_flags: z.record(z.boolean()),
  puzzle_states: z.array(z.object({
    puzzle_id: z.string(),
    status: z.enum(['solved', 'partial', 'unsolved']),
    progress_summary: z.string(),
  })),
  interactions_completed: z.array(z.string()),
  interactions_remaining: z.array(z.string()),
  solution_step_diffs: z.array(z.string()),
  unexamined_objects: z.array(z.string()),
})
type MechanicAudit = z.infer<typeof MechanicAudit>

const LoreAudit = z.object({
  source_is_mock: z.boolean(),
  narrative_context: z.string(),
  character_voice: z.string(),
  voice_rules: z.array(z.string()),
  proposed_diegetic_framing: z.string(),
  framing_type: z.enum(['metaphor', 'allegory', 'environmental_clue', 'direct_instruction']),
  consistency_notes: z.string(),
  puzzle_correctness_asserted: z.boolean(),
})
type LoreAudit = z.infer<typeof LoreAudit>

const CommunityAudit = z.object({
  source_is_mock: z.boolean(),
  stuck_points: z.array(z.object({
    puzzle_id: z.string(),
    stuck_rate: z.number(),
    common_misconception: z.string(),
  })),
  effective_hint_patterns: z.array(z.object({
    framing: z.string(),
    effectiveness_rating: z.string(),
    spoiler_risk: z.string(),
  })),
  representative_player_quotes: z.array(z.string()),
  proposed_hint_framing: z.string(),
  full_solution_disclosed: z.boolean(),
})
type CommunityAudit = z.infer<typeof CommunityAudit>

const HintDraft = z.object({
  conflict_detected: z.boolean(),
  conflicts: z.array(z.string()),
  lore_proposal_summary: z.string(),
  community_proposal_summary: z.string(),
  compromise_hint: z.string(),
  hint_type: z.enum(['metaphor', 'direct', 'compromise', 'fallback']),
  priority_chain_applied: z.string(),
  rationale: z.string(),
})
type HintDraft = z.infer<typeof HintDraft>

const SafetyReview = z.object({
  source_is_mock: z.boolean(),
  hint_under_review: z.string(),
  puzzle_id_targeted: z.string(),
  protected_linkage_revealed: z.boolean(),
  search_space_sufficiently_compressed: z.boolean(),
  spoiler_sensitivity_level: z.string(),
  max_allowed_directionality: z.string(),
  veto_triggered: z.boolean(),
  veto_reason: z.string(),
  fallback_hint: z.string(),
  fallback_hint_type: z.string(),
})
type SafetyReview = z.infer<typeof SafetyReview>

// ---------------------------------------------------------------------------
// Agent configs
// ---------------------------------------------------------------------------

const mechanicConfig: AgentConfig = {
  name: 'mechanic-agent',
  ...providerConfig,
  systemPrompt: `You are a game state analyst for a point-and-click adventure game.

You read only the provided MOCK game save state. Extract:
- Current room and inventory
- Scene flags (what has been interacted with)
- Puzzle states: which are solved, partial, or unsolved, with progress details
- Abstract solution step diffs: what remains to be done (e.g., "2 of 4 piano notes remain")
- Unexamined objects the player has not yet interacted with

You must NEVER produce player-facing text. Your output is purely structural data
that downstream agents will use to make hint decisions.

Return JSON matching the provided schema. Output ONLY valid JSON, no markdown,
no code fences, and no explanatory prose.`,
  maxTurns: 1,
  maxTokens: 1800,
  temperature: 0.1,
  outputSchema: MechanicAudit,
}

const loreConfig: AgentConfig = {
  name: 'lore-agent',
  ...providerConfig,
  systemPrompt: `You are a diegetic hint designer for a narrative puzzle game.

You read only the provided MOCK lore corpus. Tier 1 is official in-game text.
Tier 2 is community-accepted factual lore. Tier 3 (community theory) is excluded
from your input.

You embody The Performer — a character who communicates only through music,
metaphor, and theatrical imagery. The Performer's voice rules:
- NEVER give direct instructions (no "click", "move", "use", "look at")
- NEVER name objects explicitly in connection with each other
- NEVER reference game mechanics or UI elements
- NEVER assert whether a puzzle solution is correct or incorrect
- Guidance must feel like a line from a poem or a stage direction

Given the current game state summary, propose a single diegetic hint in The
Performer's voice. The hint should guide without instructing.

Return JSON matching the provided schema. Output ONLY valid JSON, no markdown,
no code fences, and no explanatory prose.`,
  maxTurns: 1,
  maxTokens: 1800,
  temperature: 0.1,
  outputSchema: LoreAudit,
}

const communityConfig: AgentConfig = {
  name: 'community-agent',
  ...providerConfig,
  systemPrompt: `You are a community analytics agent for a puzzle game.

You read only the provided MOCK platform analytics — stuck rates, effective hint
patterns, and representative player quotes.

Your job:
- Identify where players get stuck and why
- Analyze which hint framings have empirically reduced stuck duration
- Propose a hint framing based on what has actually worked for other players
- Flag spoiler risk for each proposed framing

You must NOT output full solution sequences. You must NOT disclose complete puzzle
answers. Your proposed hint should be influenced by empirical effectiveness data.

Return JSON matching the provided schema. Output ONLY valid JSON, no markdown,
no code fences, and no explanatory prose.`,
  maxTurns: 1,
  maxTokens: 2000,
  temperature: 0.1,
  outputSchema: CommunityAudit,
}

const arbiterConfig: AgentConfig = {
  name: 'hint-arbiter',
  ...providerConfig,
  systemPrompt: `You are the downstream arbiter for an immersive puzzle hint system.

You receive only structured outputs from three source-isolated agents:
- Mechanic: game state analysis (what is solved, what remains)
- Lore agent: a diegetic hint proposal in the game world's narrative voice
- Community agent: an empirically effective hint proposal based on player behavior

You cannot access the original fixtures. Your tasks:
1. Detect conflicts between the Lore proposal (immersive, metaphorical) and the
   Community proposal (direct, empirically effective).
2. Apply the priority chain: safety > immersion > progress.
3. Generate a compromise hint that balances narrative immersion with practical
   usefulness for stuck players.
4. Surface all conflicts explicitly in your output.

The fundamental tension: Lore preserves the game's designed discovery moment but
may not help frustrated players. Community helps players but may break narrative
voice and reveal intended surprises.

Return JSON matching the provided schema. Output ONLY valid JSON, no markdown,
no code fences, and no explanatory prose.`,
  maxTurns: 1,
  maxTokens: 3000,
  temperature: 0.1,
  outputSchema: HintDraft,
}

const safetyConfig: AgentConfig = {
  name: 'safety-agent',
  ...providerConfig,
  systemPrompt: `You are an independent safety reviewer for a puzzle hint system.

You receive two inputs:
1. A MOCK designer constraint policy — rules about spoiler sensitivity, allowed
   hint types, and protected object linkages for each puzzle.
2. A hint draft produced by the Arbiter.

Your job is binary semantic review:
- Does the hint draft explicitly reveal a protected object linkage?
- Does the hint compress the search space so aggressively that a frustrated player
  would brute-force the connection within 1-2 additional attempts?
- Does the hint violate any prohibited_hint_types for the targeted puzzle?

If ANY constraint is violated — even indirectly — set veto_triggered to true,
explain the reason, and provide a fallback hint: a vague atmospheric room
description with no puzzle-relevant directional cue, plus a system-level nudge
to inspect unexamined objects.

If the hint is safe, set veto_triggered to false and pass the hint through unchanged.

Return JSON matching the provided schema. Output ONLY valid JSON, no markdown,
no code fences, and no explanatory prose.`,
  maxTurns: 1,
  maxTokens: 2000,
  temperature: 0.1,
  outputSchema: SafetyReview,
}

// ---------------------------------------------------------------------------
// Build agents
// ---------------------------------------------------------------------------

function buildAgent(config: AgentConfig): Agent {
  // Source isolation is enforced at runtime: fixtures are injected into prompts,
  // and audit agents receive an empty tool registry with tools: [].
  const registry = new ToolRegistry()
  const executor = new ToolExecutor(registry)
  return new Agent(config, registry, executor)
}

const mechanicAgent = buildAgent(mechanicConfig)
const loreAgent = buildAgent(loreConfig)
const communityAgent = buildAgent(communityConfig)
const hintArbiter = buildAgent(arbiterConfig)
const safetyAgent = buildAgent(safetyConfig)

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

async function runTimed(
  name: string,
  agent: Agent,
  prompt: string,
): Promise<{ name: string, result: AgentRunResult, elapsedMs: number }> {
  const start = performance.now()
  const maxAttempts = 3

  for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
    console.log(`  [RUN] ${name} started... attempt ${attempt}/${maxAttempts}`)
    const result = await agent.run(prompt)
    const elapsedMs = performance.now() - start

    if (result.success && result.structured) {
      console.log(`  [DONE] ${name} finished in ${Math.round(elapsedMs)}ms`)
      return { name, result, elapsedMs }
    }

    const outputPreview = result.output ? result.output.slice(0, 240).replace(/\s+/g, ' ') : '<empty output>'
    console.warn(`  [RETRY] ${name} failed structured output on attempt ${attempt}/${maxAttempts}: ${outputPreview}`)
  }

  const result = await agent.run(prompt)
  const elapsedMs = performance.now() - start
  console.log(`  [DONE] ${name} finished in ${Math.round(elapsedMs)}ms`)
  return { name, result, elapsedMs }
}

function requireStructured<T>(name: string, result: AgentRunResult): T {
  if (!result.success) {
    console.error(`${name} failed: ${result.output}`)
    process.exit(1)
  }

  if (!result.structured) {
    console.error(`${name} did not return structured output`)
    process.exit(1)
  }

  return result.structured as T
}

// ---------------------------------------------------------------------------
// Main execution
// ---------------------------------------------------------------------------

console.log('Narrative Puzzle Hint Arbitration — Multi-Source Conflict Resolution + Safety Veto')
console.log('='.repeat(88))
console.log(`Model backend: anthropic-compatible (${MODEL})`)
console.log('All fixtures are MOCK. The Piano-Mirror scenario is fictional.')
console.log('Expected conflict: Lore demands metaphor, Community demands directness, Safety vetoes compromise.\n')

async function main(): Promise<void> {
  // -----------------------------------------------------------------------
  // Phase 1: Source-isolated upstream audits
  // -----------------------------------------------------------------------

  console.log('[Phase 1] Source-isolated upstream audits\n')

  const phase1Start = performance.now()
  const upstreamRuns: Array<{ name: string, result: AgentRunResult, elapsedMs: number }> = []

  upstreamRuns.push(await runTimed(
    'mechanic-agent',
    mechanicAgent,
    `Analyze this MOCK game save state. Use only this input.\n\n${extractedGameState}`,
  ))

  upstreamRuns.push(await runTimed(
    'lore-agent',
    loreAgent,
    `You are The Performer. Use only this lore corpus (Tier 1 and Tier 2 only).
Propose a diegetic hint for the current game state described below.

LORE CORPUS:
${loreCorpus}

CURRENT GAME STATE SUMMARY:
The player is in the theatre room. The piano sequence is partial (2 of 4 notes played).
The mirror has not been interacted with. The candle has been lit, revealing an inscription.
The player has a handkerchief and a pawn in inventory.

Propose a single hint in The Performer's voice.`,
  ))

  upstreamRuns.push(await runTimed(
    'community-agent',
    communityAgent,
    `Analyze these MOCK platform analytics and propose a hint framing.
Use only this input.

${communityAggregates}`,
  ))

  const phase1Elapsed = performance.now() - phase1Start

  const upstreamMap = new Map(upstreamRuns.map((run) => [run.name, run.result]))

  const mechanicAudit = requireStructured<MechanicAudit>('mechanic-agent', upstreamMap.get('mechanic-agent')!)
  const loreAudit = requireStructured<LoreAudit>('lore-agent', upstreamMap.get('lore-agent')!)
  const communityAudit = requireStructured<CommunityAudit>('community-agent', upstreamMap.get('community-agent')!)

  console.log('\n[Phase 1 Summary]')
  for (const run of upstreamRuns) {
    const status = run.result.success ? 'OK' : 'FAILED'
    console.log(`  ${run.name.padEnd(25)} [${status}] ${Math.round(run.elapsedMs)}ms, ${run.result.tokenUsage.output_tokens} out tokens`)
  }
  console.log(`  Phase 1 wall time: ${Math.round(phase1Elapsed)}ms\n`)

  // -----------------------------------------------------------------------
  // Phase 2: Arbiter — receives structured upstream outputs only
  // -----------------------------------------------------------------------

  console.log('[Phase 2] Arbiter — conflict detection and hint draft\n')

  const arbiterPrompt = `You are given structured outputs from three source-isolated agents.
You cannot access the original fixtures. Detect conflicts and produce a hint draft.

MECHANIC AUDIT (game state):
${JSON.stringify(mechanicAudit, null, 2)}

LORE AUDIT (diegetic hint proposal):
${JSON.stringify(loreAudit, null, 2)}

COMMUNITY AUDIT (empirical hint proposal):
${JSON.stringify(communityAudit, null, 2)}

Rules:
- Surface the conflict between Lore's metaphorical framing and Community's direct framing.
- Attempt a compromise following priority chain: safety > immersion > progress.
- The compromise should be a hint that a player would actually receive in-game.
- Return one JSON object matching the schema, no markdown.`

  const arbiterStart = performance.now()
  const arbiterResult = await hintArbiter.run(arbiterPrompt)
  const arbiterElapsed = performance.now() - arbiterStart

  const hintDraft = requireStructured<HintDraft>('hint-arbiter', arbiterResult)

  console.log(`  Arbiter [OK] ${Math.round(arbiterElapsed)}ms, ${arbiterResult.tokenUsage.output_tokens} out tokens\n`)

  // -----------------------------------------------------------------------
  // Phase 3: Safety — external veto on the Arbiter's draft
  // -----------------------------------------------------------------------

  console.log('[Phase 3] Safety — external veto review\n')

  const safetyPrompt = `Review this hint draft against the designer constraints.

DESIGNER CONSTRAINTS:
${designerConstraints}

HINT DRAFT FROM ARBITER:
${JSON.stringify(hintDraft, null, 2)}

Determine whether the hint violates any constraint. If it does, veto it and
provide a fallback. If it is safe, approve it.`

  const safetyStart = performance.now()
  const safetyResult = await safetyAgent.run(safetyPrompt)
  const safetyElapsed = performance.now() - safetyStart

  const safetyReview = requireStructured<SafetyReview>('safety-agent', safetyResult)

  console.log(`  Safety [OK] ${Math.round(safetyElapsed)}ms, ${safetyResult.tokenUsage.output_tokens} out tokens\n`)

  // -----------------------------------------------------------------------
  // Runtime assertions
  // -----------------------------------------------------------------------

  const asserts = [
    {
      name: 'Arbiter should detect conflict between Lore and Community',
      pass: hintDraft.conflict_detected === true,
    },
    {
      name: 'Arbiter should surface explicit conflicts',
      pass: hintDraft.conflicts.length > 0,
    },
    {
      name: 'Lore agent should not assert puzzle correctness',
      pass: loreAudit.puzzle_correctness_asserted === false,
    },
    {
      name: 'Community agent should not disclose full solution',
      pass: communityAudit.full_solution_disclosed === false,
    },
    {
      name: 'Safety should trigger veto on the Piano-Mirror compromise',
      pass: safetyReview.veto_triggered === true,
    },
    {
      name: 'Safety fallback should be atmospheric when veto is triggered',
      pass: !safetyReview.veto_triggered || safetyReview.fallback_hint_type.toLowerCase().includes('atmospheric'),
    },
  ]

  console.log('='.repeat(88))
  console.log('HINT DRAFT FROM ARBITER')
  console.log('='.repeat(88))
  console.log(JSON.stringify(hintDraft, null, 2))
  console.log()

  console.log('='.repeat(88))
  console.log('SAFETY REVIEW')
  console.log('='.repeat(88))
  console.log(JSON.stringify(safetyReview, null, 2))
  console.log()

  console.log('## Runtime Assertions\n')
  let hasFailure = false
  for (const assertion of asserts) {
    console.log(`- ${assertion.pass ? 'PASS' : 'FAIL'}: ${assertion.name}`)
    if (!assertion.pass) hasFailure = true
  }

  const allRuns = [...upstreamRuns, { name: 'hint-arbiter', result: arbiterResult, elapsedMs: arbiterElapsed }, { name: 'safety-agent', result: safetyResult, elapsedMs: safetyElapsed }]

  const totalOutputTokens = allRuns.reduce((sum, run) => sum + run.result.tokenUsage.output_tokens, 0)
  const totalInputTokens = allRuns.reduce((sum, run) => sum + run.result.tokenUsage.input_tokens, 0)

  console.log('\n## Token Usage\n')
  console.log(`Input tokens: ${totalInputTokens}`)
  console.log(`Output tokens: ${totalOutputTokens}`)
  console.log('Estimated cost depends on the selected provider/model; this example prints token usage for transparency.')

  console.log('\n' + '='.repeat(88))

  if (hasFailure) {
    console.error('Runtime assertion failed.')
    process.exit(1)
  }

  console.log('Narrative puzzle hint arbitration example complete.\n')
}

main().catch((err) => {
  console.error('Fatal error:', err)
  process.exit(1)
})

// ---------------------------------------------------------------------------
// Production source adapter sketch
// ---------------------------------------------------------------------------
//
// This example intentionally uses committed MOCK fixtures so the demo is
// deterministic, safe, and runnable. A production version could replace fixtures
// with source adapters:
//
//   Mechanic: parse binary save files or query the game engine's runtime state API
//   Lore: load from game CMS with versioned narrative content
//   Community: scheduled crawlers against Bilibili / TapTap APIs or equivalent
//   Safety: live designer-authored policy service
//
// The three-tier architecture (upstream parallel → arbiter → external veto)
// would remain the same.

task-pipeline.source:
/**
 * Explicit Task Pipeline with Dependencies
 *
 * Demonstrates how to define tasks with explicit dependency chains
 * (design → implement → test → review) using runTasks(). The TaskQueue
 * automatically blocks downstream tasks until their dependencies complete.
 * Prompt context is dependency-scoped by default: each task sees only its own
 * description plus direct dependency results (not unrelated team outputs).
 *
 * Run:
 *   npx tsx packages/core/examples/basics/task-pipeline.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY env var must be set.
 */

import { join } from 'node:path'
import { OpenMultiAgent } from '../../src/index.js'
import type { AgentConfig, OrchestratorEvent, Task } from '../../src/types.js'

// Built-in filesystem tools are sandboxed to `<cwd>/.agent-workspace` by
// default; pipeline output lives under that root so the demo runs without
// disabling the sandbox.
const OUTPUT_DIR = join(process.cwd(), '.agent-workspace', 'pipeline-output')
const SRC_DIR = join(OUTPUT_DIR, 'src')
const SPEC_FILE = join(OUTPUT_DIR, 'design-spec.md')

// ---------------------------------------------------------------------------
// Agents
// ---------------------------------------------------------------------------

const designer: AgentConfig = {
  name: 'designer',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a software designer. Your output is always a concise technical spec
in markdown. Focus on interfaces, data shapes, and file structure. Be brief.`,
  tools: ['file_write'],
  maxTurns: 4,
}

const implementer: AgentConfig = {
  name: 'implementer',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a TypeScript developer. Read the design spec written by the designer,
then implement it. Write all files to ${OUTPUT_DIR}/. Use the tools.`,
  tools: ['bash', 'file_read', 'file_write'],
  maxTurns: 10,
}

const tester: AgentConfig = {
  name: 'tester',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a QA engineer. Read the implemented files and run them to verify correctness.
Report: what passed, what failed, and any bugs found.`,
  tools: ['bash', 'file_read', 'grep'],
  maxTurns: 6,
}

const reviewer: AgentConfig = {
  name: 'reviewer',
  model: 'claude-sonnet-4-6',
  systemPrompt: `You are a code reviewer. Read all files and produce a brief structured review.
Sections: Summary, Strengths, Issues (if any), Verdict (SHIP / NEEDS WORK).`,
  tools: ['file_read', 'grep'],
  maxTurns: 4,
}

// ---------------------------------------------------------------------------
// Progress handler — shows dependency blocking/unblocking
// ---------------------------------------------------------------------------

const taskTimes = new Map<string, number>()

function handleProgress(event: OrchestratorEvent): void {
  const ts = new Date().toISOString().slice(11, 23)

  switch (event.type) {
    case 'task_start': {
      taskTimes.set(event.task ?? '', Date.now())
      const task = event.data as Task | undefined
      console.log(`[${ts}] TASK READY    "${task?.title ?? event.task}" (assignee: ${task?.assignee ?? 'any'})`)
      break
    }
    case 'task_complete': {
      const elapsed = Date.now() - (taskTimes.get(event.task ?? '') ?? Date.now())
      const task = event.data as Task | undefined
      console.log(`[${ts}] TASK DONE     "${task?.title ?? event.task}" in ${elapsed}ms`)
      break
    }
    case 'agent_start':
      console.log(`[${ts}] AGENT START   ${event.agent}`)
      break
    case 'agent_complete':
      console.log(`[${ts}] AGENT DONE    ${event.agent}`)
      break
    case 'error': {
      const task = event.data as Task | undefined
      console.error(`[${ts}] ERROR         ${event.agent ?? ''}  task="${task?.title ?? event.task}"`)
      break
    }
  }
}

// ---------------------------------------------------------------------------
// Build the pipeline
// ---------------------------------------------------------------------------

const orchestrator = new OpenMultiAgent({
  defaultModel: 'claude-sonnet-4-6',
  maxConcurrency: 2, // allow test + review to potentially run in parallel later
  onProgress: handleProgress,
})

const team = orchestrator.createTeam('pipeline-team', {
  name: 'pipeline-team',
  agents: [designer, implementer, tester, reviewer],
  sharedMemory: true,
})

// Task IDs — use stable strings so dependsOn can reference them
// (IDs will be generated by the framework; we capture the returned Task objects)

const tasks: Array<{
  title: string
  description: string
  assignee?: string
  dependsOn?: string[]
  memoryScope?: 'dependencies' | 'all'
}> = [
  {
    title: 'Design: URL shortener data model',
    description: `Design a minimal in-memory URL shortener service.
Write a markdown spec to ${SPEC_FILE} covering:
- TypeScript interfaces for Url and ShortenRequest
- The shortening algorithm (hash approach is fine)
- API contract: POST /shorten, GET /:code
Keep the spec under 30 lines.`,
    assignee: 'designer',
    // no dependencies — this is the root task
  },
  {
    title: 'Implement: URL shortener',
    description: `Read the design spec at ${SPEC_FILE}.
Implement the URL shortener in ${SRC_DIR}/:
- shortener.ts: core logic (shorten, resolve functions)
- server.ts: tiny HTTP server using Node's built-in http module (no Express)
  - POST /shorten  body: { url: string } → { code: string, short: string }
  - GET  /:code    → redirect (301) or 404
- index.ts: entry point that starts the server on port 3002
No external dependencies beyond Node built-ins.`,
    assignee: 'implementer',
    dependsOn: ['Design: URL shortener data model'],
  },
  {
    title: 'Test: URL shortener',
    description: `Run the URL shortener implementation:
1. Start the server: node ${SRC_DIR}/index.ts (or tsx)
2. POST a URL to shorten it using curl
3. Verify the GET redirect works
4. Report what passed and what (if anything) failed.
Kill the server after testing.`,
    assignee: 'tester',
    dependsOn: ['Implement: URL shortener'],
  },
  {
    title: 'Review: URL shortener',
    description: `Read all .ts files in ${SRC_DIR}/ and the design spec.
Produce a structured code review with sections:
- Summary (2 sentences)
- Strengths (bullet list)
- Issues (bullet list, or "None" if clean)
- Verdict: SHIP or NEEDS WORK`,
    assignee: 'reviewer',
    dependsOn: ['Implement: URL shortener'], // runs in parallel with Test after Implement completes
    // Optional override: reviewers can opt into full shared memory when needed.
    // Remove this line to keep strict dependency-only context.
    memoryScope: 'all',
  },
]

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------

console.log('Starting 4-stage task pipeline...\n')
console.log('Pipeline: design → implement → test + review (parallel)')
console.log('='.repeat(60))

const result = await orchestrator.runTasks(team, tasks)

// ---------------------------------------------------------------------------
// Summary
// ---------------------------------------------------------------------------

console.log('\n' + '='.repeat(60))
console.log('Pipeline complete.\n')
console.log(`Overall success: ${result.success}`)
console.log(`Tokens — input: ${result.totalTokenUsage.input_tokens}, output: ${result.totalTokenUsage.output_tokens}`)

console.log('\nPer-agent summary:')
for (const [name, r] of result.agentResults) {
  const icon = r.success ? 'OK  ' : 'FAIL'
  const toolCount = r.toolCalls.map(c => c.toolName).join(', ')
  console.log(`  [${icon}] ${name.padEnd(14)}  tools used: ${toolCount || '(none)'}`)
}

// Print the reviewer's verdict
const review = result.agentResults.get('reviewer')
if (review?.success) {
  console.log('\nCode review:')
  console.log('─'.repeat(60))
  console.log(review.output)
  console.log('─'.repeat(60))
}

cross-provider-reasoning.source:
/**
 * Cross-provider reasoning preservation via `preserveReasoningAsText`
 *
 * When an `Agent.prompt()` conversation runs against a "reasoning" model that
 * emits `reasoning_content` (OpenAI o-series, DeepSeek reasoner, Anthropic
 * extended-thinking-via-Bedrock, etc.), the model's intermediate thought
 * stream is normally either:
 *
 *   (a) native-echoed back when the next turn targets the same provider with
 *       a valid signature (Anthropic, Gemini own-issued path), OR
 *   (b) silently dropped on the next outbound conversion (everyone else).
 *
 * Opt into {@link AgentConfig.preserveReasoningAsText} to replace (b) with a
 * downgrade — the prior reasoning is wrapped in `<thinking>...</thinking>`
 * text and prepended to the next assistant message, so the receiving model
 * has full context of what was previously considered. See #223 for design.
 *
 * Run:
 *   npx tsx packages/core/examples/patterns/cross-provider-reasoning.ts
 *
 * Prerequisites:
 *   ANTHROPIC_API_KEY
 *   OPENAI_API_KEY (uses an o-series model for the reasoning emit)
 */

import { Agent } from '../../src/index.js'

// --- Caveat: loop-detector interaction --------------------------------------
//
// Some OpenAI-compatible local models (and a few hosted ones at low quality
// tiers) re-emit `<thinking>...</thinking>` text back into their assistant
// response as if the tag were an instruction template. When this happens
// across multiple turns, the framework's loop-detector may flag the agent as
// stuck because the assistant text matches turn-over-turn.
//
// Mitigation if you hit this:
//   - Set `loopDetection: { enabled: false }` on the AgentConfig (loses the
//     safety net for other genuine loop cases — use as a debug measure only).
//   - Switch to a model that ignores `<thinking>` text on input (most o-series
//     and Claude models do; problem is mostly with smaller local models).
//   - Disable `preserveReasoningAsText` entirely; accept reasoning loss.
//
// The example below does NOT trigger the issue against gpt-5 / Claude, but is
// included so contributors testing local models know what to watch for.
// ----------------------------------------------------------------------------

async function main(): Promise<void> {
  if (!process.env['ANTHROPIC_API_KEY'] || !process.env['OPENAI_API_KEY']) {
    console.log('Skip: ANTHROPIC_API_KEY and OPENAI_API_KEY both required.')
    process.exit(0)
  }

  // Step 1: a reasoning-capable OpenAI model produces a turn that includes
  // a `reasoning_content` chunk. The adapter extracts it into a ReasoningBlock
  // with `provenance: 'openai'`, stored in the agent's persistent history.
  const agent = new Agent({
    name: 'cross-provider-demo',
    model: 'gpt-5',  // o-series-style reasoning model
    provider: 'openai',
    systemPrompt: 'You reason carefully then give a short final answer.',
    preserveReasoningAsText: true,
    // compressReasoningText defaults to `true` whenever preserve is true,
    // so long reasoning chains are head+tail truncated to 1200 chars by
    // default. Override with `{ minChars: N }` to tune, or `false` to disable
    // (footgun — long CoT will eat your prompt budget).
    compressReasoningText: { minChars: 1500 },
  })

  const firstAnswer = await agent.prompt(
    'A train leaves Boston at 60 mph heading west. Another leaves NYC at 80 mph heading north. ' +
    'After 2 hours, what is the straight-line distance between them? Show your reasoning briefly.',
  )
  console.log('--- Turn 1 (OpenAI o-series) ---')
  console.log(firstAnswer.output.slice(0, 500))

  // Step 2: swap the model to Anthropic mid-conversation. Without
  // `preserveReasoningAsText`, the prior reasoning would be silently dropped
  // because Anthropic's outbound only round-trips its own-signed thinking
  // blocks. With opt-in on, the prior OpenAI reasoning is replayed as
  // `<thinking>` text so Claude sees the chain.
  //
  // (Note: in real code you'd construct a new Agent or use a per-call model
  // override. The Agent instance owns its adapter; this example keeps things
  // short and just illustrates the persistence model.)
  console.log('\n(Hypothetical: if you constructed a second Agent against ' +
    'Anthropic and replayed the same messageHistory, the prior OpenAI ' +
    'reasoning would arrive as `<thinking>` text on its first request.)')
}

void main().catch((err: unknown) => {
  console.error(err)
  process.exit(1)
})

paper-replication-triage.source:
/**
 * Paper Replication Triage (Multi-Source Evidence Reconciliation)
 *
 * Demonstrates:
 * - Source-specific agents audit different evidence snapshots, not one shared PDF
 * - runTasks() DAG: parallel source audits -> dependent replication planner
 * - Shared memory/dependency context carries upstream JSON into the planner
 * - Seeded conflicts force the planner to reconcile paper claims vs artifacts
 * - Mocked source snapshots are flagged; SOURCE_MODE=live uses Asta + GitHub
 *
 * Run:
 *   npx tsx packages/core/examples/cookbook/paper-replication-triage.ts
 *   npx tsx packages/core/examples/cookbook/paper-replication-triage.ts "paper title or arXiv id"
 *
 * Optional:
 *   SOURCE_MODE=live npx tsx packages/core/examples/cookbook/paper-replication-triage.ts "ARXIV:1706.03762"
 *
 * Prerequisites:
 *   LLM_PROVIDER=anthropic (default) requires ANTHROPIC_API_KEY.
 *   Other supported values: openai, gemini, groq, openrouter.
 *   Gemini accepts GEMINI_API_KEY or GOOGLE_API_KEY.
 *   SOURCE_MODE=live requires ASTA_API_KEY. GITHUB_TOKEN is optional but recommended.
 *   The live Asta path uses the optional @modelcontextprotocol/sdk peer dependency.
 */

import { readFileSync } from 'node:fs'
import { fileURLToPath } from 'node:url'
import path from 'node:path'
import { z } from 'zod'
import { OpenMultiAgent } from '../../src/index.js'
import type { AgentConfig, OrchestratorEvent, TaskExecutionRecord } from '../../src/types.js'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const FIXTURE_DIR = path.join(__dirname, '../fixtures/paper-replication-triage')

const DEFAULT_QUERY = 'SparseCheck: Calibrated Retrieval for Low-Resource Scientific QA'
const PAPER_QUERY = process.argv[2] ?? DEFAULT_QUERY
const REPO_EVIDENCE_LIMIT = 3
const REPO_DISCOVERY_FETCH_LIMIT = 6
const SUPPORT_FILE_EXCERPT_LIMIT = 450
const README_EXCERPT_LIMIT = 1400
const ISSUE_BODY_EXCERPT_LIMIT = 360
const RELEVANT_PATH_LIMIT = 60
const ISSUE_EVIDENCE_LIMIT = 6
const DATASET_CANDIDATE_LIMIT_PER_REPO = 8
const DATASET_CANDIDATE_MIN_CONFIDENCE = 0.65
const DATASET_CONTEXT_LINE_LIMIT = 4
const DATASET_RELATED_PATH_LIMIT = 12

type SourceMode = 'mock' | 'live'
type ProviderChoice = 'anthropic' | 'openai' | 'gemini' | 'groq' | 'openrouter'
type SnippetSearchScope = 'paper_scoped' | 'global_unscoped'
type PaperMetadataScope = 'target_scoped' | 'unresolved_unscoped'

interface SourceBundle {
  mode: SourceMode
  query: string
  sourceIndex: unknown
  scholarlyMetadata: unknown
  codeArtifacts: unknown
  datasetArtifacts: unknown
  citationFeedback: unknown
  sourceDigest?: SourceDigest
}

interface SourceDigest {
  paper: {
    title: string
    url: string
    venue_or_year: string
  }
  repositories: Array<{
    repository: string
    url: string
    description: string
    relationship_hints: string[]
    useful_paths: string[]
    issue_signals: Array<{
      title: string
      url: string
    }>
  }>
  datasets: Array<{
    name: string
    evidence: string
    source: string
  }>
  dataset_snippet_mentions: string[]
  reproduction_signals: Array<{
    title: string
    url: string
    source: string
  }>
}

interface ProviderSettings {
  label: ProviderChoice
  provider: NonNullable<AgentConfig['provider']>
  model: string
  baseURL?: string
  apiKey?: string
  missingEnv?: string
}

type DatasetEvidenceKind =
  | 'cli_arg'
  | 'data_path'
  | 'repository_path'
  | 'readme_line'
  | 'support_file_line'

interface DatasetCandidateEvidence {
  name: string
  evidence_kind: string
  source_path: string
  evidence: string
  confidence: number
}

interface MCPClientLike {
  connect(transport: unknown, options?: { timeout?: number }): Promise<void>
  callTool(
    request: { name: string; arguments: Record<string, unknown> },
    resultSchema?: unknown,
    options?: { timeout?: number },
  ): Promise<unknown>
  close?: () => Promise<void>
}

interface LivePaperIdentity {
  resolvedPaperId?: string
  targetPaperMetadata?: unknown
  metadataScope: PaperMetadataScope
  note: string
}

type MCPClientConstructor = new (
  info: { name: string; version: string },
  options: { capabilities: Record<string, unknown> },
) => MCPClientLike

type StreamableHTTPClientTransportConstructor = new (
  url: URL,
  opts?: { requestInit?: RequestInit },
) => unknown

// ---------------------------------------------------------------------------
// Provider selection
// ---------------------------------------------------------------------------

function resolveProvider(): ProviderSettings {
  const raw = (process.env.LLM_PROVIDER ?? 'anthropic').toLowerCase() as ProviderChoice
  const modelOverride = process.env.LLM_MODEL

  switch (raw) {
    case 'openai':
      return {
        label: 'openai',
        provider: 'openai',
        model: modelOverride ?? 'gpt-4o-mini',
        baseURL: process.env.OPENAI_BASE_URL,
        missingEnv: process.env.OPENAI_API_KEY ? undefined : 'OPENAI_API_KEY',
      }
    case 'gemini':
      return {
        label: 'gemini',
        provider: 'gemini',
        model: modelOverride ?? 'gemini-2.5-flash',
        missingEnv: process.env.GEMINI_API_KEY || process.env.GOOGLE_API_KEY
          ? undefined
          : 'GEMINI_API_KEY or GOOGLE_API_KEY',
      }
    case 'groq':
      return {
        label: 'groq',
        provider: 'openai',
        baseURL: 'https://api.groq.com/openai/v1',
        apiKey: process.env.GROQ_API_KEY,
        model: modelOverride ?? 'llama-3.3-70b-versatile',
        missingEnv: process.env.GROQ_API_KEY ? undefined : 'GROQ_API_KEY',
      }
    case 'openrouter':
      return {
        label: 'openrouter',
        provider: 'openai',
        baseURL: 'https://openrouter.ai/api/v1',
        apiKey: process.env.OPENROUTER_API_KEY,
        model: modelOverride ?? 'openai/gpt-4o-mini',
        missingEnv: process.env.OPENROUTER_API_KEY ? undefined : 'OPENROUTER_API_KEY',
      }
    case 'anthropic':
    default:
      return {
        label: 'anthropic',
        provider: 'anthropic',
        model: modelOverride ?? 'claude-sonnet-4-6',
        missingEnv: process.env.ANTHROPIC_API_KEY ? undefined : 'ANTHROPIC_API_KEY',
      }
  }
}

const PROVIDER = resolveProvider()

// ---------------------------------------------------------------------------
// Source loading
// ---------------------------------------------------------------------------

function readJson<T = unknown>(name: string): T {
  const filePath = path.join(FIXTURE_DIR, name)
  return JSON.parse(readFileSync(filePath, 'utf-8')) as T
}

function resolveSourceMode(): SourceMode {
  const raw = (process.env.SOURCE_MODE ?? 'mock').toLowerCase()
  if (raw === 'live') return 'live'
  if (raw !== 'mock') {
    console.warn(`[warn] Unknown SOURCE_MODE=${raw}; falling back to mock snapshots.`)
  }
  return 'mock'
}

function loadMockSourceBundle(query: string): SourceBundle {
  return {
    mode: 'mock',
    query,
    sourceIndex: readJson('source-index.json'),
    scholarlyMetadata: readJson('scholarly-metadata.json'),
    codeArtifacts: readJson('code-artifacts.json'),
    datasetArtifacts: readJson('dataset-artifacts.json'),
    citationFeedback: readJson('citation-feedback.json'),
  }
}

async function fetchJson<T>(url: string, headers: Record<string, string> = {}): Promise<T | undefined> {
  try {
    const response = await fetch(url, { headers })
    if (!response.ok) {
      return undefined
    }
    return await response.json() as T
  } catch {
    return undefined
  }
}

async function fetchText(url: string, headers: Record<string, string> = {}): Promise<string | undefined> {
  try {
    const response = await fetch(url, { headers })
    if (!response.ok) {
      return undefined
    }
    return await response.text()
  } catch {
    return undefined
  }
}

function getString(record: Record<string, unknown>, key: string): string | undefined {
  const value = record[key]
  return typeof value === 'string' ? value : undefined
}

function getNumber(record: Record<string, unknown>, key: string): number | undefined {
  const value = record[key]
  return typeof value === 'number' ? value : undefined
}

function compactText(text: string, maxLength = 180): string {
  const compacted = text.replace(/\s+/g, ' ').trim()
  return compacted.length > maxLength ? `${compacted.slice(0, maxLength - 3)}...` : compacted
}

function uniqueStrings(values: string[], limit = values.length): string[] {
  const seen = new Set<string>()
  const result: string[] = []
  for (const value of values) {
    const normalized = value.trim()
    if (!normalized || seen.has(normalized.toLowerCase())) continue
    seen.add(normalized.toLowerCase())
    result.push(normalized)
    if (result.length >= limit) break
  }
  return result
}

function normalizeTitleForCompare(title: string): string {
  return title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
}

function compactSearchItem(item: Record<string, unknown>): Record<string, unknown> {
  return {
    full_name: getString(item, 'full_name'),
    html_url: getString(item, 'html_url'),
    description: getString(item, 'description'),
    stargazers_count: getNumber(item, 'stargazers_count'),
    pushed_at: getString(item, 'pushed_at'),
    default_branch: getString(item, 'default_branch'),
  }
}

function collectStrings(value: unknown, acc: string[] = []): string[] {
  if (typeof value === 'string') {
    acc.push(value)
    return acc
  }
  if (Array.isArray(value)) {
    for (const item of value) collectStrings(item, acc)
    return acc
  }
  if (value !== null && typeof value === 'object') {
    for (const child of Object.values(value as Record<string, unknown>)) {
      collectStrings(child, acc)
    }
  }
  return acc
}

function findFirstNumberByKey(value: unknown, keyName: string): number | undefined {
  if (value === null || typeof value !== 'object') return undefined
  if (Array.isArray(value)) {
    for (const item of value) {
      const found = findFirstNumberByKey(item, keyName)
      if (found !== undefined) return found
    }
    return undefined
  }

  const record = value as Record<string, unknown>
  const direct = record[keyName]
  if (typeof direct === 'number') return direct

  for (const child of Object.values(record)) {
    const found = findFirstNumberByKey(child, keyName)
    if (found !== undefined) return found
  }
  return undefined
}

function findFirstStringByKey(value: unknown, keyName: string): string | undefined {
  if (value === null || typeof value !== 'object') return undefined
  if (Array.isArray(value)) {
    for (const item of value) {
      const found = findFirstStringByKey(item, keyName)
      if (found) return found
    }
    return undefined
  }

  const record = value as Record<string, unknown>
  const direct = record[keyName]
  if (typeof direct === 'string' && direct.trim() !== '') return direct

  for (const child of Object.values(record)) {
    const found = findFirstStringByKey(child, keyName)
    if (found) return found
  }
  return undefined
}

function extractCandidateTerms(text: string): string[] {
  const stop = new Set([
    'the',
    'and',
    'for',
    'with',
    'from',
    'that',
    'this',
    'paper',
    'using',
    'based',
    'model',
    'models',
    'method',
    'methods',
    'learning',
  ])
  const terms = new Set<string>()
  const hyphenated = text.match(/\b[A-Za-z][A-Za-z0-9]*(?:[-_][A-Za-z0-9]+)+\b/g) ?? []
  const acronyms = text.match(/\b[A-Z][A-Z0-9]{2,}\b/g) ?? []

  for (const term of [...hyphenated, ...acronyms]) {
    const normalized = term.trim()
    if (normalized.length < 3 || normalized.length > 40) continue
    if (stop.has(normalized.toLowerCase())) continue
    terms.add(normalized)
  }

  return Array.from(terms).slice(0, 6)
}

function extractGithubRepoFullNames(value: unknown): string[] {
  const text = collectStrings(value).join('\n')
  const matches = text.matchAll(/https?:\/\/github\.com\/([A-Za-z0-9_.-]+\/[A-Za-z0-9_.-]+)/g)
  const repos = new Set<string>()
  for (const match of matches) {
    repos.add(match[1].replace(/\.git$/i, ''))
  }
  return Array.from(repos).slice(0, 5)
}

function buildGitHubSearchQueries(query: string, targetPaperMetadata: unknown): string[] {
  const title = findFirstStringByKey(targetPaperMetadata, 'title')
  const text = collectStrings(targetPaperMetadata).join('\n')
  const queries = new Set<string>()

  for (const candidate of [title, query]) {
    const trimmed = candidate?.trim()
    if (!trimmed) continue
    queries.add(`"${trimmed}" in:readme`)
    queries.add(`${trimmed} in:name,readme`)
  }

  for (const term of extractCandidateTerms(text)) {
    queries.add(`${term} in:name,readme`)
  }

  return Array.from(queries).slice(0, 8)
}

function textContainsNormalizedPhrase(text: string, phrase: string): boolean {
  const normalizedPhrase = normalizeTitleForCompare(phrase)
  if (normalizedPhrase.length < 3) return false
  return normalizeTitleForCompare(text).includes(normalizedPhrase)
}

function textMentionsTarget(text: string, target: string): boolean {
  if (textContainsNormalizedPhrase(text, target)) return true

  const terms = extractCandidateTerms(target)
  return terms.some((term) => {
    const pattern = new RegExp(`(^|[^A-Za-z0-9])${escapeRegExp(term)}([^A-Za-z0-9]|$)`, 'i')
    return pattern.test(text)
  })
}

function textWindow(text: string, index: number, before = 240, after = 240): string {
  return text.slice(Math.max(0, index - before), Math.min(text.length, index + after))
}

function hasNegatedOfficialPrefix(text: string, index: number, matchLength: number): boolean {
  const local = text.slice(Math.max(0, index - 48), index + matchLength).toLowerCase()
  return /\b(?:un|non)[-\s]?official\b/.test(local)
    || /\bnot\s+(?:an?\s+|the\s+)?official\b/.test(local)
    || /\bno\s+official\b/.test(local)
    || /\bwithout\s+(?:an?\s+|the\s+)?official\b/.test(local)
}

function nonOfficialClaimNearTarget(text: string, target: string | undefined): boolean {
  const nonOfficialPattern =
    /\b(?:(?:un|non)[-\s]?official|third[-\s]?party|community|independent)\s+(?:implementation|code|repo(?:sitory)?|release|reproduction)\b|\bnot\s+(?:an?\s+|the\s+)?official\s+(?:implementation|code|repo(?:sitory)?|release)\b/gi
  const matches = [...text.matchAll(nonOfficialPattern)]
  if (matches.length === 0) return false
  if (!target) return true

  return matches.some((match) => {
    const index = match.index ?? 0
    return textMentionsTarget(textWindow(text, index), target)
  })
}

function officialClaimNearTarget(text: string, target: string | undefined): boolean {
  const officialPattern =
    /\bofficial(?:\s+(?:implementation|code|repo(?:sitory)?|github|release))?\b|\bauthors?['’]?\s+(?:implementation|code|repo(?:sitory)?|release)\b/gi
  const matches = [...text.matchAll(officialPattern)]
  if (matches.length === 0) return false

  return matches.some((match) => {
    const index = match.index ?? 0
    const matchText = match[0] ?? ''
    if (hasNegatedOfficialPrefix(text, index, matchText.length)) return false
    if (!target) return true
    return textMentionsTarget(textWindow(text, index), target)
  })
}

async function fetchGitHubSearch(
  rawQuery: string,
  headers: Record<string, string>,
): Promise<Record<string, unknown> | undefined> {
  return fetchJson<Record<string, unknown>>(
    `https://api.github.com/search/repositories?q=${encodeURIComponent(rawQuery)}&per_page=5`,
    headers,
  )
}

function rawGitHubFileUrl(fullName: string, branch: string, filePath: string): string {
  const encodedBranch = branch.split('/').map(encodeURIComponent).join('/')
  const encodedPath = filePath.split('/').map(encodeURIComponent).join('/')
  return `https://raw.githubusercontent.com/${fullName}/${encodedBranch}/${encodedPath}`
}

function scoreSupportFilePath(filePath: string): number {
  if (/package-lock\.json|pnpm-lock\.yaml|yarn\.lock|\.png$|\.jpg$|\.jpeg$|\.gif$/i.test(filePath)) return 0

  let score = 0
  if (/README/i.test(filePath)) score += 4
  if (/(^|\/)scripts?\//i.test(filePath)) score += 5
  if (/(^|\/)(configs?|experiments?)\//i.test(filePath)) score += 4
  if (/(^|\/)(data|datasets?|download|prepare|preprocess)/i.test(filePath)) score += 4
  if (/(train|training|eval|evaluation|metrics?|run|launch)/i.test(filePath)) score += 3
  if (/\.(sh|py|yaml|yml|json|md)$/i.test(filePath)) score += 2
  return score
}

function selectSupportFilePaths(paths: string[]): string[] {
  return paths
    .filter((filePath) =>
      /README|scripts?|configs?|experiments?|data|datasets?|download|prepare|preprocess|train|training|eval|evaluation|metrics?|run|launch/i.test(filePath)
      || /\.(sh|py|yaml|yml|json|md)$/i.test(filePath),
    )
    .map((filePath) => ({ filePath, score: scoreSupportFilePath(filePath) }))
    .filter((item) => item.score > 0)
    .sort((a, b) => b.score - a.score || a.filePath.localeCompare(b.filePath))
    .map((item) => item.filePath)
    .slice(0, 4)
}

const DATASET_NAME_STOPWORDS = new Set([
  'a',
  'an',
  'and',
  'arg',
  'args',
  'benchmark',
  'benchmarks',
  'benchmark.md',
  'config',
  'custom',
  'data',
  'dataset',
  'datasets',
  'data_path',
  'default',
  'download',
  'driven',
  'feature',
  'features',
  'file',
  'input',
  'input_size',
  'label',
  'loader',
  'main',
  'model',
  'path',
  'predict',
  'predict_step',
  'processed',
  'readme',
  'readme.md',
  'root',
  'root_path',
  'script',
  'target',
  'task',
  'task_id',
  'term',
  'then',
  'test',
  'the',
  'train',
  'training',
  'valid',
  'validation',
])

function normalizeDatasetCandidate(raw: string, evidenceKind: DatasetEvidenceKind): string | undefined {
  const fromPath = raw.split(/[\\/]/).filter(Boolean).at(-1) ?? raw
  const cleaned = fromPath
    .replace(/^[-/\s]+/, '')
    .replace(/\.(csv|tsv|txt|npy|npz|pkl|h5|json|md|py|sh|yaml|yml)$/i, '')
    .replace(/["'`),\]]+$/g, '')
    .replace(/^\[|\]$/g, '')
    .trim()
  if (cleaned.length < 3 || cleaned.length > 60) return undefined
  if (cleaned.includes('=')) return undefined
  if (/^-/.test(cleaned)) return undefined

  const lower = cleaned.toLowerCase()
  if (DATASET_NAME_STOPWORDS.has(lower)) return undefined
  if (/^(arg|args|cfg|config|param|kwargs?)[_.-]/i.test(cleaned)) return undefined
  if (/(^|_)(path|size|len|length|step|id|type|flag|mode|root|features?)$/i.test(cleaned)) return undefined
  if (/^\d+$/.test(cleaned)) return undefined

  const highPrecisionSource = evidenceKind === 'cli_arg'
    || evidenceKind === 'data_path'
    || evidenceKind === 'repository_path'
  const hasDigit = /\d/.test(cleaned)
  const isAcronym = /^[A-Z][A-Z0-9-]{2,}$/.test(cleaned)
  const isMixedCaseIdentifier = /^[A-Z][A-Za-z]+[A-Z0-9][A-Za-z0-9-]*$/.test(cleaned)
  const isCompoundDatasetLike = /^[A-Z][A-Za-z0-9]+(?:[-_][A-Za-z0-9]+)+$/.test(cleaned)
  const isTitleCaseWord = /^[A-Z][a-z][A-Za-z0-9-]{2,}$/.test(cleaned)
  const isPlainLowercaseWord = /^[a-z][a-z0-9-]{2,}$/.test(cleaned)
  const looksLikeMethodOrVenue = /(?:benchmark|baseline|linear|transformer|former|forecast|lookback|window|aaai|neurips|icml|iclr|acl|cvpr|emnlp)$/i.test(cleaned)
    || /(?:benchmark|linear|transformer|former|forecasting|lookback|window)/i.test(cleaned)
  const isAmbiguousShortAcronym = isAcronym && cleaned.length <= 3 && !highPrecisionSource
  const isLongAcronym = isAcronym && cleaned.length > 3

  if (isAmbiguousShortAcronym) return undefined
  if (looksLikeMethodOrVenue && !['cli_arg', 'data_path'].includes(evidenceKind)) return undefined

  if (
    !hasDigit
    && !isLongAcronym
    && !isMixedCaseIdentifier
    && !isCompoundDatasetLike
    && !isTitleCaseWord
    && !(highPrecisionSource && isPlainLowercaseWord)
  ) {
    return undefined
  }

  return cleaned
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
}

function datasetEvidenceBaseConfidence(evidenceKind: DatasetEvidenceKind): number {
  switch (evidenceKind) {
    case 'cli_arg':
      return 0.72
    case 'data_path':
      return 0.68
    case 'repository_path':
      return 0.58
    case 'support_file_line':
      return 0.54
    case 'readme_line':
      return 0.54
  }
}

function datasetEvidenceConfidence(
  name: string,
  evidenceKind: DatasetEvidenceKind,
  evidence: string,
): number {
  let confidence = datasetEvidenceBaseConfidence(evidenceKind)
  if (new RegExp(`(^|[^A-Za-z0-9])${escapeRegExp(name)}\\.(csv|tsv|txt|npy|npz|pkl|h5|json)([^A-Za-z0-9]|$)`, 'i').test(evidence)) {
    confidence += 0.12
  }
  if (/dataset|benchmark|download|split|train|test|validation/i.test(evidence)) {
    confidence += 0.08
  }
  if (/--data(?:set)?|--data_path|data_path|root_path/i.test(evidence)) {
    confidence += 0.08
  }
  return Math.min(0.95, Number(confidence.toFixed(2)))
}

function makeDatasetCandidateEvidence(
  rawName: string,
  evidenceKind: DatasetEvidenceKind,
  sourcePath: string,
  evidence: string,
): DatasetCandidateEvidence | undefined {
  const name = normalizeDatasetCandidate(rawName, evidenceKind)
  if (!name) return undefined
  return {
    name,
    evidence_kind: evidenceKind,
    source_path: sourcePath,
    evidence: compactText(evidence, 220),
    confidence: datasetEvidenceConfidence(name, evidenceKind, evidence),
  }
}

function extractDatasetCandidateEvidenceFromText(
  text: string,
  sourcePath: string,
  defaultEvidenceKind: DatasetEvidenceKind,
): DatasetCandidateEvidence[] {
  const candidates: DatasetCandidateEvidence[] = []
  const patterns: Array<{ kind: DatasetEvidenceKind, regex: RegExp }> = [
    { kind: 'cli_arg', regex: /--data(?:set)?(?:\s+|=)["']?([A-Za-z0-9_.-]{3,60})/gi },
    { kind: 'data_path', regex: /--data_path(?:\s+|=)["']?([A-Za-z0-9_./-]+\.(?:csv|tsv|txt|npy|npz|pkl|h5|json))/gi },
    { kind: 'data_path', regex: /\b(?:data_path|filename|file_name|target_file)\s*[:=]\s*["']?([A-Za-z0-9_./-]+\.(?:csv|tsv|txt|npy|npz|pkl|h5|json))/gi },
    { kind: defaultEvidenceKind, regex: /\b(?:dataset|data source|data file|benchmark dataset|dataset name)\b[^\n:=]{0,24}[:=]\s*["'`]?([A-Za-z0-9_.-]{3,60})/gi },
    { kind: 'repository_path', regex: /(?:^|\/)(?:data|datasets?)\/([A-Za-z0-9_.-]{3,60})(?:\/|\.|$)/gi },
  ]

  for (const { kind, regex } of patterns) {
    for (const match of text.matchAll(regex)) {
      const raw = match[1]
      if (!raw) continue
      const candidate = makeDatasetCandidateEvidence(raw, kind, sourcePath, match[0])
      if (candidate) candidates.push(candidate)
    }
  }

  return candidates
}

function extractDatasetCandidateEvidenceFromPaths(paths: string[]): DatasetCandidateEvidence[] {
  const candidates: DatasetCandidateEvidence[] = []
  for (const filePath of paths) {
    const pathParts = filePath.split('/').filter(Boolean)
    const datasetDirIndex = pathParts.findIndex((part) => /^datasets?$/i.test(part))
    if (datasetDirIndex >= 0 && pathParts[datasetDirIndex + 1]) {
      const candidate = makeDatasetCandidateEvidence(pathParts[datasetDirIndex + 1], 'repository_path', filePath, filePath)
      if (candidate) candidates.push(candidate)
    }

    const basename = pathParts.at(-1) ?? filePath
    if (/\.(csv|tsv|txt|npy|npz|pkl|h5|json)$/i.test(basename) && /(^|\/)(data|datasets?|benchmark)/i.test(filePath)) {
      const candidate = makeDatasetCandidateEvidence(basename, 'data_path', filePath, filePath)
      if (candidate) candidates.push(candidate)
    }

    if (/(^|\/)(scripts?|experiments?)\//i.test(filePath) && /\.(sh|py|yaml|yml|json)$/i.test(basename)) {
      const candidate = makeDatasetCandidateEvidence(basename, 'repository_path', filePath, filePath)
      if (candidate) candidates.push(candidate)
    }
  }
  return candidates
}

function summarizeDatasetCandidates(
  evidenceItems: DatasetCandidateEvidence[],
  limit = DATASET_CANDIDATE_LIMIT_PER_REPO,
): DatasetCandidateEvidence[] {
  const byName = new Map<string, DatasetCandidateEvidence & { evidence_count: number }>()

  for (const item of evidenceItems) {
    const key = item.name.toLowerCase()
    const current = byName.get(key)
    if (!current) {
      byName.set(key, { ...item, evidence_count: 1 })
      continue
    }

    const sourceKinds = new Set(current.evidence_kind.split('+'))
    sourceKinds.add(item.evidence_kind)
    current.evidence_kind = Array.from(sourceKinds).join('+')
    current.evidence_count += 1
    current.confidence = Math.min(
      0.98,
      Number((Math.max(current.confidence, item.confidence) + Math.min(0.2, current.evidence_count * 0.04)).toFixed(2)),
    )
    if (!current.evidence.includes(item.evidence)) {
      current.evidence = compactText(`${current.evidence} | ${item.evidence}`, 260)
    }
    if (!current.source_path.includes(item.source_path)) {
      current.source_path = compactText(`${current.source_path}; ${item.source_path}`, 180)
    }
  }

  return Array.from(byName.values())
    .filter((item) =>
      item.confidence >= DATASET_CANDIDATE_MIN_CONFIDENCE
      || (item.evidence_count >= 2 && item.confidence >= 0.58),
    )
    .sort((a, b) => b.confidence - a.confidence || a.name.localeCompare(b.name))
    .map(({ evidence_count: _evidenceCount, ...item }) => item)
    .slice(0, limit)
}

function extractDatasetMentionsFromAstaSnippets(value: unknown): string[] {
  const mentions: string[] = []
  const text = collectStrings(value)
    .filter((item) => /dataset|benchmark|forecast|time[- ]series|long[- ]term|experiment|result/i.test(item))
    .join('\n')
  const contextPatterns = [
    /\b(?:on|across|over|using|with|from)\s+([A-Za-z][A-Za-z0-9_.-]{2,60}(?:\s*(?:,|and|\/)\s*[A-Za-z][A-Za-z0-9_.-]{2,60}){0,6})/gi,
    /\b(?:datasets?|benchmarks?)\s*(?:include|includes|including|are|:)\s+([A-Za-z][A-Za-z0-9_.-]{2,60}(?:\s*(?:,|and|\/)\s*[A-Za-z][A-Za-z0-9_.-]{2,60}){0,10})/gi,
  ]

  for (const pattern of contextPatterns) {
    for (const match of text.matchAll(pattern)) {
      const list = match[1] ?? ''
      for (const rawName of list.split(/\s*(?:,|and|\/)\s*/)) {
        const candidate = normalizeDatasetCandidate(rawName, 'readme_line')
        if (candidate) mentions.push(candidate)
      }
    }
  }

  return uniqueStrings(mentions, 12)
}

async function fetchGitHubRepoEvidence(
  input: Record<string, unknown> | string,
  headers: Record<string, string>,
  sourceQuery?: string,
): Promise<Record<string, unknown> | undefined> {
  const fullName = typeof input === 'string' ? input : getString(input, 'full_name')
  if (!fullName) return undefined

  const apiBase = `https://api.github.com/repos/${fullName}`
  const issueQueries = ['reproduce', 'reproduction', 'result', 'dataset', 'metric']
  const repo = typeof input === 'string'
    ? await fetchJson<Record<string, unknown>>(apiBase, headers)
    : input
  const repoRecord = repo ?? (typeof input === 'string' ? { full_name: input } : input)
  const defaultBranch = getString(repoRecord, 'default_branch') ?? 'main'

  const [readme, tree, issueSearches] = await Promise.all([
    fetchText(`${apiBase}/readme`, {
      ...headers,
      Accept: 'application/vnd.github.raw',
    }),
    fetchJson<Record<string, unknown>>(
      `${apiBase}/git/trees/${encodeURIComponent(defaultBranch)}?recursive=1`,
      headers,
    ),
    Promise.all(
      issueQueries.map((term) =>
        fetchJson<Record<string, unknown>>(
          'https://api.github.com/search/issues?q=' +
          encodeURIComponent(`repo:${fullName} ${term} in:title,body type:issue`) +
          '&per_page=2',
          headers,
        ),
      ),
    ),
  ])

  const treeItems = Array.isArray(tree?.['tree'])
    ? tree['tree'] as Array<Record<string, unknown>>
    : []
  const treeTruncated = tree?.['truncated'] === true
  const paths = treeItems
    .map((entry) => getString(entry, 'path'))
    .filter((pathValue): pathValue is string => pathValue !== undefined)

  const relevantPaths = paths
    .filter((pathValue) =>
      /(^|\/)(scripts?|experiments?|configs?|data|datasets?|train|training|eval|evaluation|README|requirements|environment|Dockerfile)/i.test(pathValue)
      || /\.(sh|py|yaml|yml|json)$/i.test(pathValue),
    )
    .slice(0, RELEVANT_PATH_LIMIT)

  const supportFilePaths = selectSupportFilePaths(paths)
  const supportFileExcerpts = await Promise.all(
    supportFilePaths.map(async (filePath) => {
      const url = rawGitHubFileUrl(fullName, defaultBranch, filePath)
      const text = await fetchText(url, headers)
      return {
        path: filePath,
        raw_url: url,
        excerpt: text ? compactText(text, SUPPORT_FILE_EXCERPT_LIMIT) : 'unavailable',
      }
    }),
  )

  const issueByUrl = new Map<string, Record<string, unknown>>()
  for (const issueSearch of issueSearches) {
    if (!Array.isArray(issueSearch?.['items'])) continue
    for (const issue of issueSearch['items'] as Array<Record<string, unknown>>) {
      const url = getString(issue, 'html_url')
      if (url) issueByUrl.set(url, issue)
    }
  }

  const issues = Array.from(issueByUrl.values()).slice(0, ISSUE_EVIDENCE_LIMIT).map((issue) => ({
    title: getString(issue, 'title'),
    html_url: getString(issue, 'html_url'),
    state: getString(issue, 'state'),
    created_at: getString(issue, 'created_at'),
    body_excerpt: getString(issue, 'body')?.slice(0, ISSUE_BODY_EXCERPT_LIMIT),
  }))

  const readmeText = readme ?? ''
  const repoIdentityText = [
    fullName,
    getString(repoRecord, 'description') ?? '',
    readmeText,
  ].join('\n')
  const linkedFromPaperMetadata = sourceQuery === 'github-url-from-paper-metadata'
  const targetQuery = linkedFromPaperMetadata ? undefined : sourceQuery
  const hasOfficialClaim = officialClaimNearTarget(readmeText, undefined)
  const officialForTarget = targetQuery ? officialClaimNearTarget(readmeText, targetQuery) : hasOfficialClaim
  const nonOfficialForTarget = targetQuery
    ? nonOfficialClaimNearTarget(readmeText, targetQuery)
    : nonOfficialClaimNearTarget(readmeText, undefined)
  const repoRelationshipHints = {
    linked_from_paper_metadata: linkedFromPaperMetadata,
    mentions_query_or_title: targetQuery ? textMentionsTarget(repoIdentityText, targetQuery) : false,
    mentions_official: officialForTarget,
    official_claim_context_unclear: hasOfficialClaim && !officialForTarget,
    explicit_non_official_claim: nonOfficialForTarget,
    mentions_reproduction: /reproduc|replicat|results?|benchmark/i.test(readmeText),
    mentions_datasets: /dataset|data preparation|download data|benchmark data/i.test(readmeText),
  }

  const datasetCandidateEvidence = summarizeDatasetCandidates(
    [
      ...extractDatasetCandidateEvidenceFromText(readmeText, 'README.md', 'readme_line'),
      ...extractDatasetCandidateEvidenceFromPaths(relevantPaths),
      ...supportFileExcerpts.flatMap((item) =>
        extractDatasetCandidateEvidenceFromText(item.excerpt, item.path, 'support_file_line'),
      ),
    ],
  )
  const datasetMentions = datasetCandidateEvidence.map((candidate) => candidate.name)

  return {
    ...compactSearchItem(repoRecord),
    html_url: getString(repoRecord, 'html_url') ?? `https://github.com/${fullName}`,
    source_query: sourceQuery,
    repo_relationship_hints: repoRelationshipHints,
    readme_excerpt: readme ? readme.slice(0, README_EXCERPT_LIMIT) : 'README unavailable',
    tree_truncated: treeTruncated,
    tree_truncation_note: treeTruncated
      ? 'GitHub recursive tree response was truncated; relevant_paths and dataset/code clues may be incomplete.'
      : undefined,
    relevant_paths: relevantPaths,
    support_file_excerpts: supportFileExcerpts,
    dataset_mentions: datasetMentions,
    dataset_candidate_evidence: datasetCandidateEvidence,
    issue_search_results: issues,
  }
}

function buildDatasetCluesFromRepos(repoEvidence: Array<Record<string, unknown> | undefined>): Array<Record<string, unknown>> {
  const clues: Array<Record<string, unknown>> = []

  for (const repo of repoEvidence) {
    if (!repo) continue
    const paths = Array.isArray(repo['relevant_paths'])
      ? repo['relevant_paths'].filter((pathValue): pathValue is string => typeof pathValue === 'string')
      : []
    const datasetPaths = paths
      .filter((pathValue) => /(^|\/)(data|datasets?|download|prepare|preprocess)/i.test(pathValue))
      .slice(0, DATASET_RELATED_PATH_LIMIT)

    const datasetMentions = Array.isArray(repo['dataset_mentions'])
      ? repo['dataset_mentions'].filter((name): name is string => typeof name === 'string')
      : []
    const datasetCandidateEvidence = Array.isArray(repo['dataset_candidate_evidence'])
      ? repo['dataset_candidate_evidence']
        .filter((item): item is Record<string, unknown> => item !== null && typeof item === 'object')
        .slice(0, DATASET_CANDIDATE_LIMIT_PER_REPO)
      : []
    const supportFiles = Array.isArray(repo['support_file_excerpts'])
      ? repo['support_file_excerpts'].filter((item): item is Record<string, unknown> => item !== null && typeof item === 'object')
      : []
    const readme = typeof repo['readme_excerpt'] === 'string' ? repo['readme_excerpt'] : ''
    const datasetLines = readme
      .split(/\r?\n/)
      .filter((line) => /dataset|data|download|benchmark|split|train|test/i.test(line))
      .slice(0, DATASET_CONTEXT_LINE_LIMIT)
    const supportFileDatasetLines = supportFiles.flatMap((item) => {
      const excerpt = typeof item['excerpt'] === 'string' ? item['excerpt'] : ''
      const filePath = typeof item['path'] === 'string' ? item['path'] : 'unknown file'
      return excerpt
        .split(/\r?\n|;/)
        .filter((line) => /dataset|data_path|root_path|download|split|train|test/i.test(line))
        .slice(0, 2)
        .map((line) => `${filePath}: ${compactText(line, 120)}`)
    }).slice(0, DATASET_CONTEXT_LINE_LIMIT * 2)

    if (
      datasetPaths.length > 0
      || datasetLines.length > 0
      || datasetMentions.length > 0
      || datasetCandidateEvidence.length > 0
      || supportFileDatasetLines.length > 0
    ) {
      clues.push({
        repository: repo['full_name'],
        repository_url: repo['html_url'],
        repository_relationship_hints: summarizeRelationshipHints(repo['repo_relationship_hints']),
        target_tied_repository: repoIsTargetTied(repo),
        dataset_mentions: datasetMentions,
        dataset_candidate_evidence: datasetCandidateEvidence,
        dataset_related_paths: datasetPaths,
        readme_dataset_lines: datasetLines,
        support_file_dataset_lines: supportFileDatasetLines,
      })
    }
  }

  return clues
}

function collectRecordsWithTitle(value: unknown, acc: Array<Record<string, unknown>> = []): Array<Record<string, unknown>> {
  if (isUnavailableSourcePayload(value)) return acc
  if (value === null || typeof value !== 'object') return acc
  if (Array.isArray(value)) {
    for (const item of value) collectRecordsWithTitle(item, acc)
    return acc
  }

  const record = value as Record<string, unknown>
  if (typeof record['title'] === 'string' && record['title'].trim() !== '') {
    acc.push(record)
  }
  for (const [key, child] of Object.entries(record)) {
    if (NON_EVIDENCE_PAYLOAD_KEYS.has(key.toLowerCase())) continue
    collectRecordsWithTitle(child, acc)
  }
  return acc
}

function isUnavailableSourcePayload(value: unknown): boolean {
  if (value === null || typeof value !== 'object' || Array.isArray(value)) return false
  const record = value as Record<string, unknown>
  return record['is_error'] === true || record['source_unavailable'] === true
}

const NON_EVIDENCE_PAYLOAD_KEYS = new Set([
  'args',
  'arguments',
  'count',
  'incomplete_results',
  'is_error',
  'limit',
  'message',
  'next_cursor',
  'note',
  'offset',
  'page',
  'query',
  'reason',
  'request',
  'source',
  'source_unavailable',
  'status',
  'success',
  'total',
  'total_count',
  'type',
])

function hasSuccessfulSourcePayload(value: unknown): boolean {
  if (value === null || value === undefined) return false
  if (typeof value === 'string') return value.trim().length > 0
  if (typeof value === 'boolean') return value
  if (typeof value === 'number') return Number.isFinite(value)
  if (Array.isArray(value)) return value.some(hasSuccessfulSourcePayload)
  if (typeof value !== 'object') return false
  if (isUnavailableSourcePayload(value)) return false

  const evidenceEntries = Object.entries(value as Record<string, unknown>)
    .filter(([key]) => !NON_EVIDENCE_PAYLOAD_KEYS.has(key.toLowerCase()))
  return evidenceEntries.some(([, child]) => hasSuccessfulSourcePayload(child))
}

function collectSourceEvidenceStrings(value: unknown, acc: string[] = []): string[] {
  if (isUnavailableSourcePayload(value)) return acc
  if (typeof value === 'string') {
    acc.push(value)
    return acc
  }
  if (Array.isArray(value)) {
    for (const item of value) collectSourceEvidenceStrings(item, acc)
    return acc
  }
  if (value !== null && typeof value === 'object') {
    for (const [key, child] of Object.entries(value as Record<string, unknown>)) {
      if (NON_EVIDENCE_PAYLOAD_KEYS.has(key.toLowerCase())) continue
      collectSourceEvidenceStrings(child, acc)
    }
  }
  return acc
}

function sourceEvidenceText(...values: unknown[]): string {
  return uniqueStrings(
    values.flatMap((value) => collectSourceEvidenceStrings(value).map((item) => compactText(item, 500))),
    120,
  ).join('\n')
}

function hasReproductionFeedbackSignal(record: Record<string, unknown>): boolean {
  return /\b(?:reproduc|replicat|reimplement|re-implement|rerun|result mismatch|cannot reproduce|fail(?:ed)? to reproduce|metric mismatch|benchmark|evaluation protocol|code availability|data availability|artifact)\b/i
    .test(sourceEvidenceText(record))
}

function sourceHasReproductionFeedbackSignal(value: unknown): boolean {
  return collectRecordsWithTitle(value).some(hasReproductionFeedbackSignal)
}

function firstContextMatch(text: string, patterns: RegExp[], maxLength = 280): string | undefined {
  for (const pattern of patterns) {
    const match = pattern.exec(text)
    pattern.lastIndex = 0
    if (!match || match.index === undefined) continue

    const start = Math.max(0, match.index - 140)
    const end = Math.min(text.length, match.index + match[0].length + 140)
    return compactText(text.slice(start, end), maxLength)
  }
  return undefined
}

function findDatasetRestrictionEvidence(text: string): string | undefined {
  const datasetContext = /\b(?:dataset|datasets|data set|split|splits|holdout|benchmark|leaderboard|labels?|annotations?|download|data access)\b/i
  const restrictionSignal = /\b(?:restricted|requires? approval|approval[- ]?gated|apply|application|private|hidden|permission|not public|unavailable|non-commercial|noncommercial|terms of use)\b/i
  const paperLicenseNotice = /\b(?:snippet is extracted|open access paper|paper or abstract|copyright owner|license by the author|source to verify the license|copyright information)\b/i

  for (const segment of text.split(/\r?\n|(?<=[.!?])\s+/)) {
    const normalized = compactText(segment, 320)
    if (!normalized || paperLicenseNotice.test(normalized)) continue
    if (datasetContext.test(normalized) && restrictionSignal.test(normalized)) {
      return normalized
    }
  }

  return undefined
}

function extractGithubUrls(text: string): string[] {
  return uniqueStrings(
    [...text.matchAll(/https?:\/\/github\.com\/[A-Za-z0-9_.-]+\/[A-Za-z0-9_.-]+/g)]
      .map((match) => match[0].replace(/[).,;]+$/g, '')),
    5,
  )
}

function extractMetricNames(text: string): string[] {
  return uniqueStrings(
    [...text.matchAll(/\b(?:macro[- ]?F1|micro[- ]?F1|F1|accuracy|exact match|EM|BLEU|ROUGE|MSE|MAE|RMSE|AUROC|AUC)\b/gi)]
      .map((match) => match[0]),
    8,
  )
}

function extractedClaim(
  claim: string,
  evidence: string | undefined,
  sourceDescription = 'Asta paper metadata or paper-scoped snippets',
): Record<string, string> {
  return evidence
    ? { status: 'found', claim, evidence }
    : {
      status: 'not_found_in_asta_sources',
      claim: `No explicit claim found in ${sourceDescription}.`,
      evidence: `Asta did not surface enough target-paper text from ${sourceDescription} for this claim type.`,
    }
}

function extractedUnscopedEvidence(
  evidenceType: string,
  evidence: string | undefined,
): Record<string, string> {
  return evidence
    ? {
      status: 'unscoped_evidence',
      evidence_scope: 'global_snippet_search',
      note: `${evidenceType} surfaced in global Asta snippets, but no paper_id was resolved; do not treat this as a target-paper claim without corroboration.`,
      evidence,
    }
    : {
      status: 'not_found_in_global_snippets',
      evidence_scope: 'global_snippet_search',
      note: `No ${evidenceType.toLowerCase()} surfaced in the unscoped Asta snippets.`,
      evidence: 'Asta global snippet_search did not return a matching evidence segment.',
    }
}

function extractLiveClaimEvidence(text: string) {
  const githubUrls = extractGithubUrls(text)
  const metricNames = extractMetricNames(text)

  const codeEvidence = githubUrls.length > 0
    ? firstContextMatch(text, [/https?:\/\/github\.com\/[A-Za-z0-9_.-]+\/[A-Za-z0-9_.-]+/i])
    : firstContextMatch(text, [
      /\b(?:code|source code|implementation|repository)\b.{0,120}\b(?:available|released|public|github)\b/i,
      /\b(?:available|released|public)\b.{0,120}\b(?:code|source code|implementation|repository)\b/i,
    ])
  const datasetEvidence = firstContextMatch(text, [
    /\b(?:dataset|data|split|holdout|benchmark)\b.{0,160}\b(?:public|available|released|restricted|approval|license|download)\b/i,
    /\b(?:public|available|released|restricted|approval|license|download)\b.{0,160}\b(?:dataset|data|split|holdout|benchmark)\b/i,
  ])
  const metricEvidence = firstContextMatch(text, [
    /\b(?:primary|main|reported|evaluation|metric)\b.{0,120}\b(?:macro[- ]?F1|micro[- ]?F1|F1|accuracy|exact match|EM|BLEU|ROUGE|MSE|MAE|RMSE|AUROC|AUC)\b/i,
    /\b(?:macro[- ]?F1|micro[- ]?F1|F1|accuracy|exact match|EM|BLEU|ROUGE|MSE|MAE|RMSE|AUROC|AUC)\b.{0,120}\b(?:primary|main|reported|evaluation|metric)\b/i,
  ])
  const resultEvidence = firstContextMatch(text, [
    /\b\d+(?:\.\d+)?\s*(?:%|points?)?\s*(?:macro[- ]?F1|micro[- ]?F1|F1|accuracy|exact match|EM|BLEU|ROUGE|MSE|MAE|RMSE|AUROC|AUC)\b/i,
    /\b(?:macro[- ]?F1|micro[- ]?F1|F1|accuracy|exact match|EM|BLEU|ROUGE|MSE|MAE|RMSE|AUROC|AUC)\b.{0,40}\b\d+(?:\.\d+)?\b/i,
  ])
  const computeEvidence = firstContextMatch(text, [
    /\b(?:single[- ]?GPU|GPU|TPU|A100|V100|H100|24GB|40GB|80GB|hours?|runtime|compute)\b.{0,140}\b(?:train|reproduce|experiment|run|finetune|fine[- ]?tune)\b/i,
    /\b(?:train|reproduce|experiment|run|finetune|fine[- ]?tune)\b.{0,140}\b(?:single[- ]?GPU|GPU|TPU|A100|V100|H100|24GB|40GB|80GB|hours?|runtime|compute)\b/i,
  ])
  const reproducibilityEvidence = firstContextMatch(text, [
    /\b(?:reproducible|reproduce|replicate|all experiments|released code|public datasets?|artifact)\b/i,
  ])

  return {
    githubUrls,
    metricNames,
    codeEvidence,
    datasetEvidence,
    metricEvidence,
    resultEvidence,
    computeEvidence,
    reproducibilityEvidence,
  }
}

function liveClaimFields(
  evidence: ReturnType<typeof extractLiveClaimEvidence>,
  sourceDescription: string,
): Record<string, Record<string, string>> {
  return {
    code_availability: extractedClaim(
      evidence.githubUrls.length > 0
        ? `Code or implementation URL appears in Asta evidence: ${evidence.githubUrls.join(', ')}.`
        : 'Code or implementation availability is mentioned in Asta evidence.',
      evidence.codeEvidence,
      sourceDescription,
    ),
    dataset_availability: extractedClaim(
      'Dataset, split, access, or benchmark availability is mentioned in Asta evidence.',
      evidence.datasetEvidence,
      sourceDescription,
    ),
    primary_metric: extractedClaim(
      evidence.metricNames.length > 0
        ? `Metric evidence mentions: ${evidence.metricNames.join(', ')}.`
        : 'Metric or evaluation protocol is mentioned in Asta evidence.',
      evidence.metricEvidence,
      sourceDescription,
    ),
    reported_result: extractedClaim(
      'Reported result evidence includes a numeric score tied to an evaluation metric.',
      evidence.resultEvidence,
      sourceDescription,
    ),
    compute_claim: extractedClaim(
      'Compute or runtime evidence is mentioned in Asta evidence.',
      evidence.computeEvidence,
      sourceDescription,
    ),
    reproducibility_promise: extractedClaim(
      'Reproducibility, released-artifact, or replication promise is mentioned in Asta evidence.',
      evidence.reproducibilityEvidence,
      sourceDescription,
    ),
  }
}

function liveUnscopedEvidenceFields(
  evidence: ReturnType<typeof extractLiveClaimEvidence>,
): Record<string, Record<string, string>> {
  return {
    code_availability_lead: extractedUnscopedEvidence('Code availability evidence', evidence.codeEvidence),
    dataset_availability_lead: extractedUnscopedEvidence('Dataset availability evidence', evidence.datasetEvidence),
    primary_metric_lead: extractedUnscopedEvidence('Metric evidence', evidence.metricEvidence),
    reported_result_lead: extractedUnscopedEvidence('Reported result evidence', evidence.resultEvidence),
    compute_claim_lead: extractedUnscopedEvidence('Compute/runtime evidence', evidence.computeEvidence),
    reproducibility_promise_lead: extractedUnscopedEvidence('Reproducibility promise evidence', evidence.reproducibilityEvidence),
  }
}

function buildLivePaperClaims(
  asta: {
    targetPaperMetadata: unknown
    claimSnippets: unknown
    datasetSnippets: unknown
    replicationSnippets: unknown
  },
  resolvedPaperId: string | null | undefined,
): Record<string, unknown> {
  const hasResolvedPaperId = typeof resolvedPaperId === 'string' && resolvedPaperId.trim() !== ''
  const hasTargetMetadata = hasSuccessfulSourcePayload(asta.targetPaperMetadata)
  const scopedText = hasResolvedPaperId
    ? sourceEvidenceText(
      asta.targetPaperMetadata,
      asta.claimSnippets,
      asta.datasetSnippets,
      asta.replicationSnippets,
    )
    : hasTargetMetadata
      ? sourceEvidenceText(asta.targetPaperMetadata)
      : ''
  const scopedSourceDescription = hasResolvedPaperId
    ? hasTargetMetadata
      ? 'validated Asta target-paper metadata and paper-scoped snippets'
      : 'paper-scoped Asta snippets'
    : hasTargetMetadata
      ? 'validated Asta target-paper metadata only'
      : 'no validated Asta target-paper metadata'
  const paperClaimFields = liveClaimFields(extractLiveClaimEvidence(scopedText), scopedSourceDescription)

  const unscopedSnippetText = hasResolvedPaperId
    ? ''
    : sourceEvidenceText(asta.claimSnippets, asta.datasetSnippets, asta.replicationSnippets)

  return {
    source_note: hasResolvedPaperId
      ? 'LIVE claim surface constructed deterministically from validated Asta target-paper metadata when available plus paper-scoped snippet_search results; missing fields are explicit evidence gaps, not model guesses.'
      : hasTargetMetadata
        ? 'LIVE claim surface constructed deterministically from validated Asta target-paper metadata only. Asta snippets were global because no paper_id resolved, so snippet-derived evidence is surfaced separately as unscoped leads.'
        : 'LIVE claim surface has no validated target-paper metadata. Asta snippets were global because no paper_id resolved, so snippet-derived evidence is surfaced separately as unscoped leads.',
    snippet_scope: {
      resolved_paper_id: hasResolvedPaperId ? resolvedPaperId : null,
      snippet_search_scope: hasResolvedPaperId ? 'paper_scoped' : 'global_unscoped',
      metadata_scope: hasTargetMetadata ? 'target_scoped' : 'unresolved_unscoped',
      claim_policy: hasResolvedPaperId
        ? 'Snippet-derived evidence may be treated as target-paper evidence.'
        : 'Snippet-derived evidence must not be treated as target-paper claims without corroboration.',
    },
    ...paperClaimFields,
    ...(!hasResolvedPaperId
      ? {
        unscoped_snippet_evidence: {
          source_note: 'Global Asta snippet_search was used because paper_id resolution failed. Treat these entries as discovery leads or uncertainties, not paper claims.',
          ...liveUnscopedEvidenceFields(extractLiveClaimEvidence(unscopedSnippetText)),
        },
      }
      : {}),
  }
}

function summarizeRelationshipHints(value: unknown): string[] {
  if (value === null || typeof value !== 'object') return []
  const labels: Record<string, string> = {
    linked_from_paper_metadata: 'linked from paper metadata',
    mentions_query_or_title: 'mentions query or title',
    mentions_official: 'official claim tied to target',
    official_claim_context_unclear: 'official claim not tied to target',
    explicit_non_official_claim: 'explicit non-official claim',
    mentions_reproduction: 'mentions reproduction',
    mentions_datasets: 'mentions datasets',
  }
  return Object.entries(value as Record<string, unknown>)
    .filter(([, flag]) => flag === true)
    .map(([key]) => labels[key] ?? key.replace(/_/g, ' '))
}

function scoreRepositoryForReplication(repo: Record<string, unknown>): number {
  const hints = repo['repo_relationship_hints'] !== null && typeof repo['repo_relationship_hints'] === 'object'
    ? repo['repo_relationship_hints'] as Record<string, unknown>
    : {}
  const paths = Array.isArray(repo['relevant_paths'])
    ? repo['relevant_paths'].filter((item): item is string => typeof item === 'string')
    : []
  const issues = Array.isArray(repo['issue_search_results'])
    ? repo['issue_search_results'].filter((item): item is Record<string, unknown> => item !== null && typeof item === 'object')
    : []

  let score = 0
  if (repo['source_query'] === 'github-url-from-paper-metadata') score += 120
  if (hints['linked_from_paper_metadata'] === true) score += 60
  if (hints['mentions_query_or_title'] === true) score += 80
  if (hints['mentions_official'] === true) score += 55
  if (hints['official_claim_context_unclear'] === true) score -= 12
  if (hints['explicit_non_official_claim'] === true) score -= 35
  if (hints['mentions_reproduction'] === true) score += 20
  if (hints['mentions_datasets'] === true) score += 15

  if (paths.some((pathValue) => /(^|\/)(scripts?|experiments?)\//i.test(pathValue))) score += 25
  if (paths.some((pathValue) => /(run|train|long|forecast|eval|metric).*\.(py|sh)$/i.test(pathValue))) score += 20
  if (paths.some((pathValue) => /(^|\/)(data_provider|data_loader|datasets?)\//i.test(pathValue))) score += 15

  const issueTitles = issues.map((issue) => String(issue['title'] ?? '')).join(' ')
  if (/reproduc|replicat|result|hyperparameter|table/i.test(issueTitles)) score += 15

  const description = String(repo['description'] ?? '')
  const readme = String(repo['readme_excerpt'] ?? '')
  const genericText = `${description}\n${readme}`
  if (/framework|toolkit|library|baseline/i.test(genericText) && hints['mentions_query_or_title'] !== true) {
    score -= 20
  }

  const stars = getNumber(repo, 'stargazers_count') ?? 0
  score += Math.min(10, Math.log10(stars + 1) * 3)

  return score
}

function sortRepositoryEvidence(repos: Array<Record<string, unknown>>): Array<Record<string, unknown>> {
  return [...repos].sort((a, b) => {
    const scoreDelta = scoreRepositoryForReplication(b) - scoreRepositoryForReplication(a)
    if (scoreDelta !== 0) return scoreDelta
    return String(a['full_name'] ?? '').localeCompare(String(b['full_name'] ?? ''))
  })
}

function compactRepositoryEvidenceForCodeAgent(repo: Record<string, unknown>): Record<string, unknown> {
  const {
    dataset_candidate_evidence: _datasetCandidateEvidence,
    dataset_mentions: _datasetMentions,
    ...rest
  } = repo
  return rest
}

function repoText(repo: Record<string, unknown>): string {
  return sourceEvidenceText(
    repo['full_name'],
    repo['description'],
    repo['readme_excerpt'],
    repo['relevant_paths'],
    repo['support_file_excerpts'],
    repo['issue_search_results'],
  )
}

function repoHasUsableSnapshot(repo: Record<string, unknown>): boolean {
  const readme = String(repo['readme_excerpt'] ?? '')
  const paths = Array.isArray(repo['relevant_paths']) ? repo['relevant_paths'] : []
  return readme !== '' && readme !== 'README unavailable' || paths.length > 0
}

function repoHasTrainingOrEvalPath(repo: Record<string, unknown>): boolean {
  const paths = Array.isArray(repo['relevant_paths'])
    ? repo['relevant_paths'].filter((item): item is string => typeof item === 'string')
    : []
  return paths.some((pathValue) => /(train|training|eval|evaluation|metric|run|launch).*\.(py|sh|yaml|yml|json)$/i.test(pathValue))
}

function repoHasHint(repo: Record<string, unknown>, key: string): boolean {
  const hints = repo['repo_relationship_hints']
  return hints !== null && typeof hints === 'object' && (hints as Record<string, unknown>)[key] === true
}

function repoIsTargetTied(repo: Record<string, unknown>): boolean {
  return repo['source_query'] === 'github-url-from-paper-metadata'
    || repoHasHint(repo, 'linked_from_paper_metadata')
    || repoHasHint(repo, 'mentions_official')
    || repoHasHint(repo, 'mentions_query_or_title')
}

function repoHasUnofficialImplementationSignal(repo: Record<string, unknown>): boolean {
  if (repoHasHint(repo, 'explicit_non_official_claim')) return true

  const text = repoText(repo)
  return /\b(?:(?:un|non)[-\s]?official|third[-\s]?party|community|independent)\s+(?:implementation|code|repo(?:sitory)?|release|reproduction)\b/i.test(text)
    || /\b(?:reimplementation|re-implementation)\b/i.test(text)
    || /\b(?:replication|reproduction)\s+(?:implementation|code|repo(?:sitory)?)\b/i.test(text)
}

function statusItem(
  artifactType: string,
  status: string,
  source: string,
  note: string,
  evidenceIds: string[] = [],
): Record<string, unknown> {
  return {
    artifact_type: artifactType,
    status,
    source,
    note,
    evidence_ids: evidenceIds,
  }
}

function buildLiveDiscoveryStatus(input: {
  asta: {
    targetPaperMetadata: unknown
    citations: unknown
    datasetSnippets: unknown
    replicationSnippets: unknown
  }
  snippetScope: SnippetSearchScope
  repoEvidence: Array<Record<string, unknown>>
  datasetClues: Array<Record<string, unknown>>
  directRepos: string[]
}): Array<Record<string, unknown>> {
  const { asta, snippetScope, repoEvidence, datasetClues, directRepos } = input
  const snippetsArePaperScoped = snippetScope === 'paper_scoped'
  const scholarlyMetadataFound =
    hasSuccessfulSourcePayload(asta.targetPaperMetadata) && findFirstStringByKey(asta.targetPaperMetadata, 'title') !== undefined
  const officialRepos = repoEvidence.filter((repo) =>
    repo['source_query'] === 'github-url-from-paper-metadata'
    || repoHasHint(repo, 'linked_from_paper_metadata')
    || repoHasHint(repo, 'mentions_official'),
  )
  const targetTiedRepos = repoEvidence.filter(repoIsTargetTied)
  const usableOfficialRepos = officialRepos.filter(repoHasUsableSnapshot)
  const unofficialRepos = repoEvidence.filter((repo) =>
    !officialRepos.includes(repo)
    && repoHasUnofficialImplementationSignal(repo),
  )
  const relatedBenchmarkRepos = repoEvidence.filter((repo) =>
    !officialRepos.includes(repo)
    && !unofficialRepos.includes(repo)
    && /benchmark|baseline|toolkit|framework|library/i.test(repoText(repo)),
  )
  const anyRepoFetched = repoEvidence.length > 0
  const scopedDatasetSnippets = snippetsArePaperScoped ? asta.datasetSnippets : undefined
  const scopedReplicationSnippets = snippetsArePaperScoped ? asta.replicationSnippets : undefined
  const unscopedDatasetSnippetsFound =
    !snippetsArePaperScoped && hasSuccessfulSourcePayload(asta.datasetSnippets)
  const unscopedReplicationSnippetsFound =
    !snippetsArePaperScoped && hasSuccessfulSourcePayload(asta.replicationSnippets)
  const targetTiedDatasetClues = datasetClues.filter((clue) => clue['target_tied_repository'] === true)
  const untiedDatasetCluesFound = datasetClues.length > 0 && targetTiedDatasetClues.length === 0
  const targetTiedEntrypointRepos = targetTiedRepos.filter(repoHasTrainingOrEvalPath)
  const untiedEntrypointReposFound =
    targetTiedEntrypointRepos.length === 0 && repoEvidence.some(repoHasTrainingOrEvalPath)
  const datasetEvidenceFound =
    hasSuccessfulSourcePayload(scopedDatasetSnippets) || targetTiedDatasetClues.length > 0
  const datasetText = sourceEvidenceText(scopedDatasetSnippets, targetTiedDatasetClues)
  const restrictedDatasetEvidence = findDatasetRestrictionEvidence(datasetText)
  const metricPattern = /\b(?:macro[- ]?F1|micro[- ]?F1|F1|accuracy|exact match|EM|BLEU|ROUGE|MSE|MAE|RMSE|AUROC|AUC|metric|evaluator|evaluation)\b/i
  const metricProtocolEvidence = firstContextMatch(sourceEvidenceText(scopedDatasetSnippets, scopedReplicationSnippets, targetTiedRepos), [
    metricPattern,
  ])
  const untiedMetricEvidence = !metricProtocolEvidence && firstContextMatch(sourceEvidenceText(repoEvidence), [
    metricPattern,
  ])
  const citationTraversalFound = hasSuccessfulSourcePayload(asta.citations)
  const citationFeedbackSignalFound = sourceHasReproductionFeedbackSignal(asta.citations)
  const citationFeedbackFound =
    citationFeedbackSignalFound || hasSuccessfulSourcePayload(scopedReplicationSnippets)

  return [
    statusItem(
      'scholarly_metadata',
      scholarlyMetadataFound ? 'found' : 'source_unavailable',
      'Asta MCP get_paper/search_paper_by_title',
      scholarlyMetadataFound
        ? 'Resolved validated target-paper metadata from Asta.'
        : 'Asta paper lookup did not return a validated target-paper metadata payload.',
    ),
    statusItem(
      'official_code',
      usableOfficialRepos.length > 0
        ? 'found'
        : officialRepos.length > 0 || directRepos.length > 0
          ? 'missing'
          : anyRepoFetched
            ? 'ambiguous'
            : 'source_unavailable',
      'GitHub URLs from paper metadata plus GitHub Search README/tree inspection',
      usableOfficialRepos.length > 0
        ? 'At least one candidate official repository has a readable README or relevant file tree.'
        : officialRepos.length > 0 || directRepos.length > 0
          ? 'A paper-linked or official-looking repository was found, but README/tree evidence was unavailable or unusable.'
          : anyRepoFetched
            ? 'GitHub found code-like candidates, but none could be tied to official ownership.'
            : 'No repository evidence could be fetched from GitHub.',
      officialRepos.map((repo) => String(repo['full_name'] ?? repo['html_url'] ?? '')).filter((item) => item !== ''),
    ),
    statusItem(
      'unofficial_code',
      unofficialRepos.length > 0 ? 'found' : anyRepoFetched ? 'not_required_for_replication' : 'source_unavailable',
      'GitHub Search README/tree/issues',
      unofficialRepos.length > 0
        ? 'At least one candidate repository presents as an unofficial reproduction or reimplementation.'
        : anyRepoFetched
          ? 'Fetched repositories did not clearly identify as unofficial reproductions; this is not a missing replication artifact unless another source requires a third-party reproduction.'
          : 'No repository evidence could be fetched from GitHub.',
      unofficialRepos.map((repo) => String(repo['full_name'] ?? repo['html_url'] ?? '')).filter((item) => item !== ''),
    ),
    statusItem(
      'related_benchmark_code',
      relatedBenchmarkRepos.length > 0 ? 'found' : anyRepoFetched ? 'not_required_for_replication' : 'source_unavailable',
      'GitHub Search README/tree/issues',
      relatedBenchmarkRepos.length > 0
        ? 'At least one candidate appears to be related benchmark, baseline, toolkit, or framework code rather than the paper method itself.'
        : anyRepoFetched
          ? 'Fetched repositories did not clearly look like related benchmark/baseline code; this is not a missing replication artifact unless the paper requires a separate baseline repository.'
          : 'No repository evidence could be fetched from GitHub.',
      relatedBenchmarkRepos.map((repo) => String(repo['full_name'] ?? repo['html_url'] ?? '')).filter((item) => item !== ''),
    ),
    statusItem(
      'training_or_eval_entrypoint',
      targetTiedEntrypointRepos.length > 0
        ? 'found'
        : untiedEntrypointReposFound
          ? 'ambiguous'
          : anyRepoFetched
            ? 'missing'
            : 'source_unavailable',
      'GitHub recursive tree and support-file excerpts',
      targetTiedEntrypointRepos.length > 0
        ? 'At least one target-tied candidate repository exposes train/eval/run/metric paths.'
        : untiedEntrypointReposFound
          ? 'Only non-target-tied fetched repositories expose train/eval/run/metric paths; treat as ambiguous, not as target-paper entrypoint evidence.'
          : anyRepoFetched
            ? 'No train/eval/run/metric path was visible in fetched repository snapshots.'
            : 'No repository evidence could be fetched from GitHub.',
      (targetTiedEntrypointRepos.length > 0 ? targetTiedEntrypointRepos : repoEvidence.filter(repoHasTrainingOrEvalPath))
        .map((repo) => String(repo['full_name'] ?? repo['html_url'] ?? ''))
        .filter((item) => item !== ''),
    ),
    statusItem(
      'dataset_candidate_evidence',
      targetTiedDatasetClues.length > 0
        ? 'found'
        : datasetEvidenceFound || untiedDatasetCluesFound || unscopedDatasetSnippetsFound
          ? 'ambiguous'
          : 'source_unavailable',
      'Asta MCP snippet_search plus dataset clues from repository READMEs/paths',
      targetTiedDatasetClues.length > 0
        ? 'Target-tied repository README/path/support-file clues surfaced concrete dataset candidates.'
        : datasetEvidenceFound
          ? 'Asta surfaced dataset-related snippets, but repository candidate evidence is absent or not concrete.'
          : untiedDatasetCluesFound
            ? 'Only non-target-tied repositories surfaced dataset candidates; treat them as leads, not target-paper dataset facts.'
          : unscopedDatasetSnippetsFound
            ? 'Only global/unscoped Asta dataset snippets were available; treat them as leads, not target-paper dataset facts.'
          : 'No dataset evidence was available from Asta snippets or repository clues.',
      (targetTiedDatasetClues.length > 0 ? targetTiedDatasetClues : datasetClues)
        .map((clue) => String(clue['repository'] ?? clue['repository_url'] ?? ''))
        .filter((item) => item !== ''),
    ),
    statusItem(
      'restricted_or_private_dataset',
      restrictedDatasetEvidence
        ? 'restricted'
        : datasetEvidenceFound
          ? 'no_restriction_signal'
          : untiedDatasetCluesFound || unscopedDatasetSnippetsFound
            ? 'ambiguous'
            : 'source_unavailable',
      'Asta MCP dataset snippet_search and repository dataset clues',
      restrictedDatasetEvidence
        ? `Access restriction signal surfaced: ${restrictedDatasetEvidence}`
        : datasetEvidenceFound
          ? 'No restricted/private/approval-gated dataset signal was visible in the live evidence snapshot.'
          : untiedDatasetCluesFound
            ? 'Only non-target-tied repository dataset clues were available, so no target-paper restriction status is asserted.'
          : unscopedDatasetSnippetsFound
            ? 'Only global/unscoped dataset snippets were available, so no target-paper restriction status is asserted.'
          : 'No dataset evidence was available to inspect access restrictions.',
    ),
    statusItem(
      'metric_protocol',
      metricProtocolEvidence
        ? 'found'
        : datasetEvidenceFound || citationFeedbackFound || untiedMetricEvidence
          ? 'ambiguous'
          : 'source_unavailable',
      'Asta MCP snippet_search plus repository metric/eval paths',
      metricProtocolEvidence
        ? `Target-scoped metric/evaluator signal surfaced: ${metricProtocolEvidence}`
        : untiedMetricEvidence
          ? `Only non-target-tied repository metric/evaluator signal surfaced: ${untiedMetricEvidence}`
          : datasetEvidenceFound || citationFeedbackFound
            ? 'Evidence exists, but no concrete target-scoped metric/evaluator signal was surfaced.'
            : 'No dataset or reproduction evidence was available to inspect metrics.',
    ),
    statusItem(
      'citation_feedback',
      citationFeedbackFound
        ? 'found'
        : citationTraversalFound || unscopedReplicationSnippetsFound
          ? 'ambiguous'
          : 'source_unavailable',
      snippetsArePaperScoped
        ? 'Asta MCP get_citations and paper-scoped snippet_search'
        : 'Asta MCP get_citations; global snippet_search is not treated as citation feedback',
      citationFeedbackFound
        ? 'Citation traversal with explicit reproduction-feedback signals or paper-scoped reproduction snippets returned evidence.'
        : citationTraversalFound
          ? 'Citation traversal returned papers, but no explicit reproduction/metric/result/code/data feedback signal was visible in the live snapshot.'
        : unscopedReplicationSnippetsFound
          ? 'Global reproduction snippets were available but no paper_id resolved; they are unscoped leads, not target-paper citation feedback.'
        : 'Asta citation traversal and reproduction snippets were unavailable.',
    ),
  ]
}

function buildLiveSourceDigest(
  query: string,
  asta: {
    targetPaperMetadata: unknown
    citations: unknown
    datasetSnippets: unknown
    replicationSnippets: unknown
  },
  snippetScope: SnippetSearchScope,
  repoEvidence: Array<Record<string, unknown>>,
  datasetClues: Array<Record<string, unknown>>,
): SourceDigest {
  const snippetsArePaperScoped = snippetScope === 'paper_scoped'
  const paperTitle = findFirstStringByKey(asta.targetPaperMetadata, 'title') ?? query
  const paperUrl = findFirstStringByKey(asta.targetPaperMetadata, 'url') ?? ''
  const paperVenue = findFirstStringByKey(asta.targetPaperMetadata, 'venue') ?? ''
  const paperYear = findFirstNumberByKey(asta.targetPaperMetadata, 'year')

  const repositories = repoEvidence.slice(0, REPO_EVIDENCE_LIMIT).map((repo) => {
    const issues = Array.isArray(repo['issue_search_results'])
      ? repo['issue_search_results'].filter((item): item is Record<string, unknown> => item !== null && typeof item === 'object')
      : []
    const paths = Array.isArray(repo['relevant_paths'])
      ? repo['relevant_paths'].filter((item): item is string => typeof item === 'string')
      : []
    return {
      repository: String(repo['full_name'] ?? ''),
      url: String(repo['html_url'] ?? ''),
      description: String(repo['description'] ?? ''),
      relationship_hints: summarizeRelationshipHints(repo['repo_relationship_hints']),
      useful_paths: paths.slice(0, 8),
      issue_signals: issues.slice(0, 4).map((issue) => ({
        title: String(issue['title'] ?? ''),
        url: String(issue['html_url'] ?? ''),
      })),
    }
  })

  const datasetByName = new Map<string, SourceDigest['datasets'][number]>()
  for (const clue of datasetClues) {
    const source = String(clue['repository_url'] ?? clue['repository'] ?? '')
    const mentions = Array.isArray(clue['dataset_mentions'])
      ? clue['dataset_mentions'].filter((item): item is string => typeof item === 'string')
      : []
    const candidateEvidence = Array.isArray(clue['dataset_candidate_evidence'])
      ? clue['dataset_candidate_evidence'].filter((item): item is Record<string, unknown> => item !== null && typeof item === 'object')
      : []
    const candidateMentions = candidateEvidence
      .map((item) => String(item['name'] ?? ''))
      .filter((item) => item !== '')
    for (const name of uniqueStrings([...mentions, ...candidateMentions], 20)) {
      if (datasetByName.has(name)) continue
      const evidenceItem = candidateEvidence.find((item) => String(item['name'] ?? '').toLowerCase() === name.toLowerCase())
      const evidenceKind = evidenceItem ? String(evidenceItem['evidence_kind'] ?? '') : ''
      const evidenceLine = evidenceItem ? String(evidenceItem['evidence'] ?? '') : ''
      const hasEvidence = evidenceKind !== '' || evidenceLine !== ''
      datasetByName.set(name, {
        name,
        evidence: hasEvidence
          ? `Detected from scored candidate evidence (${evidenceKind}): ${compactText(evidenceLine, 140)}`
          : 'Detected from repository README, script/config path, or support-file excerpt.',
        source,
      })
    }
  }
  const datasetSnippetMentions = snippetsArePaperScoped
    ? extractDatasetMentionsFromAstaSnippets(asta.datasetSnippets)
    : []

  const reproductionByKey = new Map<string, SourceDigest['reproduction_signals'][number]>()
  const targetTitles = new Set([
    normalizeTitleForCompare(query),
    normalizeTitleForCompare(paperTitle),
  ])
  for (const repo of repoEvidence) {
    const issues = Array.isArray(repo['issue_search_results'])
      ? repo['issue_search_results'].filter((item): item is Record<string, unknown> => item !== null && typeof item === 'object')
      : []
    for (const issue of issues) {
      const title = String(issue['title'] ?? '')
      const url = String(issue['html_url'] ?? '')
      if (!title || reproductionByKey.has(url || title)) continue
      reproductionByKey.set(url || title, { title, url, source: 'GitHub issue search' })
    }
  }
  for (const item of [
    ...collectRecordsWithTitle(asta.citations),
    ...(snippetsArePaperScoped ? collectRecordsWithTitle(asta.replicationSnippets) : []),
  ]) {
    const title = String(item['title'] ?? '')
    const url = getString(item, 'url') ?? getString(item, 'paperUrl') ?? ''
    const normalizedTitle = normalizeTitleForCompare(title)
    const isToolError = isUnavailableSourcePayload(item)
    if (isToolError || targetTitles.has(normalizedTitle) || /^asta .*retrieval$/i.test(title)) continue
    if (!hasReproductionFeedbackSignal(item)) continue
    if (!title || reproductionByKey.has(url || title)) continue
    reproductionByKey.set(url || title, {
      title,
      url,
      source: 'Asta citation/snippet evidence',
    })
    if (reproductionByKey.size >= 10) break
  }

  return {
    paper: {
      title: paperTitle,
      url: paperUrl,
      venue_or_year: [paperVenue, paperYear].filter((item) => item !== undefined && item !== '').join(' '),
    },
    repositories,
    datasets: Array.from(datasetByName.values()).slice(0, 20),
    dataset_snippet_mentions: datasetSnippetMentions,
    reproduction_signals: Array.from(reproductionByKey.values()).slice(0, 10),
  }
}

function normalizePaperId(query: string): string | undefined {
  const trimmed = query.trim()
  if (/^(DOI|ARXIV|PMID|PMCID|MAG|ACL|CorpusId|URL):/i.test(trimmed)) {
    return trimmed.replace(/^doi:/i, 'DOI:')
      .replace(/^arxiv:/i, 'ARXIV:')
      .replace(/^pmid:/i, 'PMID:')
      .replace(/^pmcid:/i, 'PMCID:')
      .replace(/^mag:/i, 'MAG:')
      .replace(/^acl:/i, 'ACL:')
      .replace(/^corpusid:/i, 'CorpusId:')
      .replace(/^url:/i, 'URL:')
  }
  if (/^10\.\d{4,9}\//.test(trimmed)) {
    return `DOI:${trimmed}`
  }
  if (/^\d{4}\.\d{4,5}(v\d+)?$/i.test(trimmed)) {
    return `ARXIV:${trimmed}`
  }
  if (/^https?:\/\/(arxiv\.org|www\.semanticscholar\.org|aclanthology\.org|dl\.acm\.org)/i.test(trimmed)) {
    return `URL:${trimmed}`
  }
  return undefined
}

function paperIdFromRecord(record: Record<string, unknown>): string | undefined {
  for (const key of ['paper_id', 'paperId', 'paperID', 'corpusId', 'CorpusId']) {
    const candidate = record[key]
    if (typeof candidate === 'string' && candidate.trim() !== '') {
      if (key.toLowerCase().includes('corpus') && !candidate.startsWith('CorpusId:')) {
        return `CorpusId:${candidate}`
      }
      return candidate
    }
    if (typeof candidate === 'number') {
      return `CorpusId:${candidate}`
    }
  }
  return undefined
}

function significantTitleTokens(text: string): string[] {
  const stopwords = new Set([
    'a',
    'an',
    'and',
    'are',
    'as',
    'at',
    'by',
    'for',
    'from',
    'in',
    'is',
    'of',
    'on',
    'or',
    'the',
    'to',
    'with',
  ])
  return normalizeTitleForCompare(text)
    .split(' ')
    .filter((token) => token.length > 2 && !stopwords.has(token))
}

function titleMatchesQuery(candidateTitle: string, query: string): boolean {
  const candidate = normalizeTitleForCompare(candidateTitle)
  const target = normalizeTitleForCompare(query)
  if (!candidate || !target) return false
  if (candidate === target) return true

  const targetTokens = significantTitleTokens(query)
  if (targetTokens.length < 3) return false

  const candidateTokens = significantTitleTokens(candidateTitle)
  if (candidateTokens.length < 3) return false

  const candidateTokenSet = new Set(candidateTokens)
  const overlap = targetTokens.filter((token) => candidateTokenSet.has(token)).length
  const targetCoverage = overlap / targetTokens.length
  const candidateCoverage = overlap / candidateTokens.length
  return targetCoverage >= 0.82 && candidateCoverage >= 0.7
}

function resolveLivePaperIdentity(
  query: string,
  knownPaperId: string | undefined,
  paperLookup: unknown,
): LivePaperIdentity {
  if (knownPaperId) {
    return {
      resolvedPaperId: knownPaperId,
      targetPaperMetadata: hasSuccessfulSourcePayload(paperLookup) ? paperLookup : undefined,
      metadataScope: hasSuccessfulSourcePayload(paperLookup) ? 'target_scoped' : 'unresolved_unscoped',
      note: hasSuccessfulSourcePayload(paperLookup)
        ? 'Input was an explicit paper identifier, so Asta get_paper metadata is treated as target-scoped.'
        : 'Input was an explicit paper identifier, but Asta get_paper did not return usable metadata. Snippet and citation requests can still be scoped by the input identifier.',
    }
  }

  for (const record of collectRecordsWithTitle(paperLookup)) {
    const title = getString(record, 'title')
    if (!title || !titleMatchesQuery(title, query)) continue

    const paperId = paperIdFromRecord(record)
    return {
      ...(paperId ? { resolvedPaperId: paperId } : {}),
      targetPaperMetadata: record,
      metadataScope: 'target_scoped',
      note: paperId
        ? 'Asta title lookup returned a strict title match with a paper_id; snippets are paper-scoped.'
        : 'Asta title lookup returned a strict title match but no paper_id; metadata is target-scoped, but snippets remain global/unscoped.',
    }
  }

  return {
    metadataScope: 'unresolved_unscoped',
    note: 'Asta title lookup did not return a strict target-paper match. Raw lookup payload is omitted from source-agent snapshots to avoid treating fuzzy search results as target-paper facts.',
  }
}

function toolResultToPlainObject(result: unknown): unknown {
  if (result === null || typeof result !== 'object') return result

  const record = result as Record<string, unknown>
  if (record['structuredContent'] !== undefined) {
    return record['structuredContent']
  }
  if (record['toolResult'] !== undefined) {
    return record['toolResult']
  }

  const content = record['content']
  if (Array.isArray(content)) {
    const textBlocks = content
      .map((block) => {
        if (block !== null && typeof block === 'object' && typeof (block as Record<string, unknown>)['text'] === 'string') {
          return (block as Record<string, unknown>)['text'] as string
        }
        return undefined
      })
      .filter((text): text is string => text !== undefined)

    if (textBlocks.length === 1) {
      try {
        return JSON.parse(textBlocks[0])
      } catch {
        return textBlocks[0]
      }
    }
    if (textBlocks.length > 1) {
      return textBlocks
    }
  }

  return result
}

async function withAstaClient<T>(run: (client: MCPClientLike) => Promise<T>): Promise<T> {
  const apiKey = process.env.ASTA_API_KEY?.trim()
  if (!apiKey) {
    throw new Error('SOURCE_MODE=live requires ASTA_API_KEY.')
  }

  let Client: MCPClientConstructor
  let StreamableHTTPClientTransport: StreamableHTTPClientTransportConstructor
  try {
    const [clientModule, transportModule] = await Promise.all([
      import('@modelcontextprotocol/sdk/client/index.js') as Promise<{ Client: MCPClientConstructor }>,
      import('@modelcontextprotocol/sdk/client/streamableHttp.js') as Promise<{
        StreamableHTTPClientTransport: StreamableHTTPClientTransportConstructor
      }>,
    ])
    Client = clientModule.Client
    StreamableHTTPClientTransport = transportModule.StreamableHTTPClientTransport
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error)
    throw new Error(
      'SOURCE_MODE=live requires the optional @modelcontextprotocol/sdk peer dependency. ' +
      'Install it with `npm install @modelcontextprotocol/sdk` before using live Asta discovery. ' +
      `Original error: ${message}`,
    )
  }

  const transport = new StreamableHTTPClientTransport(
    new URL('https://asta-tools.allen.ai/mcp/v1'),
    { requestInit: { headers: { 'x-api-key': apiKey } } },
  )
  const client = new Client(
    { name: 'open-multi-agent-paper-replication-triage', version: '0.0.0' },
    { capabilities: {} },
  )

  await client.connect(transport, { timeout: 60_000 })
  try {
    return await run(client)
  } finally {
    await client.close?.()
  }
}

async function callAstaTool(
  client: MCPClientLike,
  name: string,
  args: Record<string, unknown>,
): Promise<unknown> {
  try {
    const result = await client.callTool({ name, arguments: args }, undefined, { timeout: 60_000 })
    return toolResultToPlainObject(result)
  } catch (error) {
    return {
      is_error: true,
      tool: name,
      args,
      message: error instanceof Error ? error.message : String(error),
    }
  }
}

async function loadLiveSourceBundle(query: string): Promise<SourceBundle> {
  const githubHeaders = process.env.GITHUB_TOKEN
    ? { Authorization: `Bearer ${process.env.GITHUB_TOKEN}` }
    : {}

  const astaFields = 'title,year,authors,venue,tldr,url,abstract,isOpenAccess,publicationDate,fieldsOfStudy'
  const knownPaperId = normalizePaperId(query)

  const asta = await withAstaClient(async (client) => {
    const paperLookup = knownPaperId
      ? await callAstaTool(client, 'get_paper', { paper_id: knownPaperId, fields: astaFields })
      : await callAstaTool(client, 'search_paper_by_title', { title: query, fields: astaFields })

    const paperIdentity = resolveLivePaperIdentity(query, knownPaperId, paperLookup)
    const resolvedPaperId = paperIdentity.resolvedPaperId
    const paperIdsArg = resolvedPaperId ? { paper_ids: resolvedPaperId } : {}
    const snippetScope: SnippetSearchScope = resolvedPaperId ? 'paper_scoped' : 'global_unscoped'

    const [citations, claimSnippets, datasetSnippets, replicationSnippets] = await Promise.all([
      resolvedPaperId
        ? callAstaTool(client, 'get_citations', {
          paper_id: resolvedPaperId,
          fields: 'title,year,authors,venue,tldr,url,abstract',
          limit: 10,
        })
        : Promise.resolve({
          source_unavailable: true,
          reason: 'Could not resolve a paper_id for citation traversal.',
        }),
      callAstaTool(client, 'snippet_search', {
        query: `${query} code implementation repository dataset split public metric result GPU reproducible released artifact`,
        limit: 5,
        ...paperIdsArg,
      }),
      callAstaTool(client, 'snippet_search', {
        query: `${query} dataset split license benchmark holdout public restricted`,
        limit: 5,
        ...paperIdsArg,
      }),
      callAstaTool(client, 'snippet_search', {
        query: `${query} reproduce replication reproduced results code metric mismatch benchmark`,
        limit: 5,
        ...paperIdsArg,
      }),
    ])

    return {
      paperLookupResolution: {
        resolved_paper_id: resolvedPaperId ?? null,
        metadata_scope: paperIdentity.metadataScope,
        note: paperIdentity.note,
      },
      targetPaperMetadata: paperIdentity.targetPaperMetadata ?? null,
      resolvedPaperId: resolvedPaperId ?? null,
      snippetScope,
      citations,
      claimSnippets,
      datasetSnippets,
      replicationSnippets,
    }
  })

  const githubSearchQueries = buildGitHubSearchQueries(query, asta.targetPaperMetadata)
  const githubSearches = await Promise.all(
    githubSearchQueries.map((rawQuery) => fetchGitHubSearch(rawQuery, githubHeaders)),
  )
  const githubItemByName = new Map<string, Record<string, unknown>>()
  for (const search of githubSearches) {
    if (!Array.isArray(search?.['items'])) continue
    for (const item of search['items'] as Array<Record<string, unknown>>) {
      const fullName = getString(item, 'full_name')
      if (fullName && !githubItemByName.has(fullName)) {
        githubItemByName.set(fullName, item)
      }
    }
  }

  const directRepos = extractGithubRepoFullNames(asta.targetPaperMetadata)
  const githubItems = Array.from(githubItemByName.values())
  const directRepoInputs = directRepos.slice(0, REPO_DISCOVERY_FETCH_LIMIT)
  const directRepoNames = new Set(directRepoInputs.map((repo) => repo.toLowerCase()))
  const searchRepoInputs = githubItems
    .filter((item) => {
      const fullName = getString(item, 'full_name')
      return fullName ? !directRepoNames.has(fullName.toLowerCase()) : false
    })
    .slice(0, Math.max(0, REPO_DISCOVERY_FETCH_LIMIT - directRepoInputs.length))
  const repoEvidence = await Promise.all(
    [
      ...directRepoInputs.map((repo) => fetchGitHubRepoEvidence(repo, githubHeaders, 'github-url-from-paper-metadata')),
      ...searchRepoInputs.map((item) => fetchGitHubRepoEvidence(item, githubHeaders, query)),
    ],
  )
  const fullRepoEvidence = sortRepositoryEvidence(
    repoEvidence.filter((item): item is Record<string, unknown> => item !== undefined),
  )
  const snippetScope = asta.snippetScope as SnippetSearchScope
  const topRepoEvidence = fullRepoEvidence.slice(0, REPO_EVIDENCE_LIMIT)
  const datasetCluesFromRepos = buildDatasetCluesFromRepos(fullRepoEvidence)
  const sourceDigest = buildLiveSourceDigest(query, asta, snippetScope, fullRepoEvidence, datasetCluesFromRepos)
  const paperClaims = buildLivePaperClaims(asta, asta.resolvedPaperId)
  const discoveryStatus = buildLiveDiscoveryStatus({
    asta,
    snippetScope,
    repoEvidence: fullRepoEvidence,
    datasetClues: datasetCluesFromRepos,
    directRepos,
  })
  const searchTotal = githubSearches.reduce((sum, search) => {
    const count = typeof search?.['total_count'] === 'number' ? search['total_count'] : 0
    return sum + count
  }, 0)
  const searchIncomplete = githubSearches.some((search) => search?.['incomplete_results'] === true)

  return {
    mode: 'live',
    query,
    sourceIndex: {
      notice: 'LIVE BEST-EFFORT SOURCE DISCOVERY. Scholarly evidence comes from Asta MCP; implementation evidence comes from GitHub Search. Missing sources are evidence, not a request for manual input.',
      query,
      source_mode: 'live',
      discovery_status: discoveryStatus,
    },
    scholarlyMetadata: {
      notice: 'LIVE Asta MCP scholarly metadata. Asta exposes the Semantic Scholar academic graph over MCP.',
      query,
      paper_lookup_resolution: asta.paperLookupResolution,
      resolved_paper_id: asta.resolvedPaperId,
      asta_paper_lookup: hasSuccessfulSourcePayload(asta.targetPaperMetadata)
        ? asta.targetPaperMetadata
        : {
          status: 'unresolved_unscoped_omitted',
          note: 'Raw Asta paper lookup was not exposed to the claim agent because it was not validated as the target paper.',
        },
      claim_snippet_scope: snippetScope,
      ...(snippetScope === 'paper_scoped'
        ? { asta_claim_snippets: asta.claimSnippets }
        : {
          unscoped_claim_snippets: {
            status: 'global_unscoped_omitted_from_claim_extraction',
            note: 'Asta claim snippet_search ran globally because no validated paper_id resolved. Raw snippets are omitted from the claim-agent snapshot so they cannot be mistaken for target-paper claims; see paper_claims.unscoped_snippet_evidence for discovery leads.',
          },
        }),
      paper_claims: paperClaims,
    },
    codeArtifacts: {
      notice: 'LIVE GitHub Search plus shallow repository evidence. GITHUB_TOKEN is optional but recommended to avoid low anonymous rate limits.',
      github_search_queries: githubSearchQueries,
      github_repos_linked_from_paper_metadata: directRepos,
      github_search_summary: {
        total_count_across_queries: searchTotal,
        incomplete_results_seen: searchIncomplete,
        top_results: githubItems.slice(0, REPO_EVIDENCE_LIMIT).map(compactSearchItem),
      },
      top_repository_evidence: topRepoEvidence.map(compactRepositoryEvidenceForCodeAgent),
    },
    datasetArtifacts: {
      notice: 'LIVE dataset evidence from Asta snippet_search plus dataset-related README/path clues from candidate repositories. This avoids requiring a separate dataset-catalog API key.',
      query: `${query} dataset split license benchmark holdout public restricted`,
      dataset_snippet_scope: snippetScope,
      ...(snippetScope === 'paper_scoped'
        ? { asta_dataset_snippets: asta.datasetSnippets }
        : {
          unscoped_dataset_snippets: {
            status: 'global_unscoped_omitted_from_dataset_facts',
            note: 'Asta dataset snippet_search ran globally because no validated paper_id resolved. Raw snippets are omitted from dataset facts; rely on repository-derived dataset clues or treat missing dataset evidence as an evidence gap.',
          },
        }),
      candidate_repositories_considered: fullRepoEvidence.length,
      dataset_clues_from_candidate_repositories: datasetCluesFromRepos,
    },
    citationFeedback: {
      notice: 'LIVE Asta citation and snippet evidence.',
      asta_citations: asta.citations,
      replication_snippet_scope: snippetScope,
      ...(snippetScope === 'paper_scoped'
        ? { asta_replication_snippets: asta.replicationSnippets }
        : {
          unscoped_replication_snippets: {
            status: 'global_unscoped_omitted_from_citation_feedback',
            note: 'Asta reproduction snippet_search ran globally because no validated paper_id resolved. Raw snippets are omitted from citation feedback so they cannot be mistaken for target-paper follow-up evidence.',
          },
        }),
    },
    sourceDigest,
  }
}

async function loadSourceBundle(query: string): Promise<SourceBundle> {
  const mode = resolveSourceMode()
  if (mode === 'live') {
    return loadLiveSourceBundle(query)
  }
  return loadMockSourceBundle(query)
}

